let cardTextLocalizedRuleCache = { signature: '', rules: [] };

function escapeCardTextRegExp(value) {
    return String(value || '').replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
}

function buildLocalizedCardTextRule(label, meta) {
    const clean = String(label || '').trim();
    if (!clean || /^[-_a-z0-9]+(?::[-_a-z0-9]+)*$/i.test(clean) && clean.includes('_')) return null;
    const escaped = escapeCardTextRegExp(clean);
    const amountPrefix = String.raw`(?:[+-]?\d+\s*(?:(?:stacks?|layers?)\s+(?:of\s+)?|(?:charges?|couches?)\s+de\s+|[еұӮеұӨ]\s*(?:гҒ®\s*)?)?)?`;
    const amountSuffix = String.raw`(?:(?:\s*[:пјҡ]\s*|\s+)[+-]?\d+(?:[;пјӣ][+-]?\d+)?\s*(?:stacks?|layers?|charges?|couches?|еұӮ|еұӨ)?)?`;
    const boundary = String.raw`(?=$|[\s,.;:пјҡпјҢгҖӮпјӣгҖҒ!пјҒ?пјҹ()пјҲпјү+\-Г—x=<>вүӨвүҘ\[\]]|[гӮ’гҒҢгҒ«гҒҜ])`;
    return {
        ...meta,
        re: new RegExp(`^${amountPrefix}${escaped}${amountSuffix}${boundary}`, 'iu'),
    };
}

function getLocalizedCardTextTokenRules() {
    const signature = `${currentLang}|${Object.keys(CUSTOM_TAG_DEFS || {}).sort().join(',')}|${Object.keys(CUSTOM_STATUS_DEFS || {}).sort().join(',')}`;
    if (cardTextLocalizedRuleCache.signature === signature) return cardTextLocalizedRuleCache.rules;
    const rules = [];
    const seen = new Set();
    const addRule = (label, meta) => {
        const key = `${String(label || '').trim().toLocaleLowerCase()}|${meta.cls}`;
        if (!String(label || '').trim() || seen.has(key)) return;
        const rule = buildLocalizedCardTextRule(label, meta);
        if (!rule) return;
        seen.add(key);
        rules.push(rule);
    };
    const termLibrary = getTermIntroLibrary();
    CARD_TEXT_LOCALIZED_FLAG_SPECS.forEach(([flag, cls]) => {
        const custom = getCustomTagDef(flag);
        const term = termLibrary[flag];
        const label = custom ? getRegistryText(custom, 'name', flag) : ((term && term.label) || getFlagLabel(flag));
        const style = CARD_FLAG_STYLES[flag];
        const color = (style && style.fg) || safeRegistryColor(custom && custom.color, (term && term.color) || '');
        addRule(label, { cls, termKey: `flag:${flag}`, color });
    });
    CARD_TEXT_LOCALIZED_STATUS_SPECS.forEach(([statusKey, cls]) => {
        let item;
        if (statusKey === 'crit' || statusKey === 'equipment_armor') {
            item = termLibrary[statusKey] || termLibrary[statusKey === 'equipment_armor' ? 'equipment_armor' : 'crit'];
        } else {
            item = getStatusIntroItem({ key: statusKey });
        }
        if (!item) return;
        const termKey = statusKey === 'crit' || statusKey === 'equipment_armor'
            ? `term:${statusKey}`
            : `status:${statusKey}`;
        const meta = { cls, termKey, color: item.color || '' };
        addRule(item.label, meta);
        const aliases = (CARD_TEXT_LOCALIZED_STATUS_ALIASES[currentLang] || {})[statusKey] || [];
        aliases.forEach(alias => addRule(alias, meta));
    });
    rules.sort((a, b) => String(b.re.source).length - String(a.re.source).length);
    cardTextLocalizedRuleCache = { signature, rules };
    return rules;
}

function buildInlineCardDict(defId, modifierText = '') {
    const resolvedDefId = findCardDefIdByAnyName(defId) || defId;
    const cardDict = {
        def_id: resolvedDefId,
        instance_flags: [],
        disabled_flags: [],
    };
    String(modifierText || '')
        .split('|')
        .map(part => part.trim())
        .filter(Boolean)
        .forEach(part => {
            const m = part.match(/^([^:=]+)\s*[:=]\s*(.+)$/);
            const rawKey = m ? m[1].trim() : part;
            const value = m ? m[2].trim() : '';
            if ((rawKey === 'flag' || rawKey === 'tag') && value) {
                cardDict.instance_flags.push(normalizeCardFlag(value));
                return;
            }
            const key = normalizeCardFlag(rawKey);
            const numberValue = Math.max(0, Math.floor(Number(value || 0)));
            if (key === 'swift') {
                if (numberValue > 0) {
                    cardDict.swift_value = numberValue;
                    cardDict.instance_flags.push('swift');
                }
                return;
            }
            if (key === 'magic_swift') {
                if (numberValue > 0) {
                    cardDict.magic_swift_value = numberValue;
                    cardDict.instance_flags.push('magic_swift');
                }
                return;
            }
            if (key === 'power') {
                if (numberValue > 0) {
                    cardDict.power_value = numberValue;
                    cardDict.instance_flags.push('power');
                }
                return;
            }
            if (key === 'fusion') {
                if (numberValue > 1) {
                    cardDict.fusion = numberValue;
                    cardDict.fusion_level = numberValue;
                }
                return;
            }
            if (key === 'fission') {
                if (numberValue > 1) {
                    cardDict.fission = numberValue;
                    cardDict.fission_level = numberValue;
                }
                return;
            }
            if (key === 'tomato' || key === 'held_turns') {
                if (numberValue > 0) {
                    cardDict.power_value = numberValue * 3;
                    cardDict.instance_flags.push('power');
                }
                return;
            }
        });
    return cardDict;
}

function parseInlineCardMarker(text) {
    const source = String(text || '');
    if (!source.toLowerCase().startsWith('[[card:')) return null;
    const closeIndex = source.indexOf(']]', 7);
    if (closeIndex < 0) return null;
    const raw = source.slice(0, closeIndex + 2);
    const body = source.slice(7, closeIndex);
    if (!body) return null;
    const parts = body
        .split('|')
        .map(part => part.trim())
        .filter(Boolean);
    const defId = parts.shift();
    if (!defId) return null;
    const modifierText = parts.join('|');
    return {
        raw,
        defId,
        modifierText,
        cardDict: buildInlineCardDict(defId, modifierText),
    };
}

function inlineCardChipHtml(cardDict) {
    const chip = createCardChoiceChip(cardDict, { hideInstanceOnlyFlags: false });
    chip.classList.add('inline-card-chip', 'inline-card-chip-compact');
    delete chip.dataset.termIntroBound;
    delete chip.dataset.choiceChipBound;
    chip.dataset.inlineCardChip = '1';
    chip.dataset.cardDict = JSON.stringify(cardDict || {});
    return chip.outerHTML;
}

