function renderCardTextTokenHtml(cls, rawText = '', termAttr = '', color = '') {
    const text = String(rawText || '');
    const iconKey = getCardTextTokenIconKey(cls, text);
    const iconHtml = renderInlineIconHtml(iconKey, text);
    const style = color ? ` style="color:${escapeHtml(color)}"` : '';
    return `<span class="card-token ${cls}"${termAttr}${style}>${escapeHtml(text)}${iconHtml}</span>`;
}

function extractInlineUnitPrefix(sourceText, iconStart, iconKey) {
    const before = String(sourceText || '').slice(0, iconStart);
    const rawKey = String(iconKey || '').trim();
    const key = ({
        damage: 'D',
        electric: 'electric_damage',
        health: 'H',
        heal: 'H',
        elixir: 'E',
        magic: 'M',
        poison: 'P',
        fire: 'F',
        armor: 'A',
    })[rawKey] || rawKey;
    const valueAtom = String.raw`(?:\([^)]+\)|пјҲ[^пјү]+пјү|[+-]?(?:\d+|[a-zA-Z])(?:\.\d+)?|[+-]?\d+%)`;
    const stackValueAtom = String.raw`(?:${valueAtom})(?:\s*еұӮ)?`;
    const healingExpression = String.raw`(?:йҖ жҲҗдјӨе®і\d+%(?:\([^)]+\)|пјҲ[^пјү]+пјү)?зҡ„|йҖ жҲҗдјӨе®ізҡ„\d+%(?:\([^)]+\)|пјҲ[^пјү]+пјү)?|йҖ жҲҗдјӨе®і(?:\([^)]+\)|пјҲ[^пјү]+пјү)?зҡ„|еҗ‘дёӢеҸ–ж•ҙ(?:\([^)]*дјӨе®і[^)]*\)|пјҲ[^пјү]*дјӨе®і[^пјү]*пјү)зҡ„)`;
    const poisonExpression = String.raw`(?:еҗ‘дёӢеҸ–ж•ҙ\([^)]*\)еұӮ|еҗ‘дёӢеҸ–ж•ҙпјҲ[^пјү]*пјүеұӮ|зӣ®ж ҮжүҖжңү|жүҖжңү|еҜ№еә”|ж–ҪеҠ |иҺ·еҫ—|еҺ»йҷӨ|еҮҸе°‘|еўһеҠ )`;
    const statusStackExpression = String.raw`(?:[+-]?(?:\d+|[a-zA-Z])(?:\.\d+)?еұӮ|[+-]?(?:\d+|[a-zA-Z])(?:\.\d+)?\s*)`;
    const damageExpression = String.raw`(?:еұӮж•°дёӨеҖҚзҡ„|еұӮж•°зҡ„дёӨеҖҚ|еұӮж•°зӯүеҗҢзҡ„|еұӮж•°зӣёеҗҢзҡ„)`;
    const patterns = {
        D: new RegExp(`${valueAtom}(?:\\s*)$`),
        electric_damage: new RegExp(`${valueAtom}(?:\\s*)$`),
        H: new RegExp(`(?:${healingExpression}|${valueAtom})(?:\\s*)$`),
        E: /[+-]?(?:\d+|[a-zA-Z])(?:\.\d+)?(?:\s*)$/,
        M: /[+-]?(?:\d+|[a-zA-Z])(?:\.\d+)?(?:\s*)$/,
        P: new RegExp(`(?:${poisonExpression}|${statusStackExpression}|${stackValueAtom})(?:\\s*)$`),
        F: new RegExp(`(?:${statusStackExpression}|${stackValueAtom})(?:\\s*)$`),
        A: /[+-]?(?:\d+|[a-zA-Z])(?:\.\d+)?(?:\s*)$/,
    };
    if (key === 'D' || key === 'electric_damage') {
        patterns[key] = new RegExp(`(?:${damageExpression}|${valueAtom})(?:\\s*)$`);
    }
    const pattern = patterns[key];
    if (!pattern) return null;
    const match = before.match(pattern);
    if (!match || !match[0]) return null;
    const text = match[0];
    // A formula can contain an earlier icon marker, for example
    // (current [[icon:H]] x 8%)[[icon:D]]. Removing that whole source prefix
    // from the already-rendered HTML would cut through the first icon's tags.
    if (text.includes('[[')) return null;
    return {
        text,
        htmlLength: escapeHtml(text).length,
    };
}

function extractInlineUnitSuffix(restAfterIcon, iconKey) {
    const rawKey = String(iconKey || '').trim();
    const key = ({
        damage: 'D',
        electric: 'electric_damage',
        health: 'H',
        heal: 'H',
        poison: 'P',
        fire: 'F',
    })[rawKey] || rawKey;
    const canHaveMultiplier = key === 'D' || key === 'electric_damage' || key === 'H' || key === 'P' || key === 'F';
    if (!canHaveMultiplier) return null;
    const text = String(restAfterIcon || '');
    const match = text.match(/^\s*[Г—x]\s*(?:\([^)]+\)|пјҲ[^пјү]+пјү|\d+(?:\.\d+)?|[a-zA-Z])/);
    if (!match || !match[0]) return null;
    return {
        text: match[0],
        length: match[0].length,
    };
}

function bindInlineCardChips(root, options = {}) {
    if (!root || !root.querySelectorAll) return;
    const interactive = options.interactive === true;
    if (!interactive) return;
    const allowTermIntro = options.allowTermIntro !== false;
    const termIntroDepth = Math.max(0, Number(options.termIntroDepth || 0) || 0);
    root.querySelectorAll('.inline-card-chip.choice-card-token[data-inline-card-chip="1"]').forEach(chip => {
        let cardDict = null;
        try {
            cardDict = JSON.parse(chip.dataset.cardDict || '{}');
        } catch (_) {
            cardDict = null;
        }
        if (!cardDict || !cardDict.def_id) return;
        if (chip.dataset.inlineChipBaseBound !== '1') {
            chip.dataset.inlineChipBaseBound = '1';
            const stop = (event) => {
                event.stopPropagation();
            };
            ['click', 'dblclick', 'mousedown', 'mouseup', 'pointerdown', 'pointerup', 'touchstart', 'touchend'].forEach(type => {
                chip.addEventListener(type, stop, { passive: true });
            });
            attachFloatingCardPreview(chip, cardDict);
        }
        if (allowTermIntro && chip.dataset.inlineChipTermBound !== '1') {
            delete chip.dataset.termIntroBound;
            chip.dataset.inlineChipTermBound = '1';
            chip.dataset.inlineChipTermDepth = String(termIntroDepth);
            attachTermIntroToCard(chip, cardDict, { termIntroDepth });
        }
    });
}

function colorizeCardText(value) {
    const text = String(value || '')
        .replace(/\bSwiftness\b/gi, 'Swift')
        .replace(/(?:йӯ”жі•зҗғ|Mana\s*Orb)пјҲиҗҢиҠҪгҖҒе…ұз”ҹпјү|(?:йӯ”жі•зҗғ|Mana\s*Orb)\(\s*иҗҢиҠҪ\s*[+пјӢгҖҒ,пјҢ]\s*е…ұз”ҹ\s*\)|\[(?:йӯ”жі•зҗғ|Mana\s*Orb)\]\s*\[\s*иҗҢиҠҪ\s*[+пјӢгҖҒ,пјҢ]\s*е…ұз”ҹ\s*\]/gi, '[[card:ManaOrb|flag=sprout|flag=symbiosis]]')
        .replace(/(?:иҪ»|Light)пјҲиҗҢиҠҪгҖҒе…ұз”ҹпјү|(?:иҪ»|Light)\(\s*иҗҢиҠҪ\s*[+пјӢгҖҒ,пјҢ]\s*е…ұз”ҹ\s*\)|\[(?:иҪ»|Light)\]\s*\[\s*иҗҢиҠҪ\s*[+пјӢгҖҒ,пјҢ]\s*е…ұз”ҹ\s*\]/gi, '[[card:Light|flag=sprout|flag=symbiosis]]');
    let html = '';
    let i = 0;
    while (i < text.length) {
        const rest = text.slice(i);
        if (rest.startsWith('  е“Қеә”пјҡ') || rest.startsWith('  е“Қеә”:')) {
            html += '&nbsp;&nbsp;';
            i += 2;
            continue;
        }
        const damageFromPoisonMarker = rest.match(/^\[\[icon:P\]\]((?:еұӮж•°дёӨеҖҚзҡ„|еұӮж•°зҡ„дёӨеҖҚ|еұӮж•°зӯүеҗҢзҡ„|еұӮж•°зӣёеҗҢзҡ„))\[\[icon:(D|electric_damage)\]\]/i);
        if (damageFromPoisonMarker && damageFromPoisonMarker[1] && damageFromPoisonMarker[2]) {
            const damageIconKey = damageFromPoisonMarker[2];
            const termKey = getIconTermKey(damageIconKey);
            const termAttr = termKey ? ` data-term-key="${escapeHtml(termKey)}"` : '';
            const cls = getIconTokenClass(damageIconKey);
            html += `<span class="card-token inline-icon-token inline-unit-token${cls ? ` ${escapeHtml(cls)}` : ''}"${termAttr}>${renderInlineIconHtml('P', 'P')}${escapeHtml(damageFromPoisonMarker[1])}${renderInlineIconHtml(damageIconKey, damageIconKey)}</span>`;
            i += damageFromPoisonMarker[0].length;
            continue;
        }
        const iconMarker = rest.match(/^\[\[icon:([a-zA-Z0-9_:-]+)\]\]/i);
        if (iconMarker && iconMarker[1]) {
            const iconKey = iconMarker[1];
            const termKey = getIconTermKey(iconKey);
            const termAttr = termKey ? ` data-term-key="${escapeHtml(termKey)}"` : '';
            const cls = getIconTokenClass(iconKey);
            const unitPrefix = extractInlineUnitPrefix(text, i, iconKey);
            if (unitPrefix) {
                const unitSuffix = extractInlineUnitSuffix(text.slice(i + iconMarker[0].length), iconKey);
                html = html.slice(0, Math.max(0, html.length - unitPrefix.htmlLength));
                html += `<span class="card-token inline-icon-token inline-unit-token${cls ? ` ${escapeHtml(cls)}` : ''}"${termAttr}>${escapeHtml(unitPrefix.text)}${renderInlineIconHtml(iconKey, iconKey)}${unitSuffix ? escapeHtml(unitSuffix.text) : ''}</span>`;
                i += iconMarker[0].length + (unitSuffix ? unitSuffix.length : 0);
                continue;
            }
            html += `<span class="card-token inline-icon-token${cls ? ` ${escapeHtml(cls)}` : ''}"${termAttr}>${renderInlineIconHtml(iconKey, iconKey)}</span>`;
            i += iconMarker[0].length;
            continue;
        }
        const statusMarker = rest.match(/^\[\[status:([^\]\r\n]+)\]\]/i);
        if (statusMarker && statusMarker[1]) {
            const statusKey = statusMarker[1].trim();
            const termLibrary = getTermIntroLibrary();
            const statusDef = getAllStatusDefs().get(statusKey) || getAllStatusDefs().get(statusKey.replace(/^.*:/, ''));
            const statusItem = statusKey === 'crit' || statusKey === 'equipment_armor'
                ? termLibrary[statusKey]
                : getStatusIntroItem({ ...(statusDef || {}), key: statusKey, customDef: statusDef && statusDef.customDef });
            const label = statusItem ? statusItem.label : (statusDef ? statusDef.label : statusKey);
            const color = statusItem ? statusItem.color : (statusDef ? statusDef.color : '');
            const style = color ? ` style="color:${escapeHtml(color)}"` : '';
            const markerTermKey = statusKey === 'crit' || statusKey === 'equipment_armor'
                ? `term:${statusKey}`
                : `status:${statusKey}`;
            html += `<span class="card-token status-inline" data-term-key="${escapeHtml(markerTermKey)}"${style}>${escapeHtml(label)}</span>`;
            i += statusMarker[0].length;
            continue;
        }
        const cardMarker = parseInlineCardMarker(rest);
        if (cardMarker) {
            html += inlineCardChipHtml(cardMarker.cardDict || buildInlineCardDict(cardMarker.defId, cardMarker.modifierText));
            i += cardMarker.raw.length;
            continue;
        }
        let matched = null;
        for (const rule of CARD_TEXT_TOKEN_RULES) {
            const m = rest.match(rule.re);
            if (m && m[0]) {
                matched = { cls: rule.cls, text: m[0] };
                break;
            }
        }
        if (!matched) {
            for (const rule of getLocalizedCardTextTokenRules()) {
                const m = rest.match(rule.re);
                if (m && m[0]) {
                    matched = { cls: rule.cls, text: m[0], termKey: rule.termKey, color: rule.color };
                    break;
                }
            }
        }
        if (matched) {
            const termKey = matched.termKey || getCardTextTokenTermKey(matched.cls, matched.text);
            const termAttr = termKey ? ` data-term-key="${escapeHtml(termKey)}"` : '';
            html += renderCardTextTokenHtml(matched.cls, matched.text, termAttr, matched.color || '');
            i += matched.text.length;
        } else {
            html += escapeHtml(text[i]);
            i += 1;
        }
    }
    return html;
}

function getBattleLogKnownPlayerNames() {
    const names = new Set();
    const add = (value) => {
        const text = String(value || '').trim();
        if (text) names.add(text);
    };
    const gs = gameState || {};
    add(gs.your_name);
    add(gs.opponent_name);
    add(gs.teammate_name);
    (gs.opponent_names || []).forEach(add);
    (gs.spectate_players || []).forEach(player => {
        add(player && (player.name || player.nickname));
    });
    for (let i = 1; i <= 4; i += 1) {
        add(gs[`player${i}_name`]);
        add(`P${i}`);
    }
    ['Player A', 'Player B', 'Player C', 'Player D', 'дҪ ', 'з»ғд№ еҜ№жүӢ', UI.you, UI.opponent, UI.tutorial_player_you, UI.tutorial_player_opponent].forEach(add);
    return Array.from(names).sort((a, b) => b.length - a.length);
}

function normalizeBattleLogIconTokens(value) {
    let text = String(value || '');
    const amountExpr = String.raw`(?:[+\-пјҚ]?\d+(?:\.\d+)?(?:\+\d+(?:\.\d+)?)?|\([+\-пјҚ]?\d+(?:\.\d+)?(?:\+[+\-пјҚ]?\d+(?:\.\d+)?)+\)|пјҲ[+\-пјҚ]?\d+(?:\.\d+)?(?:\+[+\-пјҚ]?\d+(?:\.\d+)?)+пјү)`;
    const unitBoundary = String.raw`(?=(?:\s|$|[пјҢгҖӮпјӣ;гҖҒпјҒ!пјҹ?пјү)\]]|[пјҲ(]|[Г—x]))`;
    const replaceUnit = (unit, iconKey) => {
        const re = new RegExp(`(${amountExpr})${unit}${unitBoundary}`, 'g');
        text = text.replace(re, `$1[[icon:${iconKey}]]`);
    };
    text = text.replace(/(\d+(?:\.\d+)?)з”өдјӨ/g, '$1[[icon:electric_damage]]');
    replaceUnit('D', 'D');
    replaceUnit('P', 'P');
    replaceUnit('F', 'F');
    replaceUnit('H', 'H');
    replaceUnit('E', 'E');
    replaceUnit('M', 'M');
    text = text.replace(/(^|[^:])H=/g, '$1[[icon:H]]=');
    text = text.replace(/(^|[^:])E=/g, '$1[[icon:E]]=');
    text = text.replace(/(^|[^:])M=/g, '$1[[icon:M]]=');
    return text;
}

function colorizeBattleLogText(value) {
    const text = normalizeBattleLogIconTokens(value);
    for (const name of getBattleLogKnownPlayerNames()) {
        if (!name || !text.startsWith(name)) continue;
        const rest = text.slice(name.length);
        return escapeHtml(name) + colorizeCardText(rest);
    }
    const prefixMatch = text.match(/^(.+?)(дҪҝз”Ё|еҸ—еҲ°|иҺ·еҫ—|еӣһеӨҚ|жҠҪ|ејғ|еӨұеҺ»|з§»е…Ҙ|еӣ |зҡ„|иў«)/);
    if (prefixMatch && prefixMatch[1] && prefixMatch[1].length <= 32) {
        const name = prefixMatch[1];
        return escapeHtml(name) + colorizeCardText(text.slice(name.length));
    }
    return colorizeCardText(text);
}

function getCardTextTokenTermKey(cls, text = '') {
    const raw = String(text || '');
    const tagMap = {
        'tag-team-limited': 'flag:team_limited',
        'tag-team-unique': 'flag:team_unique',
        'tag-infinite-exclude': 'flag:infinite_exclude',
        'tag-non-stackable': 'flag:non_stackable',
        'tag-indestructible': 'flag:indestructible',
        'tag-uncancellable': 'flag:uncancellable',
        'tag-self-only': 'flag:self_only',
        'tag-magic-swift': 'flag:magic_swift',
        'tag-temp-swift': 'flag:temp_swift',
        'tag-temp-heavy': 'flag:temp_heavy',
        'tag-temp-magic-heavy': 'flag:temp_magic_heavy',
        'tag-precision': 'flag:precision',
        'tag-exile': 'flag:exile',
        'tag-sprout': 'flag:sprout',
        'tag-symbiosis': 'flag:symbiosis',
        'tag-attract': 'flag:attract',
        'tag-void': 'flag:void',
        'tag-rebound': 'flag:rebound',
        'tag-copy': 'flag:copy',
        'tag-unique': 'flag:unique',
        'tag-swift': 'flag:swift',
        'tag-stealth': 'flag:stealth',
        'tag-revealed': 'flag:revealed',
        'tag-power': 'flag:power',
        'tag-charge': 'flag:charge',
        'tag-floating': 'flag:floating',
        'tag-ocean-blinded': 'flag:ocean_blinded',
        'tag-sewers-confusion': 'flag:sewers:confusion',
        'tag-arctic-ready': 'flag:arctic:ready',
        'tag-wide-strike': 'flag:wide_strike',
        'tag-self-target': 'flag:self_target',
    };
    if (tagMap[cls]) return tagMap[cls];
    const statusMap = {
        'status-toxic-poison': 'status:toxic_poison',
        'status-sluggish': 'status:sluggish',
        'status-fragile': 'status:fragile',
        'status-shield': 'status:shield',
        'status-turn-heal': 'status:turn_heal',
        'status-turn-magic': 'status:turn_magic',
        'status-root': 'status:root_status',
        'status-triangle': 'status:triangle',
        'status-dodge': 'status:dodge',
        'status-nazar': 'status:nazar',
        'status-bleed': 'status:bleed',
        'status-fracture': 'status:fracture',
        'status-stagnation': 'status:stagnation',
        'status-blind': 'status:blind',
        'status-foresight': 'status:foresight',
        'status-overload': 'status:overload',
        'status-heal-block': 'status:heal_block',
        'status-weakness': 'status:weakness',
        'status-fragment': 'status:fragment',
        'status-immune': 'status:immune',
        'status-stunned': 'status:stunned',
        'status-invincible': 'status:invincible',
        'status-bandage': 'status:bandage',
        'status-attack-blocked': 'status:attack_blocked',
        'status-attack-only': 'status:attack_only',
        'status-untargetable': 'status:untargetable',
        'status-magic-nazar': 'status:magic_nazar',
        'status-blood-debt': 'status:blood_debt',
        'status-frost': 'status:arctic:frost',
        'status-unable-counter': 'status:unable_counter',
        'status-magic-blocked': 'status:magic_blocked',
        'status-luck': 'status:luck',
        'status-blazing-fire': 'status:blazing_fire',
        'status-crit': 'term:crit',
        'equipment-armor': 'term:equipment_armor',
    };
    if (statusMap[cls]) return statusMap[cls];
    if (cls === 'toxic') return 'term:toxic';
    if (cls === 'fire') return 'term:F';
    if (cls === 'poison') return 'term:P';
    if (cls === 'damage') return raw.includes('з”өдјӨ') ? 'term:electric_damage' : 'term:D';
    if (cls === 'armor') return 'term:A';
    if (cls === 'heal' || cls === 'health') return 'term:health';
    if (cls === 'elixir') return 'term:elixir';
    if (cls === 'magic') return 'term:magic';
    return '';
}

function getLocalizedEventText(ev, field) {
    if (!ev) return '';
    const dictKey = field === 'name' ? 'name_i18n' : 'desc_i18n';
    const dict = ev[dictKey] || {};
    return dict[currentLang] || dict.en || dict.zh || ev[field] || '';
}

