function $(id) { return document.getElementById(id); }

function setIconButtonLabel(id, label) {
    const btn = $(id);
    if (!btn) return;
    const text = label || btn.getAttribute('aria-label') || btn.title || '';
    const labelEl = btn.querySelector('.top-icon-label');
    if (labelEl) {
        labelEl.textContent = text;
    } else {
        btn.textContent = text;
    }
    btn.setAttribute('aria-label', text);
    if (btn.classList && btn.classList.contains('top-icon-btn')) {
        btn.removeAttribute('title');
    } else {
        btn.title = text;
    }
}

function restartTransientClass(el, className, duration = 650) {
    if (!el || !className) return;
    el.classList.remove(className);
    void el.offsetWidth;
    el.classList.add(className);
    setTimeout(() => {
        if (el && el.classList) el.classList.remove(className);
    }, duration);
}

function getTargetFeedbackElement(region) {
    if (!region || !region.querySelector) return region || null;
    return region.matches && region.matches('.player-avatar, .mini-skin-avatar')
        ? region
        : (region.querySelector('.player-avatar, .mini-skin-avatar') || region);
}

function flashTargetRegion(playerId) {
    const region = getPlayerRegionById(playerId);
    restartTransientClass(getTargetFeedbackElement(region), 'target-feedback-pulse', 720);
}

function maybeAnimateTurnFocus(gs) {
    if (!gs) return;
    const key = `${gs.mode || ''}:${gs.phase || ''}:${gs.round_num || 0}:${normalizePlayerId(gs.current_player)}`;
    const shouldAnimate = lastRenderedTurnKey && lastRenderedTurnKey !== key && gs.phase === 'action';
    lastRenderedTurnKey = key;
    if (!shouldAnimate) return;
    requestAnimationFrame(() => {
        const region = getPlayerRegionById(gs.current_player);
        restartTransientClass(region, 'turn-focus-pulse', 900);
        const current = normalizePlayerId(gs.current_player);
        const self = normalizePlayerId(gs.your_id != null ? gs.your_id : playerId);
        const endTurnBtn = $('btn-end-turn');
        const classicEndTurnBtn = $('classic-end-turn');
        if (current != null && self != null && current === self) {
            restartTransientClass(endTurnBtn, 'turn-button-focus-pulse', 860);
            restartTransientClass(classicEndTurnBtn, 'turn-button-focus-pulse', 860);
        } else {
            restartTransientClass(endTurnBtn, 'turn-button-wait-pulse', 640);
            restartTransientClass(classicEndTurnBtn, 'turn-button-wait-pulse', 640);
        }
    });
}

function formatRoundStatus(gs, phaseText = '') {
    const roundNum = Number(gs && gs.round_num);
    const phaseName = phaseText || ((gs && gs.phase) === 'draft'
        ? UI.draft_phase
        : (gs && gs.phase) === 'event_select'
            ? UI.select_event
            : '');
    if (!Number.isFinite(roundNum) || roundNum <= 0) {
        if ((gs && gs.phase) === 'draft') return UI.draft_phase;
        if ((gs && gs.phase) === 'event_select') return UI.select_event;
        return phaseName || UI.draft_phase;
    }
    return UI.round_status.replace('{0}', roundNum).replace('{1}', phaseName);
}

function formatCompactRoundStatus(gs, phaseText = '') {
    const roundNum = Number(gs && gs.round_num);
    if (!Number.isFinite(roundNum) || roundNum <= 0) {
        if ((gs && gs.phase) === 'draft') return UI.draft_phase;
        if ((gs && gs.phase) === 'event_select') return UI.select_event;
        return phaseText || UI.draft_phase;
    }
    return `R${roundNum} В· ${phaseText}`;
}

function formatClassicRoundLabel(gs) {
    const roundNum = Number(gs && gs.round_num);
    if (Number.isFinite(roundNum) && roundNum > 0) return `R${roundNum}`;
    if ((gs && gs.phase) === 'draft') return UI.draft_phase || 'Draft';
    if ((gs && gs.phase) === 'event_select' || (gs && gs.phase) === 'event_reveal') return UI.select_event || 'Setup';
    return 'R0';
}

function appendSpectatorCountStatus(text, gs) {
    if (!gs || gs.solo || gs.spectator_count == null) return text;
    const count = Number(gs.spectator_count);
    if (!Number.isFinite(count) || count <= 0) return text;
    const label = (UI.spectator_count_status || 'Spectators: {0}').replace('{0}', String(Math.floor(count)));
    return text ? `${text} В· ${label}` : label;
}

