function showView(viewId) {
    const el = $(viewId);
    const sameView = activeViewId === viewId && el && !el.classList.contains('hidden');
    if (!sameView) {
        removeFloatingCardPreview();
        document.querySelectorAll('.view').forEach(v => v.classList.add('hidden'));
        if (el) el.classList.remove('hidden');
        activeViewId = viewId;
        updatePhaseChatPanelVisibility(viewId);
    }
    updateClassicMobileCanvas();
    updateTopActionButtons(viewId);
    scheduleBackgroundMusicUpdate();
    if (viewId !== 'view-login') {
        toggleAccountPopover(false);
        toggleFriendsPopover(false);
        toggleStatsPopover(false);
        toggleChangelogPopover(false);
        toggleLeaderboardPopover(false);
    }
    if (!sameView && viewId !== 'view-game') {
        const logContainer = $('battle-log');
        const logContent = logContainer ? logContainer.querySelector('.log-content') : null;
        resetBattleLogState(logContent);
        renderedBattleLogMatchKey = '';
        lastRenderedTurnKey = '';
        lastStatusSignatures.clear();
        updateModeSpecificControls({ solo: false, phase: '' });
        refreshBaseStatus(viewId);
    }
}

function isNetworkMatchPhase(value = phase) {
    return !soloMode && !replayMode && [
        'draft', 'event_select', 'event_reveal', 'event_sub_choice', 'playing', 'action', 'draw', 'response', 'choice', 'game_over', 'reconnecting',
    ].includes(String(value || ''));
}

function markNetworkMatchTransition(reason = '') {
    if (soloMode || replayMode) return;
    const now = Date.now();
    matchTransitionGuardUntil = Math.max(matchTransitionGuardUntil, now + 8000);
    if (reason) debugLog('[client] match transition guard:', reason);
}

function allowLobbyTransition(reason = '') {
    allowLobbyTransitionUntil = Date.now() + 5000;
    matchTransitionGuardUntil = 0;
    if (reason) debugLog('[client] allow lobby transition:', reason);
}

function isMatchTransitionGuardActive() {
    return !soloMode && !replayMode && Date.now() < matchTransitionGuardUntil;
}

function shouldIgnoreLobbyUpdateWhileInMatch() {
    if (soloMode || replayMode) return false;
    if (isMatchTransitionGuardActive()) return true;
    if (isNetworkMatchPhase(phase)) return true;
    return [
        'view-draft',
        'view-event-select',
        'view-game',
        'view-gameover',
    ].includes(activeViewId || '');
}

function canUseLobbyInvitationUi() {
    return phase === 'lobby'
        && activeViewId === 'view-lobby'
        && !soloMode
        && !replayMode
        && !isSpectating;
}

function dismissLobbyInvitationModal() {
    const inviteControlIds = [
        'invite-accept', 'invite-decline',
        'team-accept', 'team-decline',
        'match-accept', 'match-decline',
        'invite-confirm-ok', 'invite-confirm-cancel',
    ];
    if (inviteControlIds.some(id => !!$(id))) hideModal();
}

function rejectLobbyInvitationOutsideLobby(eventName, data = {}) {
    if (canUseLobbyInvitationUi()) return false;
    debugLog(`[client] ignored ${eventName} outside lobby phase=${phase} view=${activeViewId}`);
    if (!socket || !socket.connected) return true;
    if (eventName === 'invite_received' && data.inviter_sid) {
        socket.emit('decline_invite', { inviter_sid: data.inviter_sid });
    } else if (eventName === 'team_invite' && data.from_sid) {
        socket.emit('decline_team', { from_sid: data.from_sid });
    } else if (eventName === 'team_match_invite' && data.from_leader) {
        socket.emit('decline_team_match', { from_leader: data.from_leader });
    }
    return true;
}

function clearNetworkMatchStateForLobby() {
    if (soloMode || replayMode) return;
    clearActiveMatchRoute('lobby');
    gameState = {};
    draftState = {};
    eventSelectData = {};
    isSpectating = false;
    pendingSpectateRoomId = null;
    activeSpectateRoomId = null;
    spectateCardDataKey = '';
    spectatePerspective = 0;
    pendingPlayCard = null;
    responsePending = false;
    responseData = null;
    activeV2UiRequestId = null;
    removeFloatingCardPreview();
    clearSelectedPlayCard();
    clearPendingServerAction();
    resetRematchUiState();
}

function clearTransientMatchRecovery(reason = '') {
    if (transientLoginRetryTimer) {
        clearTimeout(transientLoginRetryTimer);
        transientLoginRetryTimer = null;
    }
    if (transientMatchRecovery && reason) {
        debugLog('[client] match socket recovery finished:', reason);
    }
    transientMatchRecovery = null;
    document.documentElement.classList.remove('socket-recovering');
}

function hasRecoverableNetworkMatchContext() {
    if (soloMode || replayMode || isSpectating || phase === 'game_over') return false;
    if (readActiveMatchRoute()) return true;
    if (isNetworkMatchPhase(phase)) return true;
    return ['view-draft', 'view-event-select', 'view-game'].includes(activeViewId || '');
}

function preserveCurrentMatchRouteForRecovery(previousPhase) {
    if (readActiveMatchRoute()) return;
    const candidates = [gameState, draftState, eventSelectData];
    const source = candidates.find(item => item && item.room_id != null);
    if (!source) return;
    rememberActiveMatchRoute({ ...source, phase: source.phase || previousPhase }, 'socket_disconnect');
}

function beginTransientMatchRecovery(reason = '') {
    const previousPhase = phase;
    preserveCurrentMatchRouteForRecovery(previousPhase);
    if (!transientMatchRecovery) {
        transientMatchRecovery = {
            startedAt: Date.now(),
            previousPhase,
            previousView: activeViewId,
            loginAttempts: 0,
            disconnectReason: String(reason || ''),
        };
    }
    phase = 'reconnecting';
    markNetworkMatchTransition(`socket_disconnect:${reason || 'transport'}`);
    document.documentElement.classList.add('socket-recovering');
    clearPendingServerAction({ keepOptimistic: true });
    cleanupDragState();
    updateStatus(UI.reconnecting || UI.reconnect_title || 'жӯЈеңЁйҮҚиҝһвҖҰ');
    flashStatus(UI.reconnecting || UI.reconnect_title || 'жӯЈеңЁйҮҚиҝһвҖҰ', 2400, 'warning');
}

function isRecoverableTransientLoginFailure(data = {}) {
    const reason = String(data.reason || data.message || '');
    return /Nickname already exists|иҜ·жұӮиҝҮдәҺйў‘з№Ғ|зҷ»еҪ•иҝҮдәҺйў‘з№Ғ|жңҚеҠЎеҷЁжӯЈеңЁеӨ„зҗҶ|иҜ·зЁҚеҗҺ|temporarily|too frequently/i.test(reason);
}

function scheduleTransientLoginRetry(data = {}) {
    if (!transientMatchRecovery || transientLoginRetryTimer) return false;
    const elapsed = Date.now() - Number(transientMatchRecovery.startedAt || 0);
    if (elapsed >= SOCKET_MATCH_RECOVERY_MAX_MS) {
        returnHomeAfterSocketDisconnect(translateLoginReason(data.reason || data.message || UI.reconnect_timeout));
        return true;
    }
    transientMatchRecovery.loginAttempts = Number(transientMatchRecovery.loginAttempts || 0) + 1;
    const delay = Math.min(
        SOCKET_MATCH_LOGIN_RETRY_MAX_MS,
        700 * Math.pow(1.7, Math.max(0, transientMatchRecovery.loginAttempts - 1)),
    );
    updateStatus(UI.reconnecting || UI.reconnect_title || 'жӯЈеңЁйҮҚиҝһвҖҰ');
    transientLoginRetryTimer = setTimeout(() => {
        transientLoginRetryTimer = null;
        if (!transientMatchRecovery) return;
        if (socket && socket.connected) emitSocketLogin();
    }, delay);
    return true;
}

function returnHomeAfterSocketDisconnect(message = '') {
    clearTransientMatchRecovery('return_home');
    closeAfkCheckOverlay();
    clearPendingServerAction();
    cleanupDragState();
    pendingPlayCard = null;
    responsePending = false;
    responseData = null;
    pendingSpectateRoomId = null;
    activeSpectateRoomId = null;
    isSpectating = false;
    clearSelectedPlayCard();
    removeFloatingCardPreview();
    clearNetworkMatchStateForLobby();
    setButtonLoading('btn-connect', false);
    phase = 'login';
    showView('view-login');
    if (message) flashStatus(message, 5000, 'error');
}

