let changelogLoaded = false;
let changelogLoadingPromise = null;
let changelogCache = null;
const CHANGELOG_CACHE_KEY = 'gtn_changelog_cache_v1';
const CHANGELOG_READ_VERSION_KEY = 'gtn_changelog_read_version_v1';
const CHANGELOG_READ_DATE_KEY = 'gtn_changelog_read_latest_date_v1';
const CHANGELOG_BOOT_VERSION_KEY = 'gtn_changelog_boot_version_v1';

function currentChangelogCacheVersion() {
    return String(window.__GTN_CHANGELOG_VERSION__ || window.__GTN_STATIC_VERSION__ || window.__GTN_APP_VERSION__ || window.__GTN_INSTANCE_ID__ || 'dev');
}

function formatChangelogDate(dateText) {
    const date = new Date(`${dateText}T00:00:00`);
    if (Number.isNaN(date.getTime())) return dateText || '';
    const localeMap = { zh: 'zh-CN', en: 'en-US', fr: 'fr-FR', ja: 'ja-JP' };
    try {
        return new Intl.DateTimeFormat(localeMap[currentLang] || 'zh-CN', {
            year: 'numeric',
            month: 'long',
            day: 'numeric'
        }).format(date);
    } catch (_) {
        return dateText || '';
    }
}

function renderChangelogItems(items) {
    const body = $('changelog-popover-body');
    if (!body) return;
    body.textContent = '';
    if (!Array.isArray(items) || !items.length) {
        const empty = document.createElement('p');
        empty.className = 'muted';
        empty.textContent = UI.changelog_empty || 'жҡӮж— жӣҙж–°ж—Ҙеҝ—гҖӮ';
        body.appendChild(empty);
        return;
    }
    items.slice(0, 20).forEach(item => {
        const entry = document.createElement('article');
        entry.className = 'changelog-entry';
        const date = document.createElement('h4');
        date.className = 'changelog-date';
        date.textContent = formatChangelogDate(item && item.date);
        const content = document.createElement('p');
        content.className = 'changelog-content';
        content.textContent = String(item && item.content || '').trim();
        entry.appendChild(date);
        entry.appendChild(content);
        body.appendChild(entry);
    });
}

function getChangelogUnreadCount(cache = changelogCache) {
    if (!cache || !Array.isArray(cache.items) || !cache.items.length) return 0;
    const serverVersion = String(cache.serverVersion || '');
    const readVersion = String(localStorage.getItem(CHANGELOG_READ_VERSION_KEY) || '');
    if (serverVersion && readVersion === serverVersion) return 0;
    const readDate = String(localStorage.getItem(CHANGELOG_READ_DATE_KEY) || '');
    if (!readDate) return Math.min(cache.items.length, 99);
    const newerCount = cache.items.filter(item => String(item && item.date || '') > readDate).length;
    return Math.min(Math.max(newerCount, serverVersion ? 1 : 0), 99);
}

function updateChangelogBadge() {
    const btn = $('btn-changelog-top');
    if (!btn) return;
    const count = getChangelogUnreadCount();
    if (count > 0) {
        btn.dataset.badge = count > 99 ? '99+' : String(count);
        btn.classList.add('has-badge');
    } else {
        delete btn.dataset.badge;
        btn.classList.remove('has-badge');
    }
}

function isChangelogPopoverOpen() {
    const pop = $('changelog-popover');
    return !!(pop && !pop.classList.contains('hidden'));
}

function markChangelogRead() {
    if (!changelogCache || !Array.isArray(changelogCache.items) || !changelogCache.items.length) return;
    try {
        localStorage.setItem(CHANGELOG_READ_VERSION_KEY, String(changelogCache.serverVersion || ''));
        localStorage.setItem(CHANGELOG_READ_DATE_KEY, String(changelogCache.items[0] && changelogCache.items[0].date || ''));
    } catch (_) {}
    updateChangelogBadge();
}

function loadCachedChangelog() {
    try {
        const cached = JSON.parse(localStorage.getItem(CHANGELOG_CACHE_KEY) || 'null');
        if (cached && Array.isArray(cached.items)) {
            changelogCache = cached;
            changelogLoaded = true;
            return cached;
        }
    } catch (_) {}
    return null;
}

async function loadChangelog(force = false, options = {}) {
    if (changelogLoaded && !force) {
        if (!options.silent && changelogCache && Array.isArray(changelogCache.items)) {
            renderChangelogItems(changelogCache.items);
        }
        updateChangelogBadge();
        return;
    }
    if (changelogLoadingPromise) return changelogLoadingPromise;
    const body = $('changelog-popover-body');
    const cacheVersion = currentChangelogCacheVersion();
    if (!force) {
        const cached = loadCachedChangelog();
        if (cached && cached.version === cacheVersion) {
            if (!options.silent) renderChangelogItems(cached.items);
            updateChangelogBadge();
            return;
        }
    }
    if (body && !changelogLoaded && !options.silent) {
        body.innerHTML = `<p class="muted">${escapeHtml(UI.loading || 'Loading...')}</p>`;
    }
    changelogLoadingPromise = fetch('/api/changelog?limit=20', { cache: 'default' })
        .then(resp => resp.ok ? resp.json() : Promise.reject(new Error(`HTTP ${resp.status}`)))
        .then(data => {
            changelogLoaded = true;
            const items = data && data.items || [];
            changelogCache = { version: cacheVersion, serverVersion: data && data.version || '', items, savedAt: Date.now() };
            try {
                localStorage.setItem(CHANGELOG_CACHE_KEY, JSON.stringify(changelogCache));
            } catch (_) {}
            if (!options.silent || isChangelogPopoverOpen()) renderChangelogItems(items);
            updateChangelogBadge();
        })
        .catch(() => {
            if (body && !options.silent) {
                body.textContent = '';
                const error = document.createElement('p');
                error.className = 'error-text';
                error.textContent = UI.changelog_error || 'жӣҙж–°ж—Ҙеҝ—еҠ иҪҪеӨұиҙҘгҖӮ';
                body.appendChild(error);
            }
        })
        .finally(() => {
            changelogLoadingPromise = null;
        });
    return changelogLoadingPromise;
}

function initChangelogBadge() {
    loadCachedChangelog();
    updateChangelogBadge();
    const cacheVersion = currentChangelogCacheVersion();
    const lastBootVersion = String(localStorage.getItem(CHANGELOG_BOOT_VERSION_KEY) || '');
    if (cacheVersion && lastBootVersion !== cacheVersion) {
        try { localStorage.setItem(CHANGELOG_BOOT_VERSION_KEY, cacheVersion); } catch (_) {}
        loadChangelog(true, { silent: true });
    }
}

function openAbout() {
    const panel = $('about-panel');
    if (panel) panel.classList.remove('hidden');
    setAboutPage('rules');
    ensureTutorialButtons();
    const body = $('about-rules-body');
    bindRulesCardChips(body);
    if (body && rulesScrollTop) requestAnimationFrame(() => { body.scrollTop = rulesScrollTop; });
}

function openChangelog() {
    toggleChangelogPopover(true);
}

function toggleChangelogPopover(force) {
    const pop = $('changelog-popover');
    if (!pop) return;
    const shouldOpen = typeof force === 'boolean' ? force : pop.classList.contains('hidden');
    pop.classList.toggle('hidden', !shouldOpen);
    if (shouldOpen) {
        toggleLeaderboardPopover(false);
        toggleAchievementsPopover(false);
        if (typeof toggleAccountPopover === 'function') toggleAccountPopover(false);
        if (typeof toggleFriendsPopover === 'function') toggleFriendsPopover(false);
        Promise.resolve(loadChangelog()).then(markChangelogRead);
    }
}

function closeAbout() {
    const panel = $('about-panel');
    if (panel) panel.classList.add('hidden');
}

function setHiddenFeaturesEnabled(enabled) {
    if (enabled) {
        localStorage.setItem(HIDDEN_FEATURES_KEY, '1');
    } else {
        localStorage.removeItem(HIDDEN_FEATURES_KEY);
        if (currentUiStyle === 'classic') applyUiStyle('minimal');
        else updateUiStyleAvailability();
    }
    updateUiStyleAvailability();
}

function promptHiddenFeatureUnlock() {
    showModal(`
        <div class="hidden-feature-unlock">
            <h3>йҡҗи—ҸеҠҹиғҪ</h3>
            <label class="report-field">
                <span>иҜ·иҫ“е…ҘеҶ…жөӢз§ҳй’Ҙпјҡ</span>
                <input id="hidden-feature-key-input" type="password" autocomplete="current-password">
            </label>
            <div id="hidden-feature-error" class="report-error hidden"></div>
            <div class="modal-buttons">
                <button id="hidden-feature-cancel" class="btn btn-secondary" type="button">еҸ–ж¶Ҳ</button>
                <button id="hidden-feature-confirm" class="btn btn-primary" type="button">зЎ®и®Ө</button>
            </div>
        </div>
    `);
    const input = $('hidden-feature-key-input');
    const errorEl = $('hidden-feature-error');
    const cancelBtn = $('hidden-feature-cancel');
    const confirmBtn = $('hidden-feature-confirm');
    if (input) input.focus();
    if (cancelBtn) cancelBtn.onclick = hideModal;
    const submit = async () => {
        if (!confirmBtn || !input) return;
        confirmBtn.disabled = true;
        if (errorEl) errorEl.classList.add('hidden');
        try {
            const res = await fetch('/api/hidden-features/unlock', {
                method: 'POST',
                credentials: 'same-origin',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ key: input.value || '' }),
            });
            const data = await res.json().catch(() => ({}));
            if (!res.ok || !data.success) throw new Error(data.error || 'з§ҳй’Ҙй”ҷиҜҜ');
            setHiddenFeaturesEnabled(true);
            hideModal();
            flashStatus('йҡҗи—ҸеҠҹиғҪе·ІејҖеҗҜ', 1800);
        } catch (err) {
            if (errorEl) {
                errorEl.textContent = err && err.message ? err.message : 'и§Јй”ҒеӨұиҙҘ';
                errorEl.classList.remove('hidden');
            }
        } finally {
            confirmBtn.disabled = false;
        }
    };
    if (confirmBtn) confirmBtn.onclick = submit;
    if (input) input.addEventListener('keydown', (event) => {
        if (event.key === 'Enter') submit();
    }, { once: false });
}

function bindHiddenFeatureLongPress() {
    const title = $('credits-special-title');
    if (!title || title.dataset.hiddenFeatureBound === '1') return;
    title.dataset.hiddenFeatureBound = '1';
    title.title = 'й•ҝжҢү';
    let timer = null;
    const clear = () => {
        if (timer) clearTimeout(timer);
        timer = null;
    };
    const start = (event) => {
        if (event && event.button != null && event.button !== 0) return;
        clear();
        const delay = hiddenFeaturesEnabled() ? 1000 : 2000;
        timer = setTimeout(() => {
            timer = null;
            if (hiddenFeaturesEnabled()) {
                setHiddenFeaturesEnabled(false);
                flashStatus('йҡҗи—ҸеҠҹиғҪе·Іе…ій—ӯ', 1800);
            } else {
                promptHiddenFeatureUnlock();
            }
        }, delay);
    };
    title.addEventListener('pointerdown', start);
    title.addEventListener('pointerup', clear);
    title.addEventListener('pointerleave', clear);
    title.addEventListener('pointercancel', clear);
    title.addEventListener('contextmenu', (event) => event.preventDefault());
}

function setGalleryMode(mode) {
    galleryMode = mode || 'cards';
    ['cards', 'tags', 'events', 'statuses'].forEach(name => {
        const tab = $(`gallery-tab-${name}`);
        if (tab) tab.classList.toggle('active', galleryMode === name);
    });
    const search = $('gallery-search');
    if (search) search.placeholder = UI.gallery_search;
}

async function showCardGallery(selectedId = null, mode = 'cards') {
    phase = 'gallery';
    gallerySelectedModKeys = null;
    setGalleryMode(mode);
    const backBtn = $('btn-gallery-back');
    if (backBtn) backBtn.textContent = galleryReturnToRules ? UI.gallery_back_rules : UI.back_to_home;
    if (selectedId) gallerySelectedId = selectedId;
    showView('view-card-gallery');
    const list = $('gallery-card-list');
    const detail = $('gallery-detail');
    if (list && detail && (!GALLERY_CARD_DEFS || !Object.keys(GALLERY_CARD_DEFS).length)) {
        list.className = 'gallery-card-list';
        detail.className = 'gallery-detail';
        list.innerHTML = '';
        detail.innerHTML = `<p class="gallery-no-items">${escapeHtml(UI.game_loading || 'еҠ иҪҪдёӯ...')}</p>`;
    } else {
        renderCardGallery();
    }
    try {
        await ensureGalleryDataLoaded();
    } catch (err) {
        console.warn('[mods] failed to refresh all card data before gallery:', err);
    }
    if (getVisibleViewId() !== 'view-card-gallery') return;
    const defs = getGalleryCardDefs();
    if (!gallerySelectedId || !isPublicCardDef(defs[gallerySelectedId])) {
        gallerySelectedId = Object.keys(defs).filter(id => isPublicCardDef(defs[id])).sort(compareGalleryCards)[0] || null;
    }
    requestAnimationFrame(() => {
        if (getVisibleViewId() === 'view-card-gallery') renderCardGallery();
    });
}

function getCustomTagDef(flag) {
    const normalized = normalizeCardFlag(flag);
    if (CARD_FLAG_STYLES[normalized] || GALLERY_MECHANIC_FLAGS.has(normalized)) return null;
    return (CUSTOM_TAG_DEFS && CUSTOM_TAG_DEFS[normalized]) || null;
}

function getCustomStatusDef(statusId) {
    return (CUSTOM_STATUS_DEFS && CUSTOM_STATUS_DEFS[statusId]) || null;
}

