function accountStatsText(user) {
    if (!user) return '';
    return tf(
        'account_stats',
        user.games_played || 0,
        user.wins || 0,
        user.losses || 0,
        user.draws || 0
    );
}

function parseServerTimeMs(value) {
    if (!value) return 0;
    const ms = Date.parse(String(value).replace('Z', '+00:00'));
    return Number.isFinite(ms) ? ms : 0;
}

function activeAccountWarnings() {
    const list = Array.isArray(currentAccount?.warnings) ? currentAccount.warnings : [];
    const now = Date.now();
    return list.filter((warning) => {
        const expiresAt = parseServerTimeMs(warning.expires_at);
        return expiresAt && expiresAt > now;
    });
}

function formatWarningRemaining(expiresAt) {
    const ms = parseServerTimeMs(expiresAt);
    if (!ms) return '';
    const seconds = Math.max(0, Math.ceil((ms - Date.now()) / 1000));
    if (seconds <= 0) return '';
    if (seconds >= 86400) return `${Math.ceil(seconds / 86400)}еӨ©`;
    if (seconds >= 3600) return `${Math.ceil(seconds / 3600)}е°Ҹж—¶`;
    if (seconds >= 60) return `${Math.ceil(seconds / 60)}еҲҶй’ҹ`;
    return `${seconds}з§’`;
}

function renderAccountWarningBanner() {
    const banner = $('account-warning-banner');
    if (!banner) return;
    if (accountWarningTimer) {
        clearTimeout(accountWarningTimer);
        accountWarningTimer = null;
    }
    const warnings = activeAccountWarnings();
    if (!warnings.length) {
        banner.classList.add('hidden');
        banner.textContent = '';
        if (currentAccount && Array.isArray(currentAccount.warnings) && currentAccount.warnings.length) {
            currentAccount.warnings = warnings;
            cacheAccount(currentAccount);
        }
        return;
    }
    const warning = warnings[0];
    const remaining = formatWarningRemaining(warning.expires_at);
    banner.textContent = `з®ЎзҗҶе‘ҳиӯҰе‘Ҡпјҡ${warning.message || 'иҜ·жіЁж„ҸжёёжҲҸеҶ…иЎҢдёә'}${remaining ? `пјҲеү©дҪҷ ${remaining}пјү` : ''}`;
    banner.classList.remove('hidden');
    accountWarningTimer = setTimeout(renderAccountWarningBanner, 1000);
}

function formatAccountPlayTime(seconds) {
    const totalMinutes = Math.max(0, Math.floor((Number(seconds) || 0) / 60));
    const days = Math.floor(totalMinutes / 1440);
    const hours = Math.floor((totalMinutes % 1440) / 60);
    const minutes = totalMinutes % 60;
    if (days > 0) return `${days}еӨ© ${hours}е°Ҹж—¶ ${minutes}еҲҶй’ҹ`;
    if (hours > 0) return `${hours}е°Ҹж—¶ ${minutes}еҲҶй’ҹ`;
    return `${minutes}еҲҶй’ҹ`;
}

function formatGrValue(value) {
    const n = Number(value);
    if (!Number.isFinite(n)) return '1000';
    return String(Math.round(n));
}

function renderGrMiniChart(history) {
    const points = (Array.isArray(history) ? history : [])
        .map(item => ({
            date: String(item.date || ''),
            season: Number(item.season_gr),
            total: Number(item.total_gr),
        }))
        .filter(item => item.date && Number.isFinite(item.season));
    if (points.length < 2) {
        return `<div class="account-gr-chart-empty">${escapeHtml(currentLang === 'zh' ? 'жҡӮж— и¶іеӨҹжӣІзәҝж•°жҚ®' : 'Not enough rating history')}</div>`;
    }
    const values = points.flatMap(item => [item.season, Number.isFinite(item.total) ? item.total : item.season]);
    const min = Math.min(...values, 950);
    const max = Math.max(...values, 1050);
    const span = Math.max(1, max - min);
    const w = 260;
    const h = 90;
    const pad = 10;
    const xFor = (idx) => pad + (points.length <= 1 ? 0 : idx * (w - pad * 2) / (points.length - 1));
    const yFor = (value) => h - pad - ((value - min) / span) * (h - pad * 2);
    const lineFor = (key) => points.map((item, idx) => `${xFor(idx).toFixed(1)},${yFor(Number.isFinite(item[key]) ? item[key] : item.season).toFixed(1)}`).join(' ');
    const last = points[points.length - 1] || {};
    return `
        <svg class="account-gr-chart-svg" viewBox="0 0 ${w} ${h}" role="img" aria-label="GR">
            <polyline class="account-gr-chart-total" points="${escapeHtml(lineFor('total'))}"></polyline>
            <polyline class="account-gr-chart-season" points="${escapeHtml(lineFor('season'))}"></polyline>
        </svg>
        <div class="account-gr-chart-legend">
            <span><i class="season"></i>${escapeHtml(currentLang === 'zh' ? 'иөӣеӯЈ' : 'Season')} ${escapeHtml(formatGrValue(last.season))}</span>
            <span><i class="total"></i>${escapeHtml(currentLang === 'zh' ? 'жҖ»еҲҶ' : 'Total')} ${escapeHtml(formatGrValue(last.total))}</span>
        </div>
    `;
}

function thornDewDeltaText(tx) {
    const free = Number(tx.free_delta || 0) || 0;
    const paid = Number(tx.paid_delta || 0) || 0;
    const total = free + paid;
    if (total > 0) return `+${total}`;
    return String(total);
}

function thornDewTransactionReason(tx = {}) {
    const sourceType = String(tx.source_type || '');
    const raw = String(tx.reason || sourceType || '');
    if (sourceType === 'achievement') {
        const achievementId = String(tx.source_id || '').split(':topup:')[0];
        const item = (achievementCenter?.achievements || []).find(entry => String(entry.id || '') === achievementId);
        const name = item?.name || achievementId;
        return lt({ zh: `жҲҗе°ұпјҡ${name}`, en: `Achievement: ${name}`, fr: `SuccГЁs : ${name}`, ja: `е®ҹзёҫпјҡ${name}` });
    }
    if (sourceType === 'daily_checkin') {
        const streak = (raw.match(/з¬¬\s*(\d+)\s*еӨ©/) || [])[1];
        return streak
            ? lt({ zh: `жҜҸж—ҘзӯҫеҲ° з¬¬${streak}еӨ©`, en: `Daily check-in, day ${streak}`, fr: `Connexion quotidienne, jour ${streak}`, ja: `гғӯгӮ°гӮӨгғігғңгғјгғҠгӮ№ ${streak}ж—Ҙзӣ®` })
            : lt({ zh: 'жҜҸж—ҘзӯҫеҲ°', en: 'Daily check-in', fr: 'Connexion quotidienne', ja: 'гғӯгӮ°гӮӨгғігғңгғјгғҠгӮ№' });
    }
    if (sourceType === 'match_reward') {
        const mode = (raw.match(/жңүж•ҲеҜ№еұҖеҘ–еҠұ\s+(\S+)/) || [])[1] || '';
        const result = raw.includes('е№іеұҖ')
            ? lt({ zh: 'е№іеұҖ', en: 'Draw', fr: 'Nul', ja: 'еј•еҲҶ' })
            : (raw.includes('иғңеҲ©') ? lt({ zh: 'иғңеҲ©', en: 'Win', fr: 'Victoire', ja: 'еӢқеҲ©' }) : '');
        const multiplier = (raw.match(/Г—[\d.]+/) || [])[0] || '';
        return [lt({ zh: 'жңүж•ҲеҜ№еұҖеҘ–еҠұ', en: 'Valid match reward', fr: 'RГ©compense de partie valide', ja: 'жңүеҠ№еҜҫжҲҰе ұй…¬' }), mode, result, multiplier].filter(Boolean).join(' ');
    }
    return raw;
}

function thornDewCenterHtml(user) {
    const free = Math.max(0, Number(user?.thorn_dew_free || 0) || 0);
    const paid = Math.max(0, Number(user?.thorn_dew_paid || 0) || 0);
    const total = Math.max(0, Number(user?.thorn_dew_total ?? (free + paid)) || 0);
    const center = thornDewCenter || {};
    const txs = Array.isArray(center.transactions) ? center.transactions.slice(0, 5) : [];
    const txHtml = txs.length
        ? txs.map(tx => `
            <div class="thorn-dew-tx">
                <span class="${(Number(tx.free_delta || 0) + Number(tx.paid_delta || 0)) >= 0 ? 'gain' : 'spend'}">${escapeHtml(thornDewDeltaText(tx))}</span>
                <span>${escapeHtml(thornDewTransactionReason(tx))}</span>
            </div>
        `).join('')
        : `<div class="account-replay-sub">${escapeHtml(lt({ zh: 'жҡӮж— иҚҶйңІи®°еҪ•', en: 'No Thorn Dew records yet', fr: 'Aucun historique de RosГ©e dвҖҷГ©pines', ja: 'гӮҪгғјгғігғҮгғҘгғјгҒ®еұҘжӯҙгҒҜгҒӮгӮҠгҒҫгҒӣгӮ“' }))}</div>`;
    return `
        <div class="thorn-dew-card">
            <div class="thorn-dew-head">
                <div>
                    <div class="thorn-dew-title">${escapeHtml(UI.thorn_dew || 'иҚҶйңІ')}</div>
                    <div class="thorn-dew-balance">${escapeHtml(total)}</div>
                    <div class="thorn-dew-sub">${escapeHtml(lt({ zh: 'еҸҜз”ЁдәҺжңӘжқҘе…‘жҚўеҶ…е®№', en: 'Available for future rewards', fr: 'Utilisable pour de futures rГ©compenses', ja: 'д»ҠеҫҢгҒ®е ұй…¬дәӨжҸӣгҒ«дҪҝз”ЁгҒ§гҒҚгҒҫгҒҷ' }))}</div>
                </div>
            </div>
            <div class="thorn-dew-tx-list">${txHtml}</div>
        </div>
    `;
}

function thornDewCheckinHtml() {
    const center = thornDewCenter || {};
    const checked = !!center.checked_in_today;
    const streak = Math.max(1, Number(center.streak_day || 1) || 1);
    const rewards = Array.isArray(center.checkin_rewards) && center.checkin_rewards.length
        ? center.checkin_rewards.map(item => Math.max(0, Number(item || 0) || 0))
        : [40, 45, 50, 55, 60, 70, 100];
    const reward = Math.max(0, Number(center.next_checkin_reward || rewards[(streak - 1) % rewards.length] || 40) || 40);
    const dayIndex = (Math.max(1, streak) - 1) % rewards.length;
    const pct = checked ? 100 : Math.max(8, Math.min(96, dayIndex / Math.max(1, rewards.length - 1) * 100));
    const dayLabel = lt({ zh: `иҝһз»ӯз¬¬ ${streak} еӨ©`, en: `Streak day ${streak}`, fr: `${streak} jour(s) consГ©cutif(s)`, ja: `${streak}ж—ҘйҖЈз¶ҡ` });
    return `
        <div class="thorn-dew-card">
            <div class="thorn-dew-head">
                <div>
                    <div class="thorn-dew-title">${escapeHtml(lt({ zh: 'зӯҫеҲ°', en: 'Check-in', fr: 'Connexion', ja: 'гғӯгӮ°гӮӨгғігғңгғјгғҠгӮ№' }))}</div>
                    <div class="thorn-dew-sub">${escapeHtml(dayLabel)}</div>
                </div>
                <button id="btn-thorn-dew-checkin-daily" class="btn btn-primary" type="button" ${checked || thornDewLoading ? 'disabled' : ''}>
                    ${escapeHtml(checked
                        ? lt({ zh: 'д»Ҡж—Ҙе·ІзӯҫеҲ°', en: 'Checked In', fr: 'DГ©jГ  rГ©cupГ©rГ©', ja: 'еҸ—еҸ–жёҲгҒҝ' })
                        : lt({ zh: `зӯҫеҲ° +${reward}`, en: `Check In +${reward}`, fr: `RГ©cupГ©rer +${reward}`, ja: `еҸ—гҒ‘еҸ–гӮӢ +${reward}` }))}
                </button>
            </div>
            <div class="thorn-dew-progress-wrap">
                <div class="thorn-dew-progress-meta">
                    <span>${escapeHtml(lt({ zh: `д»ҠеӨ©еҸҜиҺ·еҫ— ${reward} иҚҶйңІ`, en: `Today: ${reward} Thorn Dew`, fr: `AujourdвҖҷhui : ${reward} RosГ©e dвҖҷГ©pines`, ja: `жң¬ж—ҘпјҡгӮҪгғјгғігғҮгғҘгғј ${reward}` }))}</span>
                    <span>${escapeHtml(checked
                        ? lt({ zh: 'е·Іе®ҢжҲҗ', en: 'Done', fr: 'TerminГ©', ja: 'е®ҢдәҶ' })
                        : lt({ zh: 'еҫ…йўҶеҸ–', en: 'Ready', fr: 'Disponible', ja: 'еҸ—еҸ–еҸҜиғҪ' }))}</span>
                </div>
                <div class="thorn-dew-progress"><div class="thorn-dew-progress-fill" style="width:${pct.toFixed(1)}%"></div></div>
                <div class="thorn-dew-reward-track">
                    ${rewards.map((value, idx) => `
                        <div class="thorn-dew-day ${idx === dayIndex ? 'is-current' : ''}">
                            <div>${escapeHtml(lt({ zh: `з¬¬${idx + 1}еӨ©`, en: `D${idx + 1}`, fr: `J${idx + 1}`, ja: `${idx + 1}ж—Ҙзӣ®` }))}</div>
                            <div>+${escapeHtml(value)}</div>
                        </div>
                    `).join('')}
                </div>
            </div>
        </div>
    `;
}

