function leaderboardRankClass(rank) {
    const value = Number(rank);
    if (value === 1) return 'leaderboard-rank-gold';
    if (value === 2) return 'leaderboard-rank-silver';
    if (value === 3) return 'leaderboard-rank-bronze';
    return '';
}

function leaderboardRowHtml(item, rank, extraClass = '') {
    const games = Number(item && item.games_played || 0) || 0;
    const wins = Number(item && item.wins || 0) || 0;
    const losses = Number(item && item.losses || 0) || 0;
    const draws = Number(item && item.draws || 0) || 0;
    const rate = Number(item && item.win_rate || 0);
    const gr = Number(item && item.gr != null ? item.gr : (leaderboardScope === 'total' ? item.total_gr : item.season_gr));
    const rateText = `${Number.isInteger(rate) ? rate.toFixed(0) : rate.toFixed(1)}%`;
    const grText = Number.isFinite(gr) ? formatGrValue(gr) : '-';
    const rankClass = leaderboardRankClass(rank);
    return `
        <div class="leaderboard-row${extraClass ? ` ${extraClass}` : ''}">
            <span class="leaderboard-rank ${rankClass}">${escapeHtml(String(rank || '-'))}</span>
            <span class="leaderboard-name ${rankClass}">${escapeHtml(item && item.username || '-')}</span>
            <span class="leaderboard-rate leaderboard-gr">${escapeHtml(grText)}</span>
            <span class="leaderboard-rate">${escapeHtml(rateText)}</span>
            <span class="leaderboard-games">${games}</span>
            <span class="leaderboard-wins">${wins}</span>
            <span class="leaderboard-losses">${losses}</span>
            <span class="leaderboard-draws">${draws}</span>
        </div>
    `;
}

function leaderboardHeaderHtml() {
    const labels = currentLang === 'zh'
        ? ['жҺ’иЎҢ', 'жҳөз§°', UI.leaderboard_gr || 'иҠұйҳ¶еҲҶ', UI.leaderboard_raw_rate || 'иғңзҺҮ', 'жҖ»еұҖж•°', 'иғңеңә', 'иҙҘеңә', 'е№іеңә']
        : ['Rank', 'Name', UI.leaderboard_gr || 'GR', UI.leaderboard_raw_rate || 'Win %', 'Games', 'Wins', 'Losses', 'Draws'];
    return `<div class="leaderboard-row leaderboard-head">
        ${labels.map((label, idx) => {
            const cls = idx === 1 ? 'leaderboard-name' : '';
            return `<span class="${cls}">${escapeHtml(label)}</span>`;
        }).join('')}
    </div>`;
}

let leaderboardCache = null;
let leaderboardLoadingPromise = null;
let leaderboardRefreshTimerId = null;
let leaderboardScope = 'season';

function getNextLeaderboardRefreshMs(nowMs = Date.now()) {
    const intervalMs = 5 * 60 * 1000;
    return Math.floor(nowMs / intervalMs) * intervalMs + intervalMs;
}

function formatLeaderboardRefreshTime(tsMs) {
    const dt = new Date(tsMs);
    const hh = String(dt.getHours()).padStart(2, '0');
    const mm = String(dt.getMinutes()).padStart(2, '0');
    return `${hh}:${mm}`;
}

function updateLeaderboardRefreshMeta() {
    const meta = $('leaderboard-refresh-meta');
    if (!meta) return;
    const nextMs = leaderboardCache && leaderboardCache.nextRefreshMs
        ? leaderboardCache.nextRefreshMs
        : getNextLeaderboardRefreshMs();
    const remainSeconds = Math.max(0, Math.ceil((nextMs - Date.now()) / 1000));
    const mm = Math.floor(remainSeconds / 60);
    const ss = remainSeconds % 60;
    const timeText = `${mm}:${String(ss).padStart(2, '0')}`;
    meta.textContent = (UI.leaderboard_next_refresh || 'дёӢж¬Ў {0}').replace('{0}', timeText);
}

function startLeaderboardRefreshTimer() {
    if (leaderboardRefreshTimerId) clearInterval(leaderboardRefreshTimerId);
    updateLeaderboardRefreshMeta();
    leaderboardRefreshTimerId = setInterval(() => {
        const pop = $('leaderboard-popover');
        const open = pop && !pop.classList.contains('hidden');
        if (!open) {
            clearInterval(leaderboardRefreshTimerId);
            leaderboardRefreshTimerId = null;
            return;
        }
        updateLeaderboardRefreshMeta();
        if (leaderboardCache && Date.now() >= Number(leaderboardCache.nextRefreshMs || 0) + 250) {
            loadLeaderboard({ force: true, keepExisting: true });
        }
    }, 1000);
}

function renderLeaderboardItems(items, selfRank = null) {
    const list = $('leaderboard-list');
    if (!list) return;
    const rows = (Array.isArray(items) ? [...items] : []).sort((a, b) => {
        const scoreA = Number(a && a.gr != null ? a.gr : (leaderboardScope === 'total' ? (a && a.total_gr) : (a && a.season_gr)) || 0);
        const scoreB = Number(b && b.gr != null ? b.gr : (leaderboardScope === 'total' ? (b && b.total_gr) : (b && b.season_gr)) || 0);
        if (Math.abs(scoreB - scoreA) >= 0.0001) return scoreB - scoreA;
        const gamesKey = leaderboardScope === 'total' ? 'total_ranked_games' : 'season_ranked_games';
        return Number(b && b[gamesKey] || 0) - Number(a && a[gamesKey] || 0);
    });
    const currentId = currentAccount && currentAccount.id != null ? String(currentAccount.id) : '';
    let previousScore = null;
    let previousRank = 0;
    const renderedRows = rows.map((item, index) => {
        const isSelf = currentId && item && item.id != null && String(item.id) === currentId;
        const score = Number(item && item.gr != null ? item.gr : (leaderboardScope === 'total' ? (item && item.total_gr) : (item && item.season_gr)) || 0);
        const rank = previousScore !== null && Math.abs(score - previousScore) < 0.0001 ? previousRank : index + 1;
        previousScore = score;
        previousRank = rank;
        return leaderboardRowHtml(item, rank, isSelf ? 'is-self-rank' : '');
    }).join('');
    const selfRow = selfRank ? leaderboardRowHtml(selfRank, selfRank.rank, 'is-self-rank is-self-extra') : '';
    if (!rows.length) {
        list.innerHTML = leaderboardHeaderHtml()
            + `<div class="account-replay-sub">${escapeHtml(UI.leaderboard_empty || 'жҡӮж— з¬ҰеҗҲжқЎд»¶зҡ„зҺ©е®¶гҖӮ')}</div>`
            + selfRow;
        return;
    }
    list.innerHTML = leaderboardHeaderHtml() + renderedRows + selfRow;
}

async function loadLeaderboard(options = {}) {
    const list = $('leaderboard-list');
    if (!list) return;
    const now = Date.now();
    if (!options.force && leaderboardCache && now < Number(leaderboardCache.nextRefreshMs || 0)) {
        renderLeaderboardItems(leaderboardCache.items || [], leaderboardCache.selfRank || null);
        updateLeaderboardRefreshMeta();
        return;
    }
    if (leaderboardLoadingPromise) {
        return leaderboardLoadingPromise;
    }
    if (!options.keepExisting) {
        list.innerHTML = `<div class="account-replay-sub">${escapeHtml(UI.leaderboard_loading || 'жӯЈеңЁеҠ иҪҪжҺ’иЎҢжҰң...')}</div>`;
    }
    try {
        const minGames = leaderboardScope === 'total' ? 20 : 8;
        leaderboardLoadingPromise = authRequest(`/api/leaderboard?scope=${encodeURIComponent(leaderboardScope)}&min_games=${minGames}&limit=50`, undefined, { timeoutMs: 5000 });
        const data = await leaderboardLoadingPromise;
        const nextRefreshMs = data && data.next_refresh_ts
            ? Number(data.next_refresh_ts) * 1000
            : getNextLeaderboardRefreshMs();
        leaderboardCache = {
            items: data.items || [],
            selfRank: data.self_rank || null,
            nextRefreshMs,
            generatedAt: data.generated_at || '',
        };
        renderLeaderboardItems(data.items || [], data.self_rank || null);
        updateLeaderboardRefreshMeta();
    } catch (err) {
        if (!leaderboardCache) {
            list.innerHTML = `<div class="account-replay-sub">${escapeHtml(err.message || UI.account_error || 'еҠ иҪҪеӨұиҙҘ')}</div>`;
        }
    } finally {
        leaderboardLoadingPromise = null;
    }
}

function toggleLeaderboardPopover(force) {
    const pop = $('leaderboard-popover');
    if (!pop) return;
    const show = typeof force === 'boolean' ? force : pop.classList.contains('hidden');
    pop.classList.toggle('hidden', !show);
    if (show) {
        toggleAccountPopover(false);
        toggleFriendsPopover(false);
        toggleStatsPopover(false);
        toggleAchievementsPopover(false);
        loadLeaderboard();
        startLeaderboardRefreshTimer();
    } else if (leaderboardRefreshTimerId) {
        clearInterval(leaderboardRefreshTimerId);
        leaderboardRefreshTimerId = null;
    }
}

function friendDateText(value) {
    if (!value) return '-';
    const parsed = new Date(String(value).replace('Z', '+00:00'));
    if (Number.isNaN(parsed.getTime())) return String(value);
    return parsed.toLocaleString();
}

function friendStatsLine(user) {
    if (!user) return '';
    return `${tf('win_rate', Number(user.win_rate || 0).toFixed(1))} В· ${accountStatsText(user)}`;
}

function friendMatchResultText(result) {
    const key = String(result || '').toLowerCase();
    if (key === 'win') return UI.victory || 'Win';
    if (key === 'loss' || key === 'lose') return UI.defeat || 'Loss';
    if (key === 'draw') return UI.draw || 'Draw';
    return result || '';
}

function friendItemUserId(item) {
    const user = item && item.user ? item.user : {};
    return user.id == null ? '' : String(user.id);
}

function findFriendItemByUserId(userId) {
    const id = String(userId || '');
    return (Array.isArray(socialData.friends) ? socialData.friends : []).find(item => friendItemUserId(item) === id) || null;
}

function friendCardHtml(item, type) {
    const user = item?.user || {};
    const matches = Array.isArray(item?.matches) ? item.matches : [];
    const isNotice = item?.notice_type === 'auto_add' || item?.status === 'notice';
    const showPrivateInfo = type === 'friend';
    if (type === 'friend') {
        const unreadThread = (Array.isArray(dmData.threads) ? dmData.threads : []).find(thread => {
            const threadUser = thread.user || {};
            return String(threadUser.id || '') === String(user.id || '');
        });
        const unread = Number(unreadThread?.unread_count || 0);
        const active = String(activeSocialFriendId || '') === String(user.id || '');
        return `
          <button class="friend-name-row${active ? ' active' : ''}" type="button" data-friend-open="${escapeHtml(user.id)}">
            <span class="friend-name">${escapeHtml(user.username || '-')}</span>
            ${unread > 0 ? `<span class="dm-unread">${escapeHtml(unread > 99 ? '99+' : String(unread))}</span>` : ''}
          </button>`;
    }
    const matchText = matches.length
        ? matches.slice(0, 3).map(match => escapeHtml(`${match.mode || '-'} ${friendMatchResultText(match.result)} ${friendDateText(match.ended_at || match.started_at)}`)).join('<br>')
        : escapeHtml(`${UI.recent_matches}: -`);
    let actions = '';
    if (type === 'incoming' && !isNotice) {
        actions = `
          <button class="mini-btn" type="button" data-friend-respond="${escapeHtml(item.request_id)}" data-friend-action="accept">${escapeHtml(UI.friend_accept)}</button>
          <button class="mini-btn" type="button" data-friend-respond="${escapeHtml(item.request_id)}" data-friend-action="decline">${escapeHtml(UI.friend_decline)}</button>
          <button class="mini-btn" type="button" data-friend-respond="${escapeHtml(item.request_id)}" data-friend-action="ignore">${escapeHtml(UI.friend_ignore)}</button>`;
    } else if (type === 'friend') {
        actions = `
          <button class="mini-btn" type="button" data-dm-open-user="${escapeHtml(user.id)}" data-dm-open-name="${escapeHtml(user.username || '')}">з§ҒдҝЎ</button>
          <button class="mini-btn" type="button" data-friend-remove="${escapeHtml(user.id)}">${escapeHtml(UI.friend_remove)}</button>`;
    } else {
        actions = `<button class="mini-btn" type="button" data-dm-open-user="${escapeHtml(user.id)}" data-dm-open-name="${escapeHtml(user.username || '')}">з§ҒдҝЎ</button>`;
    }
    const noticeText = isNotice ? `<div class="friend-sub friend-notice">${escapeHtml(tf('friend_auto_added', user.username || '-'))}</div>` : '';
    const requestId = item?.request_id == null ? '' : String(item.request_id);
    const isRequestCard = type === 'incoming' || type === 'outgoing';
    const requestAttrs = isRequestCard && requestId
        ? ` data-friend-request-open="${escapeHtml(requestId)}" data-friend-request-type="${escapeHtml(type)}"`
        : '';
    const requestActive = isRequestCard && requestId && String(activeSocialRequestId || '') === requestId;
    return `
      <div class="friend-card${isRequestCard ? ' clickable' : ''}${requestActive ? ' active' : ''}"${requestAttrs}>
        <div class="friend-card-head">
          <span class="friend-name">${escapeHtml(user.username || '-')}</span>
          <span class="friend-id">${escapeHtml(user.player_id || '')}</span>
        </div>
        ${noticeText}
        ${showPrivateInfo ? `<div class="friend-sub">${escapeHtml(friendStatsLine(user))}</div>` : ''}
        ${showPrivateInfo ? `<div class="friend-sub">${escapeHtml(tf('last_login', friendDateText(user.last_login_at)))}</div>` : ''}
        ${showPrivateInfo ? `<div class="friend-sub"><b>${escapeHtml(UI.recent_matches)}</b><br>${matchText}</div>` : ''}
        ${actions ? `<div class="friend-actions">${actions}</div>` : ''}
      </div>`;
}

function renderFriendSection(id, items, emptyText, type) {
    const el = $(id);
    if (!el) return;
    const list = Array.isArray(items) ? items : [];
    if (!list.length) {
        el.innerHTML = `<div class="friend-empty">${escapeHtml(emptyText)}</div>`;
        return;
    }
    el.innerHTML = list.map(item => friendCardHtml(item, type)).join('');
}

function renderSocialSelectorList() {
    const el = $('social-selector-list');
    if (!el) return;
    if (activeSocialSection === 'requests') {
        const incoming = Array.isArray(socialData.incoming) ? socialData.incoming : [];
        const outgoing = Array.isArray(socialData.outgoing) ? socialData.outgoing : [];
        el.innerHTML = [
            `<div class="friend-section-title compact">${escapeHtml(UI.friend_requests || 'еҘҪеҸӢиҜ·жұӮ')}</div>`,
            incoming.length ? incoming.map(item => friendCardHtml(item, 'incoming')).join('') : `<div class="friend-empty">${escapeHtml(UI.friend_request_empty)}</div>`,
            `<div class="friend-section-title compact">${escapeHtml(UI.friend_sent || 'е·ІеҸ‘йҖҒ')}</div>`,
            outgoing.length ? outgoing.map(item => friendCardHtml(item, 'outgoing')).join('') : `<div class="friend-empty">${escapeHtml(UI.friend_sent_empty)}</div>`,
        ].join('');
        return;
    }
    if (activeSocialSection === 'dm') {
        const friends = Array.isArray(socialData.friends) ? socialData.friends : [];
        el.innerHTML = friends.length ? friends.map(item => {
            const user = item?.user || {};
            const thread = (Array.isArray(dmData.threads) ? dmData.threads : []).find(candidate => {
                const threadUser = candidate.user || {};
                return String(threadUser.id || '') === String(user.id || '');
            });
            const unread = Number(thread?.unread_count || 0);
            const active = String(activeDmTargetUserId || '') === String(user.id || '') || (thread && String(thread.thread_id) === String(activeDmThreadId));
            return `
              <button class="friend-name-row${active ? ' active' : ''}" type="button" data-dm-open-user="${escapeHtml(user.id || '')}" data-dm-open-name="${escapeHtml(user.username || '')}">
                <span class="dm-thread-name">${escapeHtml(user.username || '-')}</span>
                ${unread > 0 ? `<span class="dm-unread">${escapeHtml(unread > 99 ? '99+' : String(unread))}</span>` : ''}
              </button>`;
        }).join('') : `<div class="friend-empty">${escapeHtml(UI.friend_empty || 'жҡӮж— еҘҪеҸӢ')}</div>`;
        return;
    }
    const friends = Array.isArray(socialData.friends) ? socialData.friends : [];
    el.innerHTML = friends.length ? friends.map(item => friendCardHtml(item, 'friend')).join('') : `<div class="friend-empty">${escapeHtml(UI.friend_empty)}</div>`;
}

function findDmThreadByUserId(userId) {
    const id = String(userId || '');
    if (!id) return null;
    return (Array.isArray(dmData.threads) ? dmData.threads : []).find(thread => {
        const user = thread && thread.user ? thread.user : {};
        return String(user.id || '') === id;
    }) || null;
}

function findDmThreadById(threadId) {
    const id = String(threadId || '');
    if (!id) return null;
    return (Array.isArray(dmData.threads) ? dmData.threads : []).find(thread => String(thread.thread_id || '') === id) || null;
}

function clearDmUnreadForThread(threadId) {
    const tid = String(threadId || '');
    if (!tid || !Array.isArray(dmData.threads)) return;
    let removed = 0;
    dmData.threads = dmData.threads.map(thread => {
        if (String(thread.thread_id || '') !== tid) return thread;
        removed = Number(thread.unread_count || 0);
        return { ...thread, unread_count: 0 };
    });
    if (removed > 0) {
        dmData.unread_count = Math.max(0, Number(dmData.unread_count || 0) - removed);
    }
    updateFriendsBadge();
}

function renderUnifiedRequestsList() {
    const el = $('friend-requests-list');
    if (!el) return;
    const incoming = Array.isArray(socialData.incoming) ? socialData.incoming : [];
    const outgoing = Array.isArray(socialData.outgoing) ? socialData.outgoing : [];
    el.innerHTML = [
        `<div class="friend-section-title compact">${escapeHtml(UI.friend_requests || 'еҘҪеҸӢиҜ·жұӮ')}</div>`,
        incoming.length ? incoming.map(item => friendCardHtml(item, 'incoming')).join('') : `<div class="friend-empty">${escapeHtml(UI.friend_request_empty)}</div>`,
        `<div class="friend-section-title compact">${escapeHtml(UI.friend_sent || 'е·ІеҸ‘йҖҒ')}</div>`,
        outgoing.length ? outgoing.map(item => friendCardHtml(item, 'outgoing')).join('') : `<div class="friend-empty">${escapeHtml(UI.friend_sent_empty)}</div>`,
    ].join('');
}

function renderFriendsState() {
    renderFriendSection('friend-incoming-list', socialData.incoming, UI.friend_request_empty, 'incoming');
    renderFriendSection('friend-outgoing-list', socialData.outgoing, UI.friend_sent_empty, 'outgoing');
    renderUnifiedRequestsList();
    renderFriendSection('friends-list', socialData.friends, UI.friend_empty, 'friend');
    renderSocialSelectorList();
    renderFriendDetailProfile();
    renderDmThreads();
    updateFriendsBadge();
}

function normalizeSocialTab(tabName = 'friends') {
    const tab = String(tabName || 'friends');
    if (tab === 'profile') return 'friends';
    if (tab === 'incoming' || tab === 'outgoing' || tab === 'requests') return 'requests';
    if (tab === 'dm') return 'dm';
    return 'friends';
}

function showSocialDetailTab(tabName = 'friends') {
    const tab = normalizeSocialTab(tabName);
    activeSocialSection = tab;
    if (tab !== 'requests') activeSocialRequestId = null;
    document.querySelectorAll('[data-social-detail-tab]').forEach(btn => {
        btn.classList.toggle('active', btn.dataset.socialDetailTab === tab);
    });
    ['profile', 'dm', 'incoming', 'outgoing', 'requests'].forEach(name => {
        const page = $(`social-detail-page-${name}`);
        const visible = (tab === 'friends' && name === 'profile') || (tab === 'dm' && name === 'dm') || (tab === 'requests' && name === 'requests');
        if (page) page.classList.toggle('hidden', !visible);
    });
    renderSocialSelectorList();
    if (tab === 'dm') {
        loadDmThreads(true, { force: true }).then(() => {
            if (activeDmThreadId) {
                openDmThread(activeDmThreadId, { markRead: true, force: true });
            } else if (activeDmTargetUserId) {
                const thread = findDmThreadByUserId(activeDmTargetUserId);
                if (thread) openDmThread(thread.thread_id, { markRead: true, force: true });
                else renderDmMessages();
            } else {
                renderDmMessages();
            }
        });
    }
}

function toggleSocialDetailModal(force, tabName = 'friends') {
    const modal = $('social-detail-modal');
    if (!modal) return;
    const show = typeof force === 'boolean' ? force : modal.classList.contains('hidden');
    modal.classList.toggle('hidden', !show);
    if (show) {
        toggleFriendsPopover(false);
        toggleAccountPopover(false);
        showSocialDetailTab(tabName);
        renderFriendDetailProfile();
    } else {
        stopSocialNetworkActivity();
    }
}

function openFriendRequestDetail(requestId) {
    activeSocialRequestId = requestId == null ? null : String(requestId);
    toggleSocialDetailModal(true, 'requests');
    renderFriendsState();
    if (activeSocialRequestId && window.CSS && typeof CSS.escape === 'function') {
        const target = document.querySelector(`[data-friend-request-open="${CSS.escape(activeSocialRequestId)}"]`);
        if (target && typeof target.scrollIntoView === 'function') {
            target.scrollIntoView({ block: 'nearest', inline: 'nearest' });
        }
    }
}

function openFriendDetail(userId, tabName = 'friends') {
    if (userId != null && userId !== '') {
        activeSocialFriendId = String(userId);
    }
    toggleSocialDetailModal(true, tabName);
}

function renderFriendDetailProfile() {
    const el = $('friend-detail-profile');
    if (!el) return;
    const item = findFriendItemByUserId(activeSocialFriendId) || (Array.isArray(socialData.friends) ? socialData.friends[0] : null);
    if (!item) {
        activeSocialFriendId = null;
        el.innerHTML = `<div class="friend-empty">${escapeHtml(UI.friend_empty)}</div>`;
        return;
    }
    const user = item.user || {};
    activeSocialFriendId = String(user.id || '');
    const matches = Array.isArray(item.matches) ? item.matches : [];
    const matchHtml = matches.length
        ? matches.slice(0, 8).map(match => `
            <div class="friend-detail-match">${escapeHtml(`${match.mode || '-'} В· ${friendMatchResultText(match.result)} В· ${friendDateText(match.ended_at || match.started_at)}`)}</div>
          `).join('')
        : `<div class="friend-empty">${escapeHtml(`${UI.recent_matches}: -`)}</div>`;
    const lastSeenLabel = String(UI.last_login || 'дёҠж¬ЎдёӢзәҝ').replace(/\{0\}/g, '').replace(/[пјҡ:]\s*$/, '').trim() || 'дёҠж¬ЎдёӢзәҝ';
    el.innerHTML = `
      <div class="friend-detail-name">
        <span>${escapeHtml(user.username || '-')}</span>
        <span class="friend-id">${escapeHtml(user.player_id || '')}</span>
      </div>
      <div class="friend-detail-grid">
        <div class="friend-detail-stat"><b>${escapeHtml(UI.stats || 'з»ҹи®ЎдҝЎжҒҜ')}</b>${escapeHtml(friendStatsLine(user))}</div>
        <div class="friend-detail-stat"><b>${escapeHtml(lastSeenLabel)}</b>${escapeHtml(friendDateText(user.last_login_at))}</div>
      </div>
      <div class="friend-detail-actions">
        <button class="mini-btn" type="button" data-dm-open-user="${escapeHtml(user.id)}" data-dm-open-name="${escapeHtml(user.username || '')}">иҝӣе…Ҙз§ҒиҒҠ</button>
        <button class="mini-btn" type="button" data-friend-remove="${escapeHtml(user.id)}">${escapeHtml(UI.friend_remove)}</button>
      </div>
      <div>
        <div class="friend-section-title">${escapeHtml(UI.recent_matches)}</div>
        <div class="friend-detail-matches">${matchHtml}</div>
      </div>`;
}

function setFriendsError(message, tone = 'error', autoHideMs = 0) {
    const el = $('friends-error');
    if (!el) return;
    if (friendsMessageTimer) {
        clearTimeout(friendsMessageTimer);
        friendsMessageTimer = null;
    }
    el.textContent = message || '';
    el.classList.toggle('message-neutral', tone === 'neutral');
    el.classList.toggle('message-success', tone === 'success');
    if (message && autoHideMs > 0) {
        friendsMessageTimer = setTimeout(() => {
            el.textContent = '';
            el.classList.remove('message-neutral', 'message-success');
            friendsMessageTimer = null;
        }, autoHideMs);
    }
}

function updateFriendsBadge() {
    const btn = $('btn-friends-top');
    if (!btn) return;
    const count = Number(socialData.unread_count || 0) + Number(dmData.unread_count || 0);
    if (count > 0) {
        btn.dataset.badge = count > 99 ? '99+' : String(count);
        btn.classList.add('has-badge');
    } else {
        delete btn.dataset.badge;
        btn.classList.remove('has-badge');
    }
}

async function loadFriends(markRead = false) {
    if (!currentAccount) {
        socialData = { friends: [], incoming: [], outgoing: [], settings: null, unread_count: 0 };
        renderFriendsState();
        return;
    }
    try {
        const suffix = markRead ? '?mark_read=1' : '';
        const data = await authRequest(`/api/social/friends${suffix}`);
        socialData = {
            friends: Array.isArray(data.friends) ? data.friends : [],
            incoming: Array.isArray(data.incoming) ? data.incoming : [],
            outgoing: Array.isArray(data.outgoing) ? data.outgoing : [],
            settings: data.settings || null,
            unread_count: Number(data.unread_count || 0),
        };
        if (socialData.settings && currentAccount) {
            currentAccount = { ...currentAccount, ...socialData.settings };
            cacheAccount(currentAccount);
            renderSocialSettings();
        }
        renderFriendsState();
        loadDmThreads(true);
    } catch (err) {
        setFriendsError(err.message || UI.account_error);
    }
}

function renderDmThreads() {
    const list = $('dm-thread-list');
    if (!list) return;
    const threads = Array.isArray(dmData.threads) ? dmData.threads : [];
    if (!threads.length) {
        list.innerHTML = `<div class="friend-empty">жҡӮж— з§ҒдҝЎ</div>`;
    } else {
        list.innerHTML = threads.map(thread => {
            const user = thread.user || {};
            const unread = Number(thread.unread_count || 0);
            const active = String(thread.thread_id) === String(activeDmThreadId);
            return `
              <button class="dm-thread-item${active ? ' active' : ''}" type="button" data-dm-thread="${escapeHtml(thread.thread_id)}">
                <span class="dm-thread-name">${escapeHtml(user.username || '-')}</span>
                ${unread > 0 ? `<span class="dm-unread">${escapeHtml(unread > 99 ? '99+' : String(unread))}</span>` : ''}
                <span class="dm-thread-preview">${escapeHtml(thread.last_message || 'жҡӮж— ж¶ҲжҒҜ')}</span>
              </button>`;
        }).join('');
    }
    const title = $('dm-title');
    if (title) {
        const unread = Number(dmData.unread_count || 0);
        title.textContent = unread > 0 ? `з§ҒдҝЎ (${unread > 99 ? '99+' : unread})` : 'з§ҒдҝЎ';
    }
    if (activeSocialSection === 'dm') renderSocialSelectorList();
}

function renderDmMessages() {
    const list = $('dm-message-list');
    if (!list) return;
    if (!activeDmThreadId && !activeDmTargetUserId) {
        list.innerHTML = `<div class="friend-empty">йҖүжӢ©дјҡиҜқжҲ–иҫ“е…Ҙжҳөз§°/IDеҗҺеҸ‘йҖҒз¬¬дёҖжқЎз§ҒдҝЎ</div>`;
        const title = $('dm-chat-title');
        if (title) title.textContent = 'йҖүжӢ©дёҖдёӘдјҡиҜқ';
        return;
    }
    const currentUserId = currentAccount && currentAccount.id;
    list.innerHTML = '';
    const fragment = document.createDocumentFragment();
    (Array.isArray(activeDmMessages) ? activeDmMessages : []).forEach(msg => {
        const row = document.createElement('div');
        const self = Number(msg.sender_user_id) === Number(currentUserId);
        row.className = self ? 'dm-message self' : 'dm-message other';
        const bubble = document.createElement('div');
        bubble.className = 'dm-bubble';
        const meta = document.createElement('div');
        meta.className = `dm-sender-name ${feedbackNameClass(msg.sender_role)}`;
        const activeThread = findDmThreadById(activeDmThreadId);
        const nameText = self
            ? (msg.sender_name || currentAccount?.display_name || currentAccount?.username || '')
            : (msg.sender_name || activeThread?.user?.username || $('dm-chat-title')?.textContent?.replace(/^дёҺ\s*/, '').replace(/\s*зҡ„з§ҒдҝЎ$/, '') || '');
        const nameSpan = document.createElement('span');
        nameSpan.textContent = nameText;
        meta.appendChild(nameSpan);
        const timeSpan = document.createElement('span');
        timeSpan.className = 'dm-message-time';
        timeSpan.textContent = formatLobbyChatSeparator({ created_at: msg.created_at });
        meta.appendChild(timeSpan);
        const text = document.createElement('div');
        text.textContent = msg.message || '';
        bubble.appendChild(meta);
        bubble.appendChild(text);
        row.appendChild(bubble);
        fragment.appendChild(row);
    });
    list.appendChild(fragment);
    list.scrollTop = list.scrollHeight;
}

function isFriendsPopoverOpen() {
    const pop = $('friends-popover');
    return !!pop && !pop.classList.contains('hidden');
}

function isSocialDetailOpen() {
    const modal = $('social-detail-modal');
    return !!modal && !modal.classList.contains('hidden');
}

function isDmPanelOpen() {
    const page = $('social-detail-page-dm');
    return isSocialDetailOpen() && !!page && !page.classList.contains('hidden');
}

function abortDmFetches() {
    if (dmThreadsAbortController) {
        try { dmThreadsAbortController.abort(); } catch (_) {}
        dmThreadsAbortController = null;
    }
    if (dmMessagesAbortController) {
        try { dmMessagesAbortController.abort(); } catch (_) {}
        dmMessagesAbortController = null;
    }
    dmThreadsRequestPromise = null;
    dmMessageRequestPromises.clear();
}

function stopSocialNetworkActivity() {
    abortDmFetches();
}

function warnSocialEndpointStorm(endpoint) {
    const now = Date.now();
    const key = String(endpoint || '').split('?')[0];
    const times = (socialEndpointRequestTimes.get(key) || []).filter(ts => now - ts <= 10000);
    times.push(now);
    socialEndpointRequestTimes.set(key, times);
    if (times.length > 5) {
        console.warn(`[GTN social] endpoint request storm: ${key} ${times.length}/10s`);
    }
}

function socialBackoffReady(kind, threadId = '') {
    const now = Date.now();
    const store = kind === 'messages' ? dmFailureBackoff.messages : null;
    const item = store ? (store.get(String(threadId)) || { until: 0 }) : dmFailureBackoff;
    return now >= Number(item.until || 0);
}

function recordSocialBackoff(kind, threadId = '', failed = false) {
    const key = String(threadId || '');
    const now = Date.now();
    if (kind === 'messages') {
        const prev = dmFailureBackoff.messages.get(key) || { delay: 0, until: 0 };
        if (!failed) {
            dmFailureBackoff.messages.delete(key);
            return;
        }
        const delay = prev.delay ? Math.min(prev.delay * 2, 60000) : 5000;
        dmFailureBackoff.messages.set(key, { delay, until: now + delay });
        return;
    }
    if (!failed) {
        dmFailureBackoff.threads = 0;
        dmFailureBackoff.until = 0;
        return;
    }
    const delay = dmFailureBackoff.threads ? Math.min(dmFailureBackoff.threads * 2, 60000) : 5000;
    dmFailureBackoff.threads = delay;
    dmFailureBackoff.until = now + delay;
}

async function loadDmThreads(renderOnly = true, options = {}) {
    if (document.hidden || (!isFriendsPopoverOpen() && !isSocialDetailOpen())) return;
    if (!currentAccount) {
        dmData = { threads: [], unread_count: 0 };
        activeDmThreadId = null;
        activeDmTargetUserId = null;
        activeDmTargetIdentifier = '';
        activeDmMessages = [];
        renderDmThreads();
        renderDmMessages();
        updateFriendsBadge();
        return;
    }
    const force = options.force === true;
    if (!force) {
        const now = Date.now();
        if (now - Number(dmThreadsLastFetchAt || 0) < 10000) return;
    }
    if (!socialBackoffReady('threads')) return;
    if (dmThreadsRequestPromise) return dmThreadsRequestPromise;
    if (dmThreadsAbortController) {
        try { dmThreadsAbortController.abort(); } catch (_) {}
    }
    dmThreadsAbortController = typeof AbortController !== 'undefined' ? new AbortController() : null;
    const signal = dmThreadsAbortController ? dmThreadsAbortController.signal : undefined;
    const requestPath = '/api/social/dm/threads?limit=50';
    warnSocialEndpointStorm(requestPath);
    dmThreadsRequestPromise = (async () => {
    try {
        const data = await authRequest(requestPath, undefined, { signal, timeoutMs: 7000 });
        dmData = {
            threads: Array.isArray(data.threads) ? data.threads : [],
            unread_count: Number(data.unread_count || 0),
        };
        renderDmThreads();
        updateFriendsBadge();
        if (!renderOnly && activeDmThreadId) {
            await openDmThread(activeDmThreadId, { markRead: false, force: false });
        }
        dmThreadsLastFetchAt = Date.now();
        recordSocialBackoff('threads', '', false);
    } catch (err) {
        if (!(err && /abort|еҸ–ж¶Ҳ|и¶…ж—¶|timeout/i.test(String(err.message || err.name || '')))) {
            recordSocialBackoff('threads', '', true);
            setFriendsError(err.message || UI.account_error);
        }
    } finally {
        dmThreadsRequestPromise = null;
        dmThreadsAbortController = null;
    }
    })();
    return dmThreadsRequestPromise;
}

async function openDmThread(threadId, options = {}) {
    if (!threadId) return;
    if (document.hidden || !isDmPanelOpen()) return;
    const tid = String(threadId);
    const force = options.force === true;
    const markRead = options.markRead === true;
    if (!force && !markRead) {
        const last = Number(dmMessageLastFetchAt.get(tid) || 0);
        if (Date.now() - last < 5000) return;
    }
    if (!socialBackoffReady('messages', tid)) return;
    if (dmMessageRequestPromises.has(tid)) return dmMessageRequestPromises.get(tid);
    if (dmMessagesAbortController) {
        try { dmMessagesAbortController.abort(); } catch (_) {}
    }
    dmMessagesAbortController = typeof AbortController !== 'undefined' ? new AbortController() : null;
    const signal = dmMessagesAbortController ? dmMessagesAbortController.signal : undefined;
    const requestPath = `/api/social/dm/messages?thread_id=${encodeURIComponent(tid)}&limit=50&mark_read=${markRead ? '1' : '0'}`;
    warnSocialEndpointStorm(requestPath);
    const promise = (async () => {
    try {
        const data = await authRequest(requestPath, undefined, { signal, timeoutMs: 7000 });
        activeDmThreadId = data.thread_id || threadId;
        activeDmTargetUserId = data.user && data.user.id;
        activeDmTargetIdentifier = '';
        if (activeDmTargetUserId) activeSocialFriendId = String(activeDmTargetUserId);
        activeDmMessages = Array.isArray(data.messages) ? data.messages : [];
        const title = $('dm-chat-title');
        if (title) title.textContent = data.user && data.user.username ? `дёҺ ${data.user.username} зҡ„з§ҒдҝЎ` : 'з§ҒдҝЎ';
        if (markRead) clearDmUnreadForThread(activeDmThreadId);
        dmData.unread_count = Object.prototype.hasOwnProperty.call(data, 'unread_count')
            ? Number(data.unread_count || 0)
            : Number(dmData.unread_count || 0);
        renderDmThreads();
        renderDmMessages();
        renderFriendDetailProfile();
        updateFriendsBadge();
        dmMessageLastFetchAt.set(tid, Date.now());
        recordSocialBackoff('messages', tid, false);
    } catch (err) {
        if (!(err && /abort|еҸ–ж¶Ҳ|и¶…ж—¶|timeout/i.test(String(err.message || err.name || '')))) {
            recordSocialBackoff('messages', tid, true);
            setFriendsError(err.message || UI.account_error);
        }
    } finally {
        dmMessageRequestPromises.delete(tid);
        dmMessagesAbortController = null;
    }
    })();
    dmMessageRequestPromises.set(tid, promise);
    return promise;
}

async function startDmToUser(userId, username = '') {
    const uid = userId || null;
    activeDmTargetUserId = uid;
    activeDmTargetIdentifier = '';
    if (uid) activeSocialFriendId = String(uid);
    toggleSocialDetailModal(true, 'dm');
    let thread = findDmThreadByUserId(uid);
    if (!thread) {
        await loadDmThreads(true, { force: true });
        thread = findDmThreadByUserId(uid);
    }
    if (thread) {
        activeDmThreadId = thread.thread_id;
        clearDmUnreadForThread(activeDmThreadId);
        renderDmThreads();
        await openDmThread(activeDmThreadId, { markRead: true, force: true });
    } else {
        activeDmThreadId = null;
        activeDmMessages = [];
        const title = $('dm-chat-title');
        if (title) title.textContent = username ? `з»ҷ ${username} еҸ‘з§ҒдҝЎ` : 'ж–°з§ҒдҝЎ';
        renderDmThreads();
        renderDmMessages();
        renderFriendDetailProfile();
    }
    const input = $('dm-message-input');
    if (input) input.focus();
}

async function startDmFromIdentifier() {
    const input = $('input-social-identifier') || $('input-friend-identifier');
    const identifier = (input?.value || '').trim();
    if (!identifier) return;
    activeDmThreadId = null;
    activeDmTargetUserId = null;
    activeDmTargetIdentifier = identifier;
    activeDmMessages = [];
    const title = $('dm-chat-title');
    if (title) title.textContent = `з»ҷ ${identifier} еҸ‘з§ҒдҝЎ`;
    toggleSocialDetailModal(true, 'dm');
    const msgInput = $('dm-message-input');
    if (msgInput) msgInput.focus();
}

async function sendDmMessage() {
    const input = $('dm-message-input');
    if (!input) return;
    const text = input.value.trim();
    if (!text) return;
    const identifier = activeDmTargetIdentifier || ($('input-social-identifier')?.value || $('input-friend-identifier')?.value || '').trim();
    const payload = { text };
    if (activeDmTargetUserId) payload.target_user_id = activeDmTargetUserId;
    else if (identifier) payload.identifier = identifier;
    else {
        setFriendsError('иҜ·йҖүжӢ©з§ҒдҝЎеҜ№иұЎжҲ–иҫ“е…Ҙжҳөз§°/ID');
        return;
    }
    try {
        const data = await authRequest('/api/social/dm/send', payload);
        input.value = '';
        activeDmThreadId = data.thread_id || activeDmThreadId;
        activeDmTargetUserId = data.user && data.user.id ? data.user.id : activeDmTargetUserId;
        activeDmTargetIdentifier = '';
        activeDmMessages = Array.isArray(data.messages) ? data.messages : activeDmMessages;
        const title = $('dm-chat-title');
        if (title && data.user && data.user.username) title.textContent = `дёҺ ${data.user.username} зҡ„з§ҒдҝЎ`;
        await loadDmThreads(true, { force: true });
        renderDmMessages();
    } catch (err) {
        setFriendsError(err.message || UI.account_error);
    }
}

function formatDateTimeShort(value) {
    if (!value) return '-';
    const date = new Date(value);
    if (Number.isNaN(date.getTime())) return String(value || '-');
    return date.toLocaleString(currentLang === 'zh' ? 'zh-CN' : (currentLang === 'ja' ? 'ja-JP' : (currentLang === 'fr' ? 'fr-FR' : 'en-US')), {
        month: '2-digit',
        day: '2-digit',
        hour: '2-digit',
        minute: '2-digit',
        hour12: false,
    });
}

function feedbackNameClass(role) {
    const key = String(role || '').toLowerCase();
    if (key === 'admin') return 'admin-name';
    if (key === 'staff') return 'bloom-name';
    if (key === 'contributor') return 'guard-name';
    if (key === 'sponsor') return 'thorn-name';
    return '';
}

function updateFeedbackBadge() {
    const btn = $('btn-open-feedback');
    if (!btn) return;
    const count = Number(feedbackState.unread_count || 0);
    if (count > 0) {
        btn.dataset.badge = count > 99 ? '99+' : String(count);
        btn.classList.add('has-badge');
    } else {
        delete btn.dataset.badge;
        btn.classList.remove('has-badge');
    }
}

function feedbackStatusLabel(status) {
    const key = String(status || '').toLowerCase();
    if (key === 'closed') return currentLang === 'zh' ? 'е·Іе…ій—ӯ' : (currentLang === 'ja' ? 'зөӮдәҶ' : (currentLang === 'fr' ? 'FermГ©' : 'Closed'));
    if (key === 'pending') return currentLang === 'zh' ? 'е·ІеӣһеӨҚ' : (currentLang === 'ja' ? 'иҝ”дҝЎжёҲгҒҝ' : (currentLang === 'fr' ? 'RГ©pondu' : 'Replied'));
    return currentLang === 'zh' ? 'жңӘеӨ„зҗҶ' : (currentLang === 'ja' ? 'жңӘеҜҫеҝң' : (currentLang === 'fr' ? 'Ouvert' : 'Open'));
}

function feedbackStaffGroups(items = []) {
    const groups = [
        { key: 'open', label: feedbackStatusLabel('open'), items: [] },
        { key: 'pending', label: feedbackStatusLabel('pending'), items: [] },
        { key: 'closed', label: feedbackStatusLabel('closed'), items: [] },
    ];
    const byKey = Object.fromEntries(groups.map(group => [group.key, group]));
    (Array.isArray(items) ? items : []).forEach(item => {
        const key = ['open', 'pending', 'closed'].includes(String(item.status || '').toLowerCase())
            ? String(item.status || '').toLowerCase()
            : 'open';
        byKey[key].items.push(item);
    });
    return groups;
}

async function loadFeedbackSummary() {
    if (!currentAccount) {
        feedbackState = { is_staff: false, unread_count: 0, threads: [], messages: [], thread: null, replay: null };
        updateFeedbackBadge();
        return;
    }
    try {
        const data = await authRequest('/api/feedback/summary', undefined, { timeoutMs: 5000 });
        feedbackState.is_staff = !!data.is_staff;
        feedbackState.unread_count = Number(data.unread_count || 0);
        updateFeedbackBadge();
    } catch (_) {
        updateFeedbackBadge();
    }
}

function renderFeedbackThreads() {
    const list = $('feedback-thread-list');
    if (!list) return;
    const items = Array.isArray(feedbackState.threads) ? feedbackState.threads : [];
    if (!currentAccount) {
        list.innerHTML = `<div class="friend-empty">${escapeHtml(UI.feedback_login_required || 'зҷ»еҪ•иҙҰеҸ·еҗҺеҸҜд»ҘеҸ‘йҖҒеҸҚйҰҲгҖӮ')}</div>`;
        return;
    }
    if (!items.length) {
        list.innerHTML = `<div class="friend-empty">${escapeHtml(activeFeedbackStaffView ? (UI.feedback_staff_empty || 'жҡӮж— зҺ©е®¶еҸҚйҰҲгҖӮ') : (UI.feedback_empty || 'жҡӮж— еҸҚйҰҲгҖӮ'))}</div>`;
        return;
    }
    const renderItem = (item) => {
        const active = String(item.id) === String(activeFeedbackThreadId);
        const user = item.user || {};
        const title = item.title || item.last_message || `#${item.id}`;
        const status = feedbackStatusLabel(item.status);
        const replayRef = Number(item.replay_id) > 0 ? `R-${Number(item.replay_id)}` : '';
        return `
          <button class="feedback-thread-item${active ? ' active' : ''}" type="button" data-feedback-thread="${escapeHtml(item.id)}">
            <span class="feedback-thread-title">${item.unread ? '<span class="feedback-dot"></span>' : ''}${escapeHtml(title)}</span>
            <span class="feedback-thread-meta">${escapeHtml([activeFeedbackStaffView ? `${user.username || '-'} В· ${status}` : status, replayRef, formatDateTimeShort(item.updated_at || item.created_at || '')].filter(Boolean).join(' В· '))}</span>
            <span class="feedback-thread-preview">${escapeHtml(item.last_message || '')}</span>
          </button>`;
    };
    if (activeFeedbackStaffView) {
        list.innerHTML = feedbackStaffGroups(items).map(group => {
            const collapsed = !!feedbackCollapsedGroups[group.key];
            const rows = collapsed ? '' : group.items.map(renderItem).join('');
            return `
              <section class="feedback-thread-group feedback-thread-group-${escapeHtml(group.key)}${collapsed ? ' collapsed' : ''}">
                <button class="feedback-thread-group-title" type="button" data-feedback-group-toggle="${escapeHtml(group.key)}">
                  <span class="feedback-thread-group-arrow">${collapsed ? '>' : 'v'}</span>
                  <span>${escapeHtml(group.label)}</span>
                  <span>${escapeHtml(group.items.length)}</span>
                </button>
                ${rows || (collapsed ? '' : `<div class="feedback-thread-group-empty">${escapeHtml(UI.feedback_staff_empty || 'жҡӮж— зҺ©е®¶еҸҚйҰҲгҖӮ')}</div>`)}
              </section>`;
        }).join('');
        return;
    }
    list.innerHTML = items.map(renderItem).join('');
}

function renderFeedbackMessages() {
    const list = $('feedback-message-list');
    if (!list) return;
    if (!currentAccount) {
        list.innerHTML = `<div class="friend-empty">${escapeHtml(UI.feedback_login_required || 'зҷ»еҪ•иҙҰеҸ·еҗҺеҸҜд»ҘеҸ‘йҖҒеҸҚйҰҲгҖӮ')}</div>`;
        return;
    }
    const messages = Array.isArray(feedbackState.messages) ? feedbackState.messages : [];
    if (!activeFeedbackThreadId && !messages.length) {
        list.innerHTML = `<div class="friend-empty">${escapeHtml(activeFeedbackStaffView ? 'йҖүжӢ©дёҖжқЎзҺ©е®¶еҸҚйҰҲгҖӮ' : 'еЎ«еҶҷеҶ…е®№еҗҺеҸ‘йҖҒж–°зҡ„еҸҚйҰҲгҖӮ')}</div>`;
        return;
    }
    const currentUserId = currentAccount && currentAccount.id;
    list.innerHTML = '';
    const fragment = document.createDocumentFragment();
    messages.forEach(msg => {
        const self = Number(msg.sender_user_id) === Number(currentUserId);
        const row = document.createElement('div');
        row.className = `feedback-message ${self ? 'self' : 'other'}`;
        const bubble = document.createElement('div');
        bubble.className = 'feedback-bubble';
        const meta = document.createElement('div');
        meta.className = `feedback-sender ${feedbackNameClass(msg.sender_role)}`;
        const nameSpan = document.createElement('span');
        nameSpan.textContent = msg.sender_name || (self ? (currentAccount.username || '') : '-');
        meta.appendChild(nameSpan);
        const timeSpan = document.createElement('span');
        timeSpan.className = 'feedback-message-time';
        timeSpan.textContent = formatLobbyChatSeparator({ created_at: msg.created_at });
        meta.appendChild(timeSpan);
        const text = document.createElement('div');
        text.className = 'feedback-text';
        text.textContent = msg.message || '';
        bubble.appendChild(meta);
        bubble.appendChild(text);
        row.appendChild(bubble);
        fragment.appendChild(row);
    });
    list.appendChild(fragment);
    list.scrollTop = list.scrollHeight;
}

function ensureReplayVideoExportStyle() {
    if ($('gtn-replay-video-export-style')) return;
    const style = document.createElement('style');
    style.id = 'gtn-replay-video-export-style';
    style.textContent = `
        html.replay-video-export,
        html.replay-video-export body {
            width: 100%;
            height: 100%;
            margin: 0;
            overflow: hidden !important;
            background: var(--page-bg, #f5f5f3);
        }
        html.replay-video-export #account-replay-playback-bar,
        html.replay-video-export #account-replay-modal,
        html.replay-video-export #boot-loader,
        html.replay-video-export .top-action-buttons,
        html.replay-video-export .controls-bar,
        html.replay-video-export .classic-controls,
        html.replay-video-export .game-chat-input-row,
        html.replay-video-export .battle-chat-input-row {
            display: none !important;
        }
        html.replay-video-export.hide-export-cursor,
        html.replay-video-export.hide-export-cursor * {
            cursor: none !important;
        }
    `;
    document.head.appendChild(style);
}

async function loadReplayForVideoExport(payload, options = {}) {
    const replayPayload = payload && typeof payload === 'object' ? payload : {};
    const timeline = Array.isArray(replayPayload.timeline) ? replayPayload.timeline.filter(Boolean) : [];
    if (!timeline.length) throw new Error('Replay timeline is empty');
    stopAccountReplayPlayback();
    accountReplayLoadToken += 1;
    accountReplayReturnContext = null;
    accountReplayFrameFetches.clear();
    accountReplayTimeline = timeline;
    accountReplayTotalFrames = timeline.length;
    accountReplayFrameIndex = 0;
    accountReplayPerspective = Math.max(0, Number(options.perspective) || 0);
    accountReplayLoading = false;
    accountReplayControlsCollapsed = true;
    const replayInfo = replayPayload.replay && typeof replayPayload.replay === 'object' ? replayPayload.replay : {};
    accountReplayData = {
        id: replayInfo.id || replayPayload.replay_id || 'local',
        meta: replayInfo.meta || replayPayload.meta || {},
        rules: replayInfo.rules || replayPayload.rules || {},
    };

    const lang = normalizeLang(options.lang || currentLang || 'zh');
    currentLang = lang;
    localStorage.setItem('gtn_lang', lang);
    applyLang();
    applyTheme(options.theme === 'dark' ? 'dark' : 'light');
    applyUiStyle(options.ui_style === 'classic' ? 'classic' : 'minimal');
    showCardImages = true;
    localStorage.setItem('gtn_show_card_images', '1');
    showEnglishCardNames = options.show_english_names !== false;
    localStorage.setItem('gtn_show_english_card_names', showEnglishCardNames ? '1' : '0');
    try {
        const defs = await fetchGalleryCardDefs({ force: true });
        if (defs && Object.keys(defs).length) CARD_DEFS = defs;
    } catch (error) {
        console.warn('[replay-export] failed to load all bundled card definitions', error);
    }

    replayMode = true;
    isSpectating = true;
    playerId = -1;
    spectatePerspective = accountReplayPerspective;
    activeSpectateRoomId = null;
    pendingSpectateRoomId = null;
    ensureReplayVideoExportStyle();
    document.documentElement.classList.add('replay-video-export');
    document.documentElement.classList.toggle('hide-export-cursor', options.hide_cursor !== false);
    const appRoot = $('app');
    if (appRoot) appRoot.style.visibility = 'visible';
    const bootLoaderEl = $('boot-loader');
    if (bootLoaderEl) bootLoaderEl.classList.add('hidden');
    const replayModal = $('account-replay-modal');
    if (replayModal) replayModal.classList.add('hidden');
    showView('view-game');
    renderAccountReplayFrame();
    const playbackBar = $('account-replay-playback-bar');
    if (playbackBar) playbackBar.classList.add('hidden');
    if (document.fonts && document.fonts.ready) await document.fonts.ready;
    return {
        frame_count: timeline.length,
        players: collectReplayPlayers(getReplaySnapshot(timeline[0])).map(player => player.name || ''),
        meta: accountReplayData.meta,
    };
}

window.GTNReplayVideoBridge = {
    version: 1,
    async load(payload, options = {}) {
        return loadReplayForVideoExport(payload, options);
    },
    async loadFromUrl(url, options = {}) {
        const response = await fetch(url, { cache: 'no-store' });
        if (!response.ok) throw new Error(`Replay file HTTP ${response.status}`);
        return loadReplayForVideoExport(await response.json(), options);
    },
    showFrame(index) {
        const maxIndex = Math.max(0, accountReplayTimeline.length - 1);
        accountReplayFrameIndex = Math.max(0, Math.min(maxIndex, Number(index) || 0));
        renderAccountReplayFrame();
        const playbackBar = $('account-replay-playback-bar');
        if (playbackBar) playbackBar.classList.add('hidden');
        const frame = accountReplayTimeline[accountReplayFrameIndex] || {};
        return {
            index: accountReplayFrameIndex,
            t: Number(frame.t) || 0,
            phase: frame.phase || '',
            round: frame.round || 0,
            action: replayActionLabel(frame),
        };
    },
    setPerspective(index) {
        accountReplayPerspective = Math.max(0, Number(index) || 0);
        spectatePerspective = accountReplayPerspective;
        return this.showFrame(accountReplayFrameIndex);
    },
    info() {
        return {
            frame_count: accountReplayTimeline.length,
            frame_index: accountReplayFrameIndex,
            perspective: accountReplayPerspective,
            ready: replayMode && accountReplayTimeline.length > 0,
        };
    },
};

function normalizedFeedbackReplayId(value) {
    const text = String(value || '').trim().toUpperCase().replace(/^R-/, '');
    if (!/^\d+$/.test(text) || Number(text) <= 0) return null;
    return Number(text);
}

function renderFeedbackReplayPreview() {
    const box = $('feedback-replay-preview');
    if (!box) return;
    const threadReplayId = Number(feedbackState.thread && feedbackState.thread.replay_id || 0);
    const replay = feedbackState.replay;
    const replayId = Number(replay && replay.id || threadReplayId || 0);
    if (!(replayId > 0)) {
        box.innerHTML = '';
        box.classList.add('hidden');
        return;
    }
    const replayRef = `R-${replayId}`;
    const players = replay && Array.isArray(replay.players) ? replay.players.join(' / ') : '';
    const detail = replay
        ? [formatCommunityTime(replay.created_at), replay.mode, players].filter(Boolean).join(' В· ')
        : (currentLang === 'zh' ? 'еӣһж”ҫдёҚеӯҳеңЁжҲ–е·ІиҝҮжңҹ' : 'Replay unavailable or expired');
    box.innerHTML = `
        <div class="feedback-replay-preview-main"><strong>${escapeHtml(replayRef)}</strong>${detail ? ` В· ${escapeHtml(detail)}` : ''}</div>
        ${replay ? `<button class="mini-btn" type="button" data-feedback-replay-open="${escapeHtml(replayId)}">${escapeHtml(UI.replay_view || 'жҹҘзңӢ')}</button>` : ''}
    `;
    box.classList.remove('hidden');
}

async function loadFeedbackReplayPreview(replayId, showError = false) {
    const normalized = normalizedFeedbackReplayId(replayId);
    feedbackState.replay = null;
    if (!normalized) {
        renderFeedbackReplayPreview();
        return false;
    }
    try {
        const data = await authRequest(`/api/replays/${encodeURIComponent(normalized)}`);
        feedbackState.replay = data.replay || null;
        renderFeedbackReplayPreview();
        return !!feedbackState.replay;
    } catch (err) {
        renderFeedbackReplayPreview();
        if (showError) {
            const errorBox = $('feedback-error');
            if (errorBox) errorBox.textContent = err.message || UI.replay_load_failed;
        }
        return false;
    }
}

function updateFeedbackReplayField() {
    const category = $('feedback-category');
    const input = $('feedback-replay-id');
    const creatingAppeal = !activeFeedbackThreadId
        && !activeFeedbackStaffView
        && category
        && category.value === 'appeal';
    if (input) input.classList.toggle('hidden', !creatingAppeal);
    if (!activeFeedbackThreadId && !creatingAppeal) feedbackState.replay = null;
    renderFeedbackReplayPreview();
}

function renderFeedbackModal() {
    const staffTab = $('feedback-tab-staff');
    if (staffTab) staffTab.classList.toggle('hidden', !feedbackState.is_staff);
    document.querySelectorAll('[data-feedback-tab]').forEach(btn => {
        btn.classList.toggle('active', btn.dataset.feedbackTab === activeFeedbackTab);
    });
    activeFeedbackStaffView = activeFeedbackTab === 'staff';
    const category = $('feedback-category');
    const titleInput = $('feedback-title-input');
    const statusSelect = $('feedback-status-select');
    if (category) category.classList.toggle('hidden', activeFeedbackStaffView || !!activeFeedbackThreadId);
    if (titleInput) titleInput.classList.toggle('hidden', activeFeedbackStaffView || !!activeFeedbackThreadId);
    if (statusSelect) statusSelect.classList.toggle('hidden', !activeFeedbackStaffView || !activeFeedbackThreadId);
    updateFeedbackReplayField();
    renderFeedbackThreads();
    renderFeedbackMessages();
    updateFeedbackBadge();
}

async function loadFeedbackThreads(staffView = false) {
    if (!currentAccount) {
        feedbackState.threads = [];
        feedbackState.messages = [];
        feedbackState.thread = null;
        feedbackState.replay = null;
        renderFeedbackModal();
        return;
    }
    try {
        let data;
        if (staffView) {
            const statuses = ['open', 'pending', 'closed'];
            const results = await Promise.all(statuses.map(status =>
                authRequest(`/api/feedback/threads?staff=1&status=${encodeURIComponent(status)}&limit=30`, undefined, { timeoutMs: 7000 })
            ));
            data = {
                is_staff: results.some(item => item && item.is_staff),
                unread_count: Math.max(...results.map(item => Number(item && item.unread_count || 0)), 0),
                items: results.flatMap(item => Array.isArray(item && item.items) ? item.items : []),
            };
        } else {
            data = await authRequest('/api/feedback/threads?staff=0&limit=50', undefined, { timeoutMs: 7000 });
        }
        feedbackState.is_staff = !!data.is_staff;
        feedbackState.unread_count = Number(data.unread_count || 0);
        feedbackState.threads = Array.isArray(data.items) ? data.items : [];
        if (!activeFeedbackThreadId && feedbackState.threads.length && staffView) {
            activeFeedbackThreadId = feedbackState.threads[0].id;
            await openFeedbackThread(activeFeedbackThreadId);
            return;
        }
        renderFeedbackModal();
    } catch (err) {
        const box = $('feedback-error');
        if (box) box.textContent = err.message || UI.account_error;
    }
}

async function openFeedbackThread(threadId) {
    if (!threadId) return;
    activeFeedbackThreadId = threadId;
    try {
        const data = await authRequest(`/api/feedback/messages?thread_id=${encodeURIComponent(threadId)}&limit=100&mark_read=1`, undefined, { timeoutMs: 7000 });
        feedbackState.is_staff = !!data.is_staff;
        feedbackState.unread_count = Number(data.unread_count || 0);
        feedbackState.messages = Array.isArray(data.messages) ? data.messages : [];
        const thread = data.thread || {};
        feedbackState.thread = thread;
        feedbackState.replay = null;
        const statusSelect = $('feedback-status-select');
        if (statusSelect && thread.status) statusSelect.value = thread.status;
        renderFeedbackModal();
        if (thread.replay_id) await loadFeedbackReplayPreview(thread.replay_id);
    } catch (err) {
        const box = $('feedback-error');
        if (box) box.textContent = err.message || UI.account_error;
    }
}

async function sendFeedbackMessage() {
    const input = $('feedback-message-input');
    const text = (input?.value || '').trim();
    const box = $('feedback-error');
    if (box) box.textContent = '';
    if (!currentAccount) {
        if (box) box.textContent = UI.feedback_login_required || 'зҷ»еҪ•иҙҰеҸ·еҗҺеҸҜд»ҘеҸ‘йҖҒеҸҚйҰҲгҖӮ';
        return;
    }
    if (!text) return;
    const payload = { text };
    if (activeFeedbackThreadId) payload.thread_id = activeFeedbackThreadId;
    else {
        payload.category = $('feedback-category')?.value || 'other';
        payload.title = ($('feedback-title-input')?.value || '').trim();
        if (payload.category === 'appeal') payload.replay_id = ($('feedback-replay-id')?.value || '').trim();
    }
    try {
        const data = await authRequest('/api/feedback/send', payload, { timeoutMs: 7000 });
        if (input) input.value = '';
        activeFeedbackThreadId = data.thread?.id || data.thread_id || activeFeedbackThreadId;
        feedbackState.is_staff = !!data.is_staff;
        feedbackState.unread_count = Number(data.unread_count || 0);
        feedbackState.messages = Array.isArray(data.messages) ? data.messages : [];
        feedbackState.thread = data.thread || feedbackState.thread;
        await loadFeedbackThreads(activeFeedbackStaffView);
        if (activeFeedbackThreadId) await openFeedbackThread(activeFeedbackThreadId);
        if (box) box.textContent = UI.feedback_sent || 'еҸҚйҰҲе·ІеҸ‘йҖҒ';
    } catch (err) {
        if (box) box.textContent = err.message || UI.account_error;
    }
}

async function updateFeedbackStatus() {
    if (!activeFeedbackThreadId || !feedbackState.is_staff) return;
    const status = $('feedback-status-select')?.value || 'open';
    try {
        const data = await authRequest('/api/feedback/status', { thread_id: activeFeedbackThreadId, status }, { timeoutMs: 7000 });
        feedbackState.messages = Array.isArray(data.messages) ? data.messages : feedbackState.messages;
        await loadFeedbackThreads(true);
        await openFeedbackThread(activeFeedbackThreadId);
    } catch (err) {
        const box = $('feedback-error');
        if (box) box.textContent = err.message || UI.account_error;
    }
}

async function toggleFeedbackModal(show) {
    const modal = $('feedback-modal');
    if (!modal) return;
    modal.classList.toggle('hidden', !show);
    if (!show) return;
    activeFeedbackTab = feedbackState.is_staff && activeFeedbackTab === 'staff' ? 'staff' : 'send';
    activeFeedbackStaffView = activeFeedbackTab === 'staff';
    if (!currentAccount) {
        feedbackState.threads = [];
        feedbackState.messages = [];
        renderFeedbackModal();
        return;
    }
    await loadFeedbackSummary();
    await loadFeedbackThreads(activeFeedbackStaffView);
}

async function addFriendFromInput() {
    setFriendsError('');
    const input = $('input-social-identifier') || $('input-friend-identifier');
    const identifier = (input?.value || '').trim();
    if (!identifier) return;
    try {
        const outgoingBefore = Array.isArray(socialData.outgoing) ? socialData.outgoing.length : 0;
        const data = await authRequest('/api/social/friends/add', { identifier });
        socialData = {
            friends: Array.isArray(data.friends) ? data.friends : [],
            incoming: Array.isArray(data.incoming) ? data.incoming : [],
            outgoing: Array.isArray(data.outgoing) ? data.outgoing : [],
            settings: data.settings || socialData.settings,
            unread_count: Number(data.unread_count || 0),
        };
        if (input) input.value = '';
        const outgoingAfter = Array.isArray(socialData.outgoing) ? socialData.outgoing.length : 0;
        setFriendsError(outgoingAfter > outgoingBefore ? UI.friend_added : (UI.friend_added_direct || UI.friend_updated), 'neutral', 2200);
        renderFriendsState();
    } catch (err) {
        setFriendsError(err.message || UI.account_error);
    }
}

async function respondFriendRequest(requestId, action) {
    try {
        const data = await authRequest('/api/social/friends/respond', { request_id: requestId, action });
        socialData = {
            friends: Array.isArray(data.friends) ? data.friends : [],
            incoming: Array.isArray(data.incoming) ? data.incoming : [],
            outgoing: Array.isArray(data.outgoing) ? data.outgoing : [],
            settings: data.settings || socialData.settings,
            unread_count: Number(data.unread_count || 0),
        };
        setFriendsError(UI.friend_updated, 'neutral', 1800);
        renderFriendsState();
    } catch (err) {
        setFriendsError(err.message || UI.account_error);
    }
}

async function removeFriend(userId) {
    if (!confirm(UI.friend_remove_confirm || 'зЎ®и®ӨеҲ йҷӨиҝҷдёӘеҘҪеҸӢеҗ—пјҹ')) return;
    try {
        const data = await authRequest('/api/social/friends/remove', { user_id: userId });
        socialData = {
            friends: Array.isArray(data.friends) ? data.friends : [],
            incoming: Array.isArray(data.incoming) ? data.incoming : [],
            outgoing: Array.isArray(data.outgoing) ? data.outgoing : [],
            settings: data.settings || socialData.settings,
            unread_count: Number(data.unread_count || 0),
        };
        setFriendsError(UI.friend_removed, 'neutral', 1800);
        renderFriendsState();
    } catch (err) {
        setFriendsError(err.message || UI.account_error);
    }
}

function toggleFriendsPopover(force) {
    const pop = $('friends-popover');
    if (!pop) return;
    const show = typeof force === 'boolean' ? force : pop.classList.contains('hidden');
    pop.classList.toggle('hidden', !show);
    if (show) {
        toggleAccountPopover(false);
        toggleStatsPopover(false);
        toggleLeaderboardPopover(false);
        loadFriends(true);
    } else {
        stopSocialNetworkActivity();
    }
}

function openSocialCenter(tabName = 'friends') {
    const requested = tabName === 'friends' && Number(socialData.unread_count || 0) > 0 ? 'requests' : tabName;
    toggleSocialDetailModal(true, requested);
    loadFriends(true);
}

function renderSocialSettings() {
    const ids = [
        ['settings-accept-friend-requests', 'accept_friend_requests'],
        ['settings-searchable-by-nickname', 'searchable_by_nickname'],
        ['settings-searchable-by-player-id', 'searchable_by_player_id'],
        ['settings-accept-game-invites', 'accept_game_invites'],
        ['settings-allow-guest-spectators', 'allow_guest_spectators'],
    ];
    ids.forEach(([id, key]) => {
        const input = $(id);
        if (!input) return;
        input.disabled = !currentAccount;
        input.checked = currentAccount ? (key === 'allow_guest_spectators' ? currentAccount[key] === true : currentAccount[key] !== false) : key !== 'allow_guest_spectators';
    });
    const hint = $('settings-social-login-hint');
    if (hint) hint.classList.toggle('hidden', !!currentAccount);
}

async function saveSocialSettings() {
    if (!currentAccount) {
        renderSocialSettings();
        return;
    }
    const payload = {
        accept_friend_requests: !!$('settings-accept-friend-requests')?.checked,
        searchable_by_nickname: !!$('settings-searchable-by-nickname')?.checked,
        searchable_by_player_id: !!$('settings-searchable-by-player-id')?.checked,
        accept_game_invites: !!$('settings-accept-game-invites')?.checked,
        allow_guest_spectators: !!$('settings-allow-guest-spectators')?.checked,
    };
    const status = $('settings-social-status');
    try {
        const data = await authRequest('/api/social/settings', payload);
        currentAccount = data.user || { ...currentAccount, ...payload };
        if (status) status.textContent = UI.social_settings_saved;
        renderAccountState();
    } catch (err) {
        if (status) status.textContent = err.message || UI.account_error;
        renderSocialSettings();
    }
}

function getServerAddress() {
    localStorage.removeItem('gtn_server');
    return DEFAULT_SERVER;
}

function isLocalSoloRuntimeActive() {
    // Solo training intentionally uses the server-side 1v1 GameEngine.
    // Keep the old worker code dormant so solo behavior represents real games.
    return false;
}

function clearPendingSoloFallback() {
    if (pendingSoloFallbackTimer) {
        clearTimeout(pendingSoloFallbackTimer);
        pendingSoloFallbackTimer = null;
    }
}

function scheduleSoloOfflineFallback(kind, payload) {
    clearPendingSoloFallback();
    pendingSoloFallbackTimer = setTimeout(() => {
        pendingSoloFallbackTimer = null;
        if (soloMode || (gameState && gameState.solo)) return;
        if (socket && socket.connected) return;
        pendingSoloStart = false;
        pendingTutorialStart = false;
        window.__pendingSoloPayload = null;
        flashStatus(UI.server_no_response || UI.server_not_connected || UI.operation_failed, 3200, 'error');
    }, 5000);
}

function effectsAreLocalSoloSupported(effects) {
    if (!Array.isArray(effects)) return true;
    for (const effect of effects) {
        if (!effect || typeof effect !== 'object') continue;
        const effectType = effect.type || '';
        if (effectType && !LOCAL_SOLO_SUPPORTED_EFFECTS.has(effectType)) return false;
        const params = effect.params || {};
        for (const key of ['then', 'else', 'body', 'effects']) {
            if (Array.isArray(params[key]) && !effectsAreLocalSoloSupported(params[key])) return false;
        }
    }
    return true;
}

function v2StepsAreLocalSoloSupported(value) {
    if (Array.isArray(value)) return value.every(v2StepsAreLocalSoloSupported);
    if (!value || typeof value !== 'object') return true;
    const op = value.op || value.type || '';
    if (op && !LOCAL_SOLO_SUPPORTED_V2_OPS.has(op)) return false;
    return Object.values(value).every(v2StepsAreLocalSoloSupported);
}

function v2EventsAreLocalSoloSupported(cardDef) {
    const events = (cardDef.v2_events && typeof cardDef.v2_events === 'object')
        ? cardDef.v2_events
        : ((cardDef.v2_resource && cardDef.v2_resource.events && typeof cardDef.v2_resource.events === 'object')
            ? cardDef.v2_resource.events
            : {});
    return Object.values(events).every(eventDef => {
        const steps = Array.isArray(eventDef) ? eventDef : (eventDef && (eventDef.steps || eventDef.effects));
        return v2StepsAreLocalSoloSupported(steps || []);
    });
}

function cardIsLocalSoloSupported(cardDef) {
    if (!cardDef) return false;
    if (!effectsAreLocalSoloSupported(cardDef.effects || [])) return false;
    if (!v2EventsAreLocalSoloSupported(cardDef)) return false;
    const scripts = cardDef.scripts || {};
    for (const script of Object.values(scripts)) {
        const effects = Array.isArray(script) ? script : (script && script.effects);
        if (!effectsAreLocalSoloSupported(effects || [])) return false;
    }
    return true;
}

function soloPayloadIsLocalSupported(payload) {
    if (!window.Worker || !payload) return false;
    const deck = [...(payload.deck0 || []), ...(payload.deck1 || [])];
    return deck.every(entry => {
        const defId = typeof entry === 'string' ? entry : entry && entry.def_id;
        return cardIsLocalSoloSupported(getCardDef(defId));
    });
}

function stopLocalSoloRuntime() {
    if (localSoloRuntime.worker) {
        try { localSoloRuntime.worker.terminate(); } catch (_) {}
    }
    localSoloRuntime.enabled = false;
    localSoloRuntime.worker = null;
    localSoloRuntime.fallbackPayload = null;
    localSoloRuntime.fallbackKind = '';
}

function handleLocalGamePhase(data) {
    phase = data.phase || phase;
    if (data.solo) soloMode = true;
    if (data.tutorial) tutorialMode = true;
    if (phase === 'playing' || phase === 'action' || phase === 'draw' || phase === 'response' || phase === 'choice') {
        showView('view-game');
        updateStatus(UI.game_loading || 'Loading...');
    } else if (phase === 'game_over') {
        updateStatus(UI.game_over);
    }
    syncBattleLogMatch(data || {});
    syncPhaseChatMatch(data || {});
}

function handleLocalSoloState(data) {
    applyClientSoloSkins(data);
    const previousGameState = gameState;
    soloMode = true;
    tutorialMode = !!data.tutorial || tutorialMode;
    isSpectating = false;
    spectateCardDataKey = '';
    syncBattleLogMatch(data || {});
    gameState = data;
    phase = data.phase || phase;
    playerId = data.your_id;
    if (data.pending_response == null && !responsePending) {
        pendingPlayCard = null;
    }
    if (data.pending_response === null && responsePending) {
        responsePending = false;
        responseData = null;
        removeFloatingCardPreview();
        const rp = $('response-panel');
        if (rp) { rp.innerHTML = ''; rp.classList.add('hidden'); }
        if (responseTimerId) { clearInterval(responseTimerId); responseTimerId = null; }
    }
    if (data.pending_choice == null && choicePending) {
        invalidateChoiceRequest();
    }
    const keepOptimisticForState = !!optimisticResourceOverride;
    clearPendingServerAction({ keepOptimistic: keepOptimisticForState });
    if (phase === 'game_over') {
        if (data.tutorial || tutorialMode) {
            renderGameOverAfterFinalAnimation(previousGameState, data, { fullScreen: true, tutorial: true });
        } else {
            renderGameOverAfterFinalAnimation(previousGameState, data, { fullScreen: false, deferResultLabels: true });
        }
        optimisticResourceOverride = null;
    } else {
        clearScheduledGameOver();
        if (!areSequentialGameStates(previousGameState, data)) {
            pendingLocalResourceCosts = [];
            pendingOptimisticResourceCosts = [];
        }
        queueVisibleHandExileAnimations(previousGameState, data);
        renderGame(data);
        showStateDeltas(previousGameState, data);
        optimisticResourceOverride = null;
    }
    if (tutorialMode) {
        scheduleTutorialOverlayStart();
        updateTutorialOverlay();
        scheduleTutorialBotAction();
        setTimeout(updateTutorialOverlay, 80);
    }
}

function handleLocalSoloMessage(event) {
    const message = event.data || {};
    const data = message.data || {};
    if (message.type === 'game_phase') {
        handleLocalGamePhase(data);
    } else if (message.type === 'solo_state') {
        handleLocalSoloState(data);
    } else if (message.type === 'response_request') {
        clearPendingServerAction({ keepOptimistic: true });
        responsePending = true;
        responseData = data;
        showResponseUI(data);
    } else if (message.type === 'choice_request') {
        clearPendingServerAction({ keepOptimistic: true });
        pendingPlayCard = null;
        beginChoiceRequest(data);
    } else if (message.type === 'server_error') {
        const errorCode = data && (data.code || data.error_code || data.reason);
        const errorMessage = data && (data.message || '');
        if (errorCode === 'NO_PENDING_CHOICE' || errorMessage === UI.error_no_pending_choice || errorMessage === 'жІЎжңүеҫ…йҖүжӢ©ж“ҚдҪң') {
            debugLog('[client] ignored stale local no-pending-choice server_error');
            clearPendingServerAction();
            return;
        }
        clearPendingServerAction();
        flashStatus(translateServerError(data.message), 3000, 'error');
        if (gameState && gameState.phase) renderGame(gameState);
    } else if (message.type === 'solo_paused') {
        const wasTutorial = tutorialMode;
        stopLocalSoloRuntime();
        soloMode = false;
        tutorialMode = false;
        if (wasTutorial) finishTutorialReturn();
        else showSoloTraining();
    } else if (message.type === 'fallback_required') {
        const payload = localSoloRuntime.fallbackPayload;
        const kind = localSoloRuntime.fallbackKind;
        stopLocalSoloRuntime();
        if (kind === 'tutorial') {
            pendingTutorialStart = true;
        } else {
            pendingSoloStart = true;
            window.__pendingSoloPayload = payload;
        }
        connectSocket(getServerAddress());
    }
}

function startLocalSoloRuntime(kind, payload) {
    stopLocalSoloRuntime();
    return false;
}

function emitSoloEvent(eventName, payload = {}) {
    if (socket && socket.connected) {
        socket.emit(eventName, payload);
        return;
    }
    clientRejectAction(UI.server_not_connected || UI.server_no_response || UI.operation_failed);
}

function emitModeEvent(soloEventName, onlineEventName, payload = {}) {
    if (soloMode) emitSoloEvent(soloEventName, payload);
    else if (socket) socket.emit(onlineEventName, payload);
}

function handleSoloHistoryShortcut(event) {
    if (!event || !event.ctrlKey || event.altKey || event.metaKey) return false;
    if (!soloMode || replayMode || isSpectating || tutorialMode) return false;
    if (!gameState || !gameState.solo || gameState.phase === 'game_over') return false;
    if (isTypingKeyboardTarget(event.target)) return false;
    const key = String(event.key || '').toLowerCase();
    if (key !== 'z' && key !== 'y') return false;
    event.preventDefault();
    event.stopPropagation();
    if (key === 'z' && !event.shiftKey) {
        emitSoloEvent('solo_undo', {});
    } else {
        emitSoloEvent('solo_redo', {});
    }
    return true;
}

async function showSoloTraining() {
    try {
        await ensureCardDataForCurrentMods();
    } catch (err) {
        console.warn('[mods] failed to refresh card data before solo:', err);
    }
    stopLocalSoloRuntime();
    clearActiveMatchRoute('open_solo_training');
    soloMode = false;
    phase = 'solo_edit';
    clearActionToast();
    showView('view-solo');
    updateStatus(UI.solo_training);
    try {
        loadSoloDecks(false);
    } catch (err) {
        console.error('[solo] failed to load saved decks', err);
        localStorage.removeItem('gtn_solo_decks');
        soloDeckA = [];
        soloDeckB = [];
        soloEventA = '';
        soloEventB = '';
    }
    try {
        renderSoloEventSelects();
        renderSoloBuilder();
    } catch (err) {
        console.error('[solo] failed to render builder', err);
        flashStatus(UI.operation_failed || 'ж“ҚдҪңеӨұиҙҘ', 2400, 'error');
    }
}

function loadSoloDecks(showNotice = true) {
    let saved = null;
    try {
        saved = JSON.parse(localStorage.getItem('gtn_solo_decks') || 'null');
    } catch (err) {
        localStorage.removeItem('gtn_solo_decks');
        saved = null;
    }
    if (saved && Array.isArray(saved.deck0) && Array.isArray(saved.deck1)) {
        const normalizeDeck = (deck) => deck
            .map(entry => typeof entry === 'string'
                ? { def_id: entry, instance_flags: [], disabled_flags: [] }
                : { def_id: entry.def_id, instance_flags: [...(entry.instance_flags || [])], disabled_flags: [...(entry.disabled_flags || [])] })
            .filter(entry => entry)
            .slice(0, 15);
        soloDeckA = normalizeDeck(saved.deck0);
        soloDeckB = normalizeDeck(saved.deck1);
        soloEventA = saved.event0 != null ? String(saved.event0) : '';
        soloEventB = saved.event1 != null ? String(saved.event1) : '';
        if (showNotice) flashStatus(UI.load_last, 1200);
    }
}

function saveSoloDecks() {
    localStorage.setItem('gtn_solo_decks', JSON.stringify({ deck0: soloDeckA, deck1: soloDeckB, event0: soloEventA, event1: soloEventB }));
    flashStatus(UI.solo_saved, 1600);
}

function startTutorial(returnTarget = 'home') {
    stopLocalSoloRuntime();
    tutorialReturnTarget = returnTarget;
    if (returnTarget === 'home') localStorage.setItem('gtn_seen_intro', '1');
    tutorialLastLogTotal = 0;
    tutorialDeckViewed = false;
    tutorialCounterSeen = false;
    tutorialIntroActive = false;
    tutorialIntroShown = false;
    tutorialTargetHintSeen = false;
    tutorialTriggerHintSeen = false;
    if (tutorialOverlayStartTimer) { clearTimeout(tutorialOverlayStartTimer); tutorialOverlayStartTimer = null; }
    if (tutorialIntroTimer) { clearTimeout(tutorialIntroTimer); tutorialIntroTimer = null; }
    tutorialEndHintCount = 0;
    tutorialEndHintKey = '';
    pendingTutorialStart = false;
    closeAbout();
    hideModal();
    hideGameAlert();
    tutorialMode = true;
    hideTutorialOverlay();
    const nickInput = $('input-nickname');
    const stored = localStorage.getItem('gtn_nickname') || '';
    nickname = (nickInput && nickInput.value.trim()) || stored || `ж–°жүӢ${Math.floor(1000 + Math.random() * 9000)}`;
    if (nickInput && !nickInput.value.trim()) nickInput.value = nickname;
    localStorage.setItem('gtn_nickname', nickname);
    updateStatus(UI.tutorial_start);
    if (!socket || !socket.connected) {
        pendingTutorialStart = true;
        connectSocket(getServerAddress());
        return;
    }
    emitTutorialStart();
}

function emitTutorialStart() {
    tutorialMode = true;
    emitSoloEvent('tutorial_start', {});
}

function showTutorialOverlay() {
    let overlay = $('tutorial-overlay');
    if (!overlay) {
        overlay = document.createElement('div');
        overlay.id = 'tutorial-overlay';
        overlay.className = 'tutorial-overlay';
        overlay.innerHTML = `
            <div class="tutorial-click-shield hidden" aria-hidden="true"></div>
            <button id="btn-tutorial-skip" class="btn btn-secondary tutorial-skip" type="button"></button>
            <div class="tutorial-card">
                <div class="tutorial-kicker"></div>
                <div class="tutorial-text"></div>
            </div>
            <div class="tutorial-arrow" aria-hidden="true"></div>
        `;
        document.body.appendChild(overlay);
    }
    overlay.classList.remove('hidden');
    const skip = $('btn-tutorial-skip');
    if (skip) {
        skip.textContent = UI.tutorial_skip;
        skip.onclick = skipTutorial;
    }
    updateTutorialOverlay();
}

function scheduleTutorialOverlayStart() {
    if (!tutorialMode || tutorialIntroShown || tutorialOverlayStartTimer) return;
    if (!gameState || !gameState.tutorial) return;
    tutorialOverlayStartTimer = setTimeout(() => {
        tutorialOverlayStartTimer = null;
        if (!tutorialMode || !gameState || !gameState.tutorial) return;
        tutorialIntroActive = true;
        showTutorialOverlay();
        if (tutorialIntroTimer) clearTimeout(tutorialIntroTimer);
        tutorialIntroTimer = setTimeout(() => {
            tutorialIntroTimer = null;
            tutorialIntroActive = false;
            tutorialIntroShown = true;
            updateTutorialOverlay();
        }, 1500);
    }, 500);
}

function hideTutorialOverlay() {
    const overlay = $('tutorial-overlay');
    if (overlay) overlay.classList.add('hidden');
    tutorialStrictFocus = false;
    tutorialEndHintCount = 0;
    tutorialEndHintKey = '';
}

function onTutorialGuardClick(e) {
    if (!tutorialMode || !tutorialStrictFocus) return;
    const target = e.target;
    if (!(target instanceof Element)) return;
    if (target.closest('.tutorial-highlight, #btn-tutorial-skip, .target-pickable, [data-player-target-region].target-pickable')) return;
    e.preventDefault();
    e.stopPropagation();
}

document.addEventListener('click', onTutorialGuardClick, true);

function updateTutorialOverlay() {
    if (!tutorialMode) return;
    const overlay = $('tutorial-overlay');
    if (!overlay) return;
    document.querySelectorAll('.tutorial-highlight').forEach(el => el.classList.remove('tutorial-highlight'));
    document.querySelectorAll('.tutorial-card-target').forEach(el => el.classList.remove('tutorial-card-target'));
    const kicker = overlay.querySelector('.tutorial-kicker');
    const text = overlay.querySelector('.tutorial-text');
    const arrow = overlay.querySelector('.tutorial-arrow');
    const shield = overlay.querySelector('.tutorial-click-shield');
    if (tutorialIntroActive) {
        if (shield) shield.classList.add('hidden');
        if (kicker) kicker.textContent = UI.tutorial_start;
        if (text) text.textContent = UI.tutorial_intro || 'зҺ°еңЁпјҢи®©жҲ‘д»¬ејҖе§Ӣж–°жүӢж•ҷзЁӢеҗ§пјҒ';
        if (arrow) positionTutorialArrow(arrow, '');
        return;
    }
    const myTurn = gameState && gameState.current_player === 0 && gameState.phase === 'action';
    const enemyTurn = gameState && gameState.current_player === 1 && gameState.phase === 'action';
    const playedThisTurn = Object.values((gameState && gameState.you && gameState.you.cards_played_this_turn) || {})
        .reduce((sum, n) => sum + Number(n || 0), 0);
    const hand = (gameState && gameState.you && gameState.you.hand) || [];
    const hasPlayableType = (type) => hand.some(c => {
        const cd = getCardDef(c.def_id);
        return cd && cd.card_type === type && canPlayCard(c);
    });
    const hasFissionTarget = hand.some(c => {
        const cd = getCardDef(c.def_id);
        return cd && cd.card_type === 'thorn';
    });
    const attackCounts = {};
    hand.forEach(c => {
        const cd = getCardDef(c.def_id);
        if (cd && cd.card_type === 'thorn') attackCounts[c.def_id] = (attackCounts[c.def_id] || 0) + 1;
    });
    const hasFusionTargets = Object.values(attackCounts).some(n => n >= 2);
    const hasFission = hasFissionTarget && hand.some(c => c.def_id === 'Fission' && canPlayCard(c));
    const hasFusion = hasFusionTargets && hand.some(c => c.def_id === 'Fusion' && canPlayCard(c));
    const hasCounter = hand.some(c => {
        const cd = getCardDef(c.def_id);
        return cd && cd.card_type === 'guard';
    });
    const hasFissionedAttack = hand.some(c => {
        const cd = getCardDef(c.def_id);
        return cd && cd.card_type === 'thorn' && Number(c.fission_level || 1) > 1 && canPlayCard(c);
    });
    const hasFusionedAttack = hand.some(c => {
        const cd = getCardDef(c.def_id);
        return cd && cd.card_type === 'thorn' && Number(c.fusion_level || 1) > 1 && canPlayCard(c);
    });
    const hasEnhancedAttack = hasFissionedAttack || hasFusionedAttack;
    const hasTargetCard = hand.some(c => {
        const cd = getCardDef(c.def_id);
        return cd && cd.card_type !== 'thorn' && canPlayCard(c) && cardNeedsPlayerTarget(cd, c);
    });
    const triggerButton = document.querySelector('.btn-equip-trigger:not(:disabled)');
    const shouldShowDeckHint = !!(gameState && myTurn && !tutorialDeckViewed);
    const shouldShowCounterHint = !!responsePending;
    const shouldShowTriggerHint = !!(myTurn && !tutorialTriggerHintSeen && triggerButton && !shouldShowCounterHint && !shouldShowDeckHint);
    const shouldShowTargetHint = !!(myTurn && !tutorialTargetHintSeen && hasTargetCard && playedThisTurn === 0 && !shouldShowCounterHint && !shouldShowDeckHint && !shouldShowTriggerHint);
    const endHintCandidate = !!(!enemyTurn && myTurn && playedThisTurn > 0 && !hasEnhancedAttack);
    if (endHintCandidate) {
        const key = `${gameState.round_num || 0}:${gameState.current_player || 0}`;
        if (tutorialEndHintKey !== key) {
            tutorialEndHintKey = key;
            tutorialEndHintCount += 1;
        }
    }
    const shouldShowEndHint = endHintCandidate && tutorialEndHintCount <= 2;
    const shouldFocusEndHint = shouldShowEndHint && tutorialEndHintCount <= 1;
    const strictFocus = shouldShowCounterHint || shouldShowDeckHint || shouldShowTriggerHint || shouldFocusEndHint;
    tutorialStrictFocus = strictFocus;
    if (shield) shield.classList.toggle('hidden', !strictFocus);
    if (shouldShowCounterHint) tutorialCounterSeen = true;
    if (shouldShowTriggerHint) tutorialTriggerHintSeen = true;
    if (kicker) kicker.textContent = UI.tutorial_start;
    if (text) {
        text.textContent = shouldShowCounterHint
            ? UI.tutorial_hint_counter
            : enemyTurn
            ? UI.tutorial_hint_enemy
            : shouldShowDeckHint
                ? (UI.tutorial_hint_ui || UI.tutorial_hint_deck)
                : shouldShowTriggerHint
                    ? UI.tutorial_hint_trigger
                : shouldShowTargetHint
                    ? UI.tutorial_hint_target
                : (myTurn && hasFissionedAttack)
                    ? UI.tutorial_hint_play_fissioned
                    : (myTurn && hasFusionedAttack)
                    ? UI.tutorial_hint_play_fusioned
                : shouldShowEndHint
                    ? UI.tutorial_hint_end
                    : (myTurn && (gameState.round_num || 0) <= 1)
                    ? UI.tutorial_hint_play
                    : (myTurn && hasFission)
                    ? UI.tutorial_hint_fission
                    : (myTurn && hasFusion)
                        ? UI.tutorial_hint_fusion
                        : (myTurn && hasPlayableType('root'))
                            ? UI.tutorial_hint_root
                            : (myTurn && hasPlayableType('bloom'))
                                ? UI.tutorial_hint_bloom
                    : (tutorialDeckViewed && !tutorialCounterSeen && hasCounter)
                        ? UI.tutorial_hint_continue
                        : UI.tutorial_hint_free;
    }
    if (arrow) {
        let arrowMode = '';
        if (!enemyTurn && !shouldShowCounterHint && !shouldShowDeckHint && shouldShowTargetHint) {
            arrowMode = 'target';
        } else if (!enemyTurn && !shouldShowCounterHint && !shouldShowDeckHint && !shouldShowTriggerHint && myTurn && hasFissionedAttack) {
            arrowMode = 'fissioned';
        } else if (!enemyTurn && !shouldShowCounterHint && !shouldShowDeckHint && !shouldShowTriggerHint && myTurn && hasFusionedAttack) {
            arrowMode = 'fusioned';
        } else if (!enemyTurn && !shouldShowCounterHint && !shouldShowDeckHint && !shouldShowTriggerHint && myTurn && playedThisTurn === 0) {
            if ((gameState.round_num || 0) <= 1) arrowMode = 'play';
            else if (hasFission) arrowMode = 'fission';
            else if (hasFusion) arrowMode = 'fusion';
            else if (hasPlayableType('root')) arrowMode = 'root';
            else if (hasPlayableType('bloom')) arrowMode = 'bloom';
            else arrowMode = 'play';
        }
        positionTutorialArrow(arrow, arrowMode);
    }
    if (shouldShowCounterHint) {
        const panel = $('response-panel');
        if (panel) panel.classList.add('tutorial-highlight');
    } else if (!enemyTurn && shouldShowDeckHint) {
        const btn = $('btn-view-deck');
        if (btn) btn.classList.add('tutorial-highlight');
    } else if (!enemyTurn && shouldShowTriggerHint && triggerButton) {
        triggerButton.classList.add('tutorial-highlight');
    } else if (shouldFocusEndHint) {
        const btn = $('btn-end-turn');
        if (btn) btn.classList.add('tutorial-highlight');
    }
}

function scheduleTutorialOverlayRefresh(delay = 320) {
    if (!tutorialMode) return;
    if (tutorialOverlayRefreshTimer) clearTimeout(tutorialOverlayRefreshTimer);
    tutorialOverlayRefreshTimer = setTimeout(() => {
        tutorialOverlayRefreshTimer = null;
        updateTutorialOverlay();
    }, delay);
}

function positionTutorialArrow(arrow, mode) {
    if (arrow) arrow.classList.remove('active');
    if (arrow) {
        arrow.style.removeProperty('--tutorial-arrow-x');
        arrow.style.removeProperty('--tutorial-arrow-top');
        arrow.style.removeProperty('--tutorial-arrow-h');
    }
    if (!mode) {
        return;
    }
    if (mode) {
        const cards = [...document.querySelectorAll('#you-hand .card.card-draggable:not(.card-disabled)')];
        const playable = cards.find(el => {
            const id = Number(el.dataset.instanceId);
            const hand = (gameState && gameState.you && gameState.you.hand) || [];
            const card = hand.find(c => c.instance_id === id);
            const cd = card ? getCardDef(card.def_id) : null;
            if (!card || !cd) return false;
            if (mode === 'fission') return card.def_id === 'Fission';
            if (mode === 'fissioned') return cd.card_type === 'thorn' && Number(card.fission_level || 1) > 1;
            if (mode === 'fusion') return card.def_id === 'Fusion';
            if (mode === 'fusioned') return cd.card_type === 'thorn' && Number(card.fusion_level || 1) > 1;
            if (mode === 'target') return cd.card_type !== 'thorn' && cardNeedsPlayerTarget(cd, card);
            if (mode === 'root') return cd.card_type === 'root';
            if (mode === 'bloom') return cd.card_type === 'bloom';
            return cd.card_type === 'thorn';
        }) || cards[0] || document.querySelector('#you-hand .card:not(.card-disabled)');
        if (playable) {
            playable.classList.add('tutorial-card-target');
            const rect = playable.getBoundingClientRect();
            const arrowHeight = Math.min(74, Math.max(52, rect.height * 0.86));
            const overlap = Math.min(10, rect.height * 0.16);
            const top = Math.max(8, rect.top - arrowHeight + overlap);
            arrow.style.setProperty('--tutorial-arrow-x', `${rect.left + rect.width / 2}px`);
            arrow.style.setProperty('--tutorial-arrow-top', `${top}px`);
            arrow.style.setProperty('--tutorial-arrow-h', `${arrowHeight}px`);
            arrow.classList.add('active');
        }
        return;
    }
}

function stopTutorialUiForGameOver() {
    if (tutorialBotTimer) {
        clearTimeout(tutorialBotTimer);
        tutorialBotTimer = null;
    }
    if (tutorialOverlayStartTimer) {
        clearTimeout(tutorialOverlayStartTimer);
        tutorialOverlayStartTimer = null;
    }
    if (tutorialIntroTimer) {
        clearTimeout(tutorialIntroTimer);
        tutorialIntroTimer = null;
    }
    if (tutorialOverlayRefreshTimer) {
        clearTimeout(tutorialOverlayRefreshTimer);
        tutorialOverlayRefreshTimer = null;
    }
    tutorialMode = false;
    pendingTutorialStart = false;
    tutorialDeckViewed = false;
    tutorialCounterSeen = false;
    tutorialIntroActive = false;
    tutorialIntroShown = false;
    tutorialTargetHintSeen = false;
    tutorialTriggerHintSeen = false;
    tutorialStrictFocus = false;
    tutorialEndHintCount = 0;
    tutorialEndHintKey = '';
    hideTutorialOverlay();
    document.querySelectorAll('.tutorial-highlight').forEach(el => el.classList.remove('tutorial-highlight'));
    document.querySelectorAll('.tutorial-card-target').forEach(el => el.classList.remove('tutorial-card-target'));
    clearSelectedPlayCard();
    pendingPlayCard = null;
}

function skipTutorial() {
    if (tutorialBotTimer) {
        clearTimeout(tutorialBotTimer);
        tutorialBotTimer = null;
    }
    if ((socket && socket.connected && tutorialMode) || isLocalSoloRuntimeActive()) {
        emitSoloEvent('solo_pause', {});
    } else {
        finishTutorialReturn();
    }
}

function finishTutorialReturn() {
    tutorialMode = false;
    pendingTutorialStart = false;
    tutorialDeckViewed = false;
    tutorialCounterSeen = false;
    tutorialIntroActive = false;
    tutorialIntroShown = false;
    tutorialTargetHintSeen = false;
    tutorialTriggerHintSeen = false;
    tutorialStrictFocus = false;
    if (tutorialOverlayStartTimer) { clearTimeout(tutorialOverlayStartTimer); tutorialOverlayStartTimer = null; }
    if (tutorialIntroTimer) { clearTimeout(tutorialIntroTimer); tutorialIntroTimer = null; }
    if (tutorialOverlayRefreshTimer) { clearTimeout(tutorialOverlayRefreshTimer); tutorialOverlayRefreshTimer = null; }
    soloMode = false;
    hideTutorialOverlay();
    document.querySelectorAll('.tutorial-highlight').forEach(el => el.classList.remove('tutorial-highlight'));
    document.querySelectorAll('.tutorial-card-target').forEach(el => el.classList.remove('tutorial-card-target'));
    clearSelectedPlayCard();
    pendingPlayCard = null;
    if (tutorialReturnTarget === 'about') {
        showView('view-login');
        openAbout();
    } else {
        showView('view-login');
    }
}

function scheduleTutorialBotAction() {
    if (!tutorialMode || (!socket && !isLocalSoloRuntimeActive()) || !gameState || gameState.phase === 'game_over') return;
    if (tutorialBotTimer) clearTimeout(tutorialBotTimer);
    if (gameState.current_player !== 1 || gameState.pending_response || choicePending || responsePending) return;
    tutorialBotTimer = setTimeout(() => {
        if (!tutorialMode || (!socket && !isLocalSoloRuntimeActive()) || !gameState || gameState.current_player !== 1) return;
        emitSoloEvent('tutorial_bot_action', {});
    }, 2100);
}

function getSearchLocalizedText(source, i18nKey, fallbackKey) {
    if (!source) return '';
    const dict = source[i18nKey] || {};
    const parts = [
        dict[currentLang],
        dict.en,
        fallbackKey ? source[fallbackKey] : '',
    ];
    return [...new Set(parts.filter(Boolean))].join(' ');
}

