    if (p.triangle_stacks > 0) tags.push({ key: 'triangle', name: UI.status_triangle, abbr: 'в–і', val: p.triangle_stacks, fg: COLORS.non_stack, bg: COLORS.non_stack_bg });
    if (p.dodge > 0) tags.push({ key: 'dodge', name: UI.status_dodge || 'й—ӘйҒҝ', abbr: 'Ddg', val: p.dodge, fg: COLORS.guard, bg: COLORS.guard_bg });
    let nazarStacks = customCount('nazar', 'йӮӘзңј', 'Nazar');
    if (p.nazar_active) nazarStacks += Math.max(0, 2 - Math.max(0, Number(p.nazar_big_hits || 0)));
