function battleCardActionTemplate(entry) {
    const table = LOG_TEXT[currentLang] || LOG_TEXT.en;
    const subtype = String(entry && entry.subtype || '');
    if (subtype === 'use_detail') return table.use_detail || '{p} uses {card}, {detail}';
    if (subtype === 'use_equip_target') return table.equip_target || '{p} equips {card} to {target}';
    if (subtype === 'use_equip_self') return table.equip_self || '{p} equips {card}';
    if (subtype === 'equip') return table.equip || '{p} equips {card}';
    if (subtype === 'trigger') return table.trigger_card || "{p}'s {card} triggers: {detail}";
    if (subtype === 'destroy_equipment') return table.destroy_equipment || "{p} destroys {target}'s {card}";
    if (subtype === 'gain_equipment') return table.gain_equipment || '{p} gains equipment {card}';
    if (subtype === 'equipment_removed') return table.equipment_removed || "{p}'s {card} {detail}";
    if (subtype === 'equipment_destroyed') return table.equipment_destroyed || '{card} is destroyed';
    if (subtype === 'card_rejected') return table.card_rejected || '{target} refuses to let {p} use {card}';
    return table.use_detail || '{p} uses {card}, {detail}';
}

function localizedBattleCardActionDetail(entry) {
    const detail = String(entry && entry.detail || '').trim();
    if (!detail || currentLang === 'zh') return detail;
    const fixed = {
        'еӣ жӯ»дәЎиў«ж‘§жҜҒ': {
            en: 'is destroyed on death',
            fr: 'est dГ©truit Г  la mort',
            ja: 'гҒҜжӯ»дәЎгҒ«гӮҲгӮҠз ҙеЈҠгҒ•гӮҢгҒҹ',
        },
        'еӣ зӣ®ж Үжӯ»дәЎз§»еҮәиЈ…еӨҮеҢә': {
            en: 'leaves the equipment area because its target died',
            fr: "quitte la zone dвҖҷГ©quipement car sa cible est morte",
            ja: 'гҒҜеҜҫиұЎгҒ®жӯ»дәЎгҒ«гӮҲгӮҠиЈ…еӮҷж¬„гҒӢгӮүйҷӨеӨ–гҒ•гӮҢгҒҹ',
        },
    };
    if (fixed[detail] && fixed[detail][currentLang]) return fixed[detail][currentLang];
    let match;
    if ((match = detail.match(/^иЈ…еӨҮжҠӨз”ІжҠөж¶ҲдәҶж‘§жҜҒ[пјҲ(]еү©дҪҷ(\d+)[пјү)]$/))) {
        if (currentLang === 'fr') return `lвҖҷarmure dвҖҷГ©quipement empГӘche la destruction (${match[1]} restante)`;
        if (currentLang === 'ja') return `иЈ…еӮҷиЈ…з”ІгҒҢз ҙеЈҠгӮ’йҳІгҒ„гҒ пјҲж®ӢгӮҠ${match[1]}пјү`;
        return `Equipment Armor prevents destruction (${match[1]} left)`;
    }
    if ((match = detail.match(/^дҪҶ(.+?)жңӘеҸ—еҲ°з”өдјӨ$/))) {
        const player = localizePlayerNameInText(match[1]);
        if (currentLang === 'fr') return `mais ${player} ne subit aucun dГ©gГўt Г©lectrique`;
        if (currentLang === 'ja') return `гҒ—гҒӢгҒ—${player}гҒҜйӣ»ж’ғгғҖгғЎгғјгӮёгӮ’еҸ—гҒ‘гҒӘгҒӢгҒЈгҒҹ`;
        return `but ${player} takes no electric damage`;
    }
    if ((match = detail.match(/^(.+?)еҺ»йҷӨ(\d+)еұӮдёӯжҜ’[пјҢ,]\s*еҸ—еҲ°(\d+)зӮ№зү©зҗҶдјӨе®і$/))) {
        const player = localizePlayerNameInText(match[1]);
        if (currentLang === 'fr') return `${player} retire ${match[2]} Poison et subit ${match[3]} dГ©gГўts physiques`;
        if (currentLang === 'ja') return `${player}гҒ®жҜ’гҒҢ${match[2]}еұӨжёӣе°‘гҒ—гҖҒ${match[3]}зү©зҗҶгғҖгғЎгғјгӮёгӮ’еҸ—гҒ‘гӮӢ`;
        return `${player} removes ${match[2]} Poison and takes ${match[3]} physical damage`;
    }
    if (detail === 'зҠ¶жҖҒе…Қз–«еӨұж•Ҳ') {
        if (currentLang === 'fr') return 'ImmunitГ© aux Г©tats prend fin';
        if (currentLang === 'ja') return 'зҠ¶ж…Ӣе…Қз–«гҒҢзөӮдәҶ';
        return 'Status Immunity ends';
    }
    return translateLogLine(detail);
}

function appendLocalizedBattleCardActionDetail(parent, entry) {
    const detail = localizedBattleCardActionDetail(entry);
    if (!detail) return;
    appendBattleLogTextWithCardChips(parent, detail);
}

function renderBattleCardActionLogChipLine(el, entry) {
    const cardDict = (entry && entry.cardDict && typeof entry.cardDict === 'object') ? entry.cardDict : null;
    const defId = (cardDict && cardDict.def_id) || findCardDefIdByAnyName(entry && entry.card);
    if (!defId) {
        const fallback = translateLogLine(formatBattleCardActionLogForCompact(entry));
        el.innerHTML = colorizeBattleLogText(fallback);
        bindInlineCardChips(el, { interactive: true });
        return;
    }
    const template = battleCardActionTemplate(entry)
        .replaceAll('{p}', localizePlayerNameInText(entry.actor || ''))
        .replaceAll('{target}', localizePlayerNameInText(entry.target || ''));
    const tokens = template.split(/(\{card\}|\{detail\})/g);
    let renderedCard = false;
    let renderedDetail = false;
    tokens.forEach(token => {
        if (!token) return;
        if (token === '{card}') {
            const chip = createCardChoiceChip({ ...(cardDict || {}), def_id: defId }, { hideInstanceOnlyFlags: false });
            chip.classList.add('battle-log-card-chip');
            el.appendChild(chip);
            renderedCard = true;
            return;
        }
        if (token === '{detail}') {
            appendLocalizedBattleCardActionDetail(el, entry);
            renderedDetail = true;
            return;
        }
        appendColorizedLogText(el, token);
    });
    if (!renderedCard) appendBattleLogCardChip(el, entry.card, cardDict);
    if (entry.detail && !renderedDetail) {
        appendColorizedLogText(el, currentLang === 'ja' ? 'пјҡ' : (currentLang === 'zh' ? 'пјҢ' : ': '));
        appendLocalizedBattleCardActionDetail(el, entry);
    }
    const count = Math.max(1, Number(entry && entry.count || 1));
    if (count > 1) appendColorizedLogText(el, ` Г—${count}`);
}

function appendColorizedLogText(parent, text) {
    if (!parent || !text) return;
    const span = document.createElement('span');
    span.innerHTML = colorizeBattleLogText(stripBattleLogCardMarkers(text));
    parent.appendChild(span);
    bindInlineCardChips(span, { interactive: true });
}

function appendBattleLogCardChip(parent, cardText, cardDict = null) {
    if (!parent) return false;
    const rawCardText = stripBattleLogCardMarkers(cardText || '').trim();
    const lookupText = rawCardText
        .replace(/\s*[пјҲ(]\s*вҶ’[^пјү)]*[пјү)]\s*$/u, '')
        .trim();
    const suffix = lookupText && lookupText !== rawCardText ? rawCardText.slice(rawCardText.indexOf(lookupText) + lookupText.length) : '';
    const defId = (cardDict && cardDict.def_id) || findCardDefIdByAnyName(lookupText || rawCardText);
    if (!defId) return false;
    const chip = createCardChoiceChip({ ...(cardDict || {}), def_id: defId }, { hideInstanceOnlyFlags: false });
    chip.classList.add('battle-log-card-chip');
    parent.appendChild(chip);
    if (suffix) appendColorizedLogText(parent, suffix);
    return true;
}

function getBattleLogCardNameCandidates() {
    const candidates = [];
    const seen = new Set();
    const add = (name, defId) => {
        const text = String(name || '').trim();
        if (!text || !defId) return;
        // Single CJK card names are too ambiguous for whole-line fuzzy matching:
        // "йҮҚ" can appear inside "еӨҡйҮҚз“Ј", and "иҪ»" can appear in ordinary prose.
        // Explicit use/equip patterns and [[card:...]] markers still render them as chips.
        if (text.length < 2) return;
        const key = `${text}\u0000${defId}`;
        if (seen.has(key)) return;
        seen.add(key);
        candidates.push({ text, defId });
    };
    for (const [defId, cd] of Object.entries(CARD_DEFS || {})) {
        if (!cd) continue;
        add(getCardName(cd), defId);
        add(cd.name_cn, defId);
        add(cd.name_en, defId);
        add(cd.id, defId);
        add(cd.def_id, defId);
        add(defId, defId);
        Object.values(cd.name_i18n || {}).forEach(name => add(name, defId));
    }
    return candidates.sort((a, b) => b.text.length - a.text.length);
}

function isAsciiWordChar(ch) {
    return /[A-Za-z0-9_]/.test(ch || '');
}

function isBattleLogCardNameBoundary(text, index, length, name) {
    if (!/^[A-Za-z0-9_ -]+$/.test(name || '')) return true;
    const before = index > 0 ? text[index - 1] : '';
    const after = index + length < text.length ? text[index + length] : '';
    return !isAsciiWordChar(before) && !isAsciiWordChar(after);
}

function isBattleLogCardNameContextBlocked(text, index, length, candidate) {
    const raw = String(text || '');
    const before = raw.slice(Math.max(0, index - 12), index);
    const after = raw.slice(index + length, Math.min(raw.length, index + length + 8));
    const name = String(candidate && candidate.text || '');
    if (!name) return true;
    // Status/effect layer prose should stay as status text, not card chips.
    // Examples: "+1еұӮзң©жҷ•", "иҺ·еҫ—2еұӮз ҙжҚҹ", "ж–ҪеҠ 10еұӮдёӯжҜ’".
    if (/(?:[+\-пјҚ]?\d+|[дёҖдәҢдёүеӣӣдә”е…ӯдёғе…«д№қеҚҒзҷҫ]+)?\s*еұӮ\s*$/.test(before)) return true;
    if (/^(?:зҠ¶жҖҒ|ж•Ҳжһң|еұӮж•°|еұӮ)/.test(after)) return true;
    // Setup/event names are not card names even when they contain a card name.
    if (before.endsWith('гҖҗ') || /й…ҚиЈ…[:пјҡ]?$/.test(before)) return true;
    return false;
}

function isBattleLogCardNameContextAllowed(text, index, length, candidate) {
    const raw = String(text || '');
    const before = raw.slice(Math.max(0, index - 24), index);
    const after = raw.slice(index + length, Math.min(raw.length, index + length + 12));
    if (before.endsWith('[[card:')) return true;
    if (/(?:дҪҝз”ЁдәҶе№¶иЈ…еӨҮдәҶ|дҪҝз”Ёе№¶иЈ…еӨҮдәҶ|дҪҝз”ЁдәҶ|дҪҝз”Ё|иЈ…еӨҮдәҶ|иҺ·еҫ—иЈ…еӨҮ|и§ҰеҸ‘|ж”ҫйҖҗдәҶ)$/.test(before)) return true;
    if (/(?:ж‘§жҜҒдәҶ|ж‘§жҜҒ|иҺ·еҫ—дәҶ|иҺ·еҫ—|еҫ—еҲ°|жӢҝиө°дәҶ|еӣһеҲ°жүӢдёӯ|з§»е…ҘејғзүҢе Ҷ|иў«ж”ҫйҖҗ)$/.test(before)) return true;
    if (/зҡ„$/.test(before) && /^(?:еӣ |иў«|иЈ…еӨҮжҠӨз”І|еӣһиҪ¬|еӨҡдҪҷеүҜжң¬|е”ҜдёҖзүҢ|иҷҡж— |еүҜжң¬ж•Ҳжһң)/.test(after)) return true;
    if (/(?:ж‘§жҜҒдәҶ|ж‘§жҜҒ|иҺ·еҫ—дәҶ|иҺ·еҫ—|жӢҝиө°дәҶ).{0,12}зҡ„$/.test(before)) return true;
    return false;
}

function getBattleLogProtectedPlayerRanges(text) {
    const raw = String(text || '');
    const ranges = [];
    if (!raw) return ranges;
    const names = getBattleLogKnownPlayerNames();
    const addRange = (start, end) => {
        if (start >= 0 && end > start) ranges.push({ start, end });
    };
    for (const name of names) {
        if (!name) continue;
        let pos = raw.indexOf(name);
        while (pos >= 0) {
            addRange(pos, pos + name.length);
            pos = raw.indexOf(name, pos + Math.max(1, name.length));
        }
    }
    ranges.sort((a, b) => a.start - b.start || b.end - a.end);
    const merged = [];
    for (const range of ranges) {
        const last = merged[merged.length - 1];
        if (last && range.start <= last.end) {
            last.end = Math.max(last.end, range.end);
        } else {
            merged.push({ ...range });
        }
    }
    return merged;
}

function isInsideBattleLogProtectedRange(index, length, ranges) {
    const start = Number(index || 0);
    const end = start + Math.max(0, Number(length || 0));
    return (ranges || []).some(range => start < range.end && end > range.start);
}

function replaceBattleLogTextOutsidePlayerNames(text, from, to) {
    const raw = String(text || '');
    const needle = String(from || '');
    if (!needle || !raw.includes(needle) || needle === String(to || '')) return raw;
    const protectedRanges = getBattleLogProtectedPlayerRanges(raw);
    const indexes = [];
    let index = raw.indexOf(needle);
    while (index >= 0) {
        if (!isInsideBattleLogProtectedRange(index, needle.length, protectedRanges)) indexes.push(index);
        index = raw.indexOf(needle, index + Math.max(1, needle.length));
    }
    let result = raw;
    for (let i = indexes.length - 1; i >= 0; i -= 1) {
        const start = indexes[i];
        result = result.slice(0, start) + String(to || '') + result.slice(start + needle.length);
    }
    return result;
}

function appendBattleLogTextWithCardChips(parent, text) {
    if (!parent) return false;
    const raw = String(text || '');
    if (!raw) return false;
    const candidates = getBattleLogCardNameCandidates();
    const protectedRanges = getBattleLogProtectedPlayerRanges(raw);
    let cursor = 0;
    let usedChip = false;
    let guard = 0;
    while (cursor < raw.length && guard++ < 200) {
        const rest = raw.slice(cursor);
        const marker = parseInlineCardMarker(rest);
        if (marker) {
            appendBattleLogCardChip(parent, marker.defId, marker.cardDict || buildInlineCardDict(marker.defId, marker.modifierText));
            cursor += marker.raw.length;
            usedChip = true;
            continue;
        }
        const nextMarkerIndex = raw.toLowerCase().indexOf('[[card:', cursor);
        let best = null;
        for (const candidate of candidates) {
            const idx = raw.indexOf(candidate.text, cursor);
            if (idx < 0) continue;
            // Never let fuzzy card-name matching consume text inside an explicit
            // [[card:...|flag=...]] marker. Otherwise the card id is replaced
            // first and the marker modifiers leak into the battle log.
            if (nextMarkerIndex >= 0 && idx >= nextMarkerIndex) continue;
            if (isInsideBattleLogProtectedRange(idx, candidate.text.length, protectedRanges)) continue;
            if (!isBattleLogCardNameBoundary(raw, idx, candidate.text.length, candidate.text)) continue;
            if (isBattleLogCardNameContextBlocked(raw, idx, candidate.text.length, candidate)) continue;
            if (!isBattleLogCardNameContextAllowed(raw, idx, candidate.text.length, candidate)) continue;
            if (!best || idx < best.index || (idx === best.index && candidate.text.length > best.text.length)) {
                best = { ...candidate, index: idx };
            }
        }
        if (nextMarkerIndex >= 0 && (!best || nextMarkerIndex < best.index)) {
            if (nextMarkerIndex > cursor) {
                appendColorizedLogText(parent, raw.slice(cursor, nextMarkerIndex));
            }
            const markerAtIndex = parseInlineCardMarker(raw.slice(nextMarkerIndex));
            if (markerAtIndex) {
                appendBattleLogCardChip(parent, markerAtIndex.defId, markerAtIndex.cardDict || buildInlineCardDict(markerAtIndex.defId, markerAtIndex.modifierText));
                cursor = nextMarkerIndex + markerAtIndex.raw.length;
                usedChip = true;
                continue;
            }
        }
        if (!best) {
            appendColorizedLogText(parent, raw.slice(cursor));
            break;
        }
        if (best.index > cursor) {
            appendColorizedLogText(parent, raw.slice(cursor, best.index));
        }
        appendBattleLogCardChip(parent, best.text, { def_id: best.defId });
        usedChip = true;
        cursor = best.index + best.text.length;
    }
    return usedChip;
}

function renderBattleLogInlineCardLine(el, text) {
    if (!el) return false;
    const rawLine = String(text || '');
    const cardDict = decodeBattleLogCardMarker(rawLine);
    const line = stripBattleLogCardMarkers(rawLine);
    const patterns = [
        /^(.+?дҪҝз”ЁдәҶе№¶иЈ…еӨҮдәҶ)([^пјҢгҖӮпјҒ!]+)(.*)$/,
        /^(.+?дҪҝз”Ёе№¶иЈ…еӨҮдәҶ)([^пјҢгҖӮпјҒ!]+)(.*)$/,
        /^(.+?дҪҝз”ЁдәҶ?е№¶з»ҷ.+?иЈ…еӨҮдәҶ)([^пјҢгҖӮпјҒ!]+)(.*)$/,
        /^(.+?дҪҝз”ЁдәҶ?е№¶иЈ…еӨҮдәҶ)([^пјҢгҖӮпјҒ!]+)(.*)$/,
        /^(.+?иҺ·еҫ—иЈ…еӨҮ)([^пјҢгҖӮпјҒ!]+)(.*)$/,
        /^(.+?иЈ…еӨҮдәҶ)([^пјҢгҖӮпјҒ!]+)(.*)$/,
        /^(.+?ж‘§жҜҒдәҶ.+?зҡ„)([^пјҢгҖӮпјҒ!]+)(.*)$/,
        /^(.+?ж‘§жҜҒ.+?зҡ„)([^пјҢгҖӮпјҒ!]+)(.*)$/,
        /^(.+?зҡ„)([^пјҢгҖӮпјҒ!]+)(еӣ еӣһиҪ¬еӣһеҲ°жүӢдёӯ.*)$/,
        /^(.+?зҡ„)([^пјҢгҖӮпјҒ!]+)(еӣ иҷҡж— иў«ж”ҫйҖҗ.*)$/,
        /^(.+?зҡ„)([^пјҢгҖӮпјҒ!]+)(еӣ йҳҹдјҚзӢ¬дёҖиў«ж”ҫйҖҗ.*)$/,
        /^(.+?дҪҝз”ЁдәҶ?)([^пјҢгҖӮпјҒ!]+)(.*)$/,
    ];
    for (const pattern of patterns) {
        const match = line.match(pattern);
        if (!match) continue;
        const cardText = String(match[2] || '').trim();
        if (!((cardDict && cardDict.def_id) || findCardDefIdByAnyName(cardText))) continue;
        appendColorizedLogText(el, match[1]);
        appendBattleLogCardChip(el, cardText, cardDict);
        appendColorizedLogText(el, match[3] || '');
        return true;
    }
    return false;
}

function createBattleLogElement(entry) {
    if (typeof entry === 'string') {
        entry = { type: 'battle', text: entry };
    } else if (!entry || typeof entry !== 'object') {
        entry = { type: 'battle', text: String(entry || '') };
    }
    const el = document.createElement('div');
    if (entry.type === 'chat') {
        el.className = 'log-entry log-chat';
        const channelLabel = getChatChannelLogLabel(entry);
        if (channelLabel) {
            const channelSpan = document.createElement('span');
            channelSpan.className = `chat-channel chat-channel-${entry.channel || 'public'}`;
            channelSpan.textContent = `[${channelLabel}] `;
            el.appendChild(channelSpan);
        }
    const nameSpan = document.createElement('span');
    nameSpan.className = 'chat-nick';
    if (entry.system) nameSpan.classList.add('system-name');
    if (entry.isAdmin) nameSpan.classList.add('admin-name');
        if (entry.specialRoleColor === 'bloom') nameSpan.classList.add('bloom-name');
        if (entry.specialRoleColor === 'guard') nameSpan.classList.add('guard-name');
        nameSpan.textContent = entry.system ? `${entry.nick} ` : `${entry.nick}: `;
        el.appendChild(nameSpan);
        el.appendChild(document.createTextNode(entry.text));
        const repeatCount = Number(entry.repeatCount || entry.repeat_count || 1);
        if (repeatCount > 1) {
            const repeatSpan = document.createElement('span');
            repeatSpan.className = 'chat-repeat-count';
            repeatSpan.textContent = ` Г—${repeatCount}`;
            el.appendChild(repeatSpan);
        }
        if (isReportableChatEntry(entry)) {
            el.appendChild(createReportButton(chatEntryReportMeta(entry), {
                className: 'report-inline-btn chat-report-btn',
                text: UI.report,
                title: UI.report_chat,
            }));
        }
        return el;
    }
    if (!entry.kind) {
        const cardAction = parseBattleCardActionLogForCompact(entry.text || '');
        if (cardAction) entry = { ...entry, kind: 'card_action', ...cardAction };
    }
    const line = stripBattleLogCardMarkers(entry.text || '');
    const displayLine = translateLogLine(line);
    const styleLine = String(displayLine || line).toLowerCase();
    el.className = 'log-entry';
    if (styleLine.includes('damage') || styleLine.includes('degats') || styleLine.includes('dano') || styleLine.includes('\u9020\u6210') || styleLine.includes('\u4f24\u5bb3') || line.includes('D')) el.classList.add('log-damage');
    else if (styleLine.includes('+h') || styleLine.includes('recover') || styleLine.includes('recupera') || styleLine.includes('\u56de\u590d') || styleLine.includes('\u56de\u5fa9')) el.classList.add('log-heal');
    else if (styleLine.includes('poison') || styleLine.includes('veneno') || styleLine.includes('\u4e2d\u6bd2') || styleLine.includes('\u6bd2')) el.classList.add('log-poison');
    else if (styleLine.includes('burn') || styleLine.includes('queima') || styleLine.includes('\u707c\u70e7') || styleLine.includes('\u706b\u50b7')) el.classList.add('log-fire');
    else if (styleLine.includes('+e') || styleLine.includes('energy') || styleLine.includes('energia') || styleLine.includes('\u80fd\u91cf')) el.classList.add('log-elixir');
    else if (styleLine.includes('+m') || styleLine.includes('magic') || styleLine.includes('magie') || styleLine.includes('mana') || styleLine.includes('\u9b54\u529b')) el.classList.add('log-magic');
    else if (line.includes('===')) el.classList.add('log-round');
    if (entry && entry.kind === 'use') {
        renderBattleUseLogChipLine(el, entry);
        return el;
    }
    if (entry && entry.kind === 'counter') {
        renderBattleCounterLogChipLine(el, entry);
        return el;
    }
    if (entry && entry.kind === 'post_use') {
        renderBattlePostUseLogChipLine(el, entry);
        return el;
    }
    if (entry && entry.kind === 'card_action') {
        renderBattleCardActionLogChipLine(el, entry);
        return el;
    }
    const localizedInlineLine = currentLang === 'zh' ? line : displayLine;
    if (renderBattleLogInlineCardLine(el, localizedInlineLine)) {
        bindInlineCardChips(el, { interactive: true });
        return el;
    }
    if (appendBattleLogTextWithCardChips(el, displayLine)) {
        bindInlineCardChips(el, { interactive: true });
        return el;
    }
    el.innerHTML = colorizeBattleLogText(displayLine);
    bindInlineCardChips(el, { interactive: true });
    return el;
}

function resetBattleLogDom(content) {
    if (content) content.innerHTML = '';
    renderedTimelineDomCount = 0;
}

function resetBattleLogState(content) {
    gameTimelineEntries = [];
    battleChatEntries = [];
    roomChatHistorySignature = '';
    battleChatMatchKey = '';
    renderedBattleLogCount = 0;
    renderedBattleLogTotal = 0;
    renderedClassicLogSignature = '';
    renderedBattleLogSnapshot = [];
    const classicContent = $('classic-log-content');
    if (classicContent) {
        classicContent.dataset.renderSignature = '';
        classicContent.innerHTML = '';
    }
    resetBattleLogDom(content);
}

function parseBattleDamageLogForCompact(line) {
    const text = String(line || '');
    let pointMatch = text.match(/^(.+?)еҸ—еҲ°(\d+(?:\+\d+)*)зӮ№(?:[^пјҲпјү()]*?)дјӨе®і[пјҲ(]H=([^пјү)]+)[пјү)]$/);
    if (pointMatch) {
        const parts = pointMatch[2].split('+').map(v => Number(v || 0));
        return {
            target: pointMatch[1],
            units: [{ expr: formatBattleDamagePartsForCompact(parts), parts }],
            hp: String(pointMatch[3] || '').split('вҶ’').filter(Boolean),
        };
    }
    let match = text.match(/^(.+?)еҸ—еҲ°(\d+)D(?:Г—(\d+))?(?:Г—(\d+))?[пјҲ(]H=([^пјү)]+)[пјү)]$/);
    if (match) {
        const inner = Math.max(1, Number(match[3] || 1));
        const outer = Math.max(1, Number(match[4] || 1));
        const expr = `${match[2]}D${inner > 1 ? `Г—${inner}` : ''}`;
        return {
            target: match[1],
            units: Array.from({ length: outer }, () => ({ expr, parts: Array(inner).fill(Number(match[2])) })),
            hp: String(match[5] || '').split('вҶ’').filter(Boolean),
        };
    }
    match = text.match(/^(.+?)еҸ—еҲ°[пјҲ(](\d+(?:\+\d+)*)[пјү)]D[пјҲ(]H=([^пјү)]+)[пјү)]$/);
    if (match) {
        const parts = match[2].split('+').map(v => Number(v || 0));
        return {
            target: match[1],
            units: [{ expr: `(${parts.join('+')})D`, parts }],
            hp: String(match[3] || '').split('вҶ’').filter(Boolean),
        };
    }
    return null;
}

function formatBattleDamagePartsForCompact(parts) {
    const values = (parts || []).map(v => Number(v || 0));
    if (!values.length) return '0D';
    if (values.length === 1) return `${values[0]}D`;
    if (values.every(v => v === values[0])) return `${values[0]}DГ—${values.length}`;
    return `(${values.join('+')})D`;
}

function formatBattleDamageUnitsForCompact(units) {
    const clean = (units || []).map(unit => ({
        expr: String(unit && unit.expr || ''),
        parts: Array.isArray(unit && unit.parts) ? unit.parts.map(v => Number(v || 0)) : [],
    })).filter(unit => unit.expr);
    if (!clean.length) return '0D';
    if (clean.every(unit => unit.expr === clean[0].expr)) {
        return clean.length === 1 ? clean[0].expr : `${clean[0].expr}Г—${clean.length}`;
    }
    const parts = clean.flatMap(unit => unit.parts);
    if (parts.length && parts.every(v => v === parts[0])) return `${parts[0]}DГ—${parts.length}`;
    return `(${parts.join('+')})D`;
}

function mergeBattleHpChainForCompact(a, b) {
    const left = Array.isArray(a) ? a.slice() : [];
    const right = Array.isArray(b) ? b.slice() : [];
    if (!left.length) return right;
    if (!right.length) return left;
    if (left[left.length - 1] === right[0]) return left.concat(right.slice(1));
    return left.concat(right);
}

const BATTLE_LOG_CARD_MARKER_RE = /\u2063CARD:([A-Za-z0-9_-]+)\u2063/g;

function stripBattleLogCardMarkers(text) {
    return String(text || '').replace(BATTLE_LOG_CARD_MARKER_RE, '');
}

function decodeBattleLogCardMarker(text) {
    const source = String(text || '');
    const match = source.match(/\u2063CARD:([A-Za-z0-9_-]+)\u2063/);
    if (!match) return null;
    try {
        const b64 = match[1].replace(/-/g, '+').replace(/_/g, '/');
        const padded = b64 + '='.repeat((4 - (b64.length % 4)) % 4);
        const binary = atob(padded);
        const bytes = Uint8Array.from(binary, ch => ch.charCodeAt(0));
        const jsonText = new TextDecoder('utf-8').decode(bytes);
        const data = JSON.parse(jsonText);
        return data && typeof data === 'object' ? data : null;
    } catch (err) {
        return null;
    }
}

function battleLogCardSignature(cardDict, fallbackName = '') {
    if (!cardDict || typeof cardDict !== 'object') return String(fallbackName || '');
    const keys = [
        'def_id', 'cost_e_override', 'cost_m_override', 'fission_level', 'fusion_level',
        'mimic_discount', 'bonus_damage', 'held_turns', 'return_to_hand_turns',
        'swift_value', 'magic_swift_value', 'power_value', 'temp_swift_value',
        'temp_heavy_value', 'extra_hits',
    ];
    const compact = {};
    keys.forEach(key => {
        const value = cardDict[key];
        if (value !== undefined && value !== null && value !== 0 && value !== 1) compact[key] = value;
    });
    ['instance_flags', 'disabled_flags', 'setup_modifiers'].forEach(key => {
        const arr = Array.isArray(cardDict[key]) ? cardDict[key].map(String).sort() : [];
        if (arr.length) compact[key] = arr;
    });
    return JSON.stringify(compact);
}

function parseBattleUseLogForCompact(line) {
    const rawLine = String(line || '');
    const cardDict = decodeBattleLogCardMarker(rawLine);
    const cleanLine = stripBattleLogCardMarkers(rawLine);
    if (/иҝӣиЎҢеҸҚеҲ¶[пјҒ!]?(?:\s*Г—\d+)?$/.test(cleanLine)) return null;
    const match = cleanLine.match(/^(.+?)дҪҝз”ЁдәҶ?([^пјҢ,пјҒ!:пјҡ]+?)(?: Г—(\d+))?$/);
    if (!match) return null;
    const cardText = String(match[2] || '').trim();
    if (/^е№¶(?:з»ҷ.+?иЈ…еӨҮдәҶ|иЈ…еӨҮдәҶ)/.test(cardText)) return null;
    const defId = (cardDict && cardDict.def_id) || findCardDefIdByAnyName(cardText);
    if (!defId) return null;
    const resolvedCardDict = cardDict || { def_id: defId };
    return {
        actor: match[1],
        card: cardText,
        cardDict: resolvedCardDict,
        cardSignature: battleLogCardSignature(resolvedCardDict, cardText),
        count: Math.max(1, Number(match[3] || 1)),
        cards: [{
            card: cardText,
            cardDict,
            cardSignature: battleLogCardSignature(cardDict, cardText),
            count: Math.max(1, Number(match[3] || 1)),
        }],
    };
}

function parseBattleCounterLogForCompact(line) {
    const rawLine = String(line || '');
    const cardDict = decodeBattleLogCardMarker(rawLine);
    const cleanLine = stripBattleLogCardMarkers(rawLine);
    const match = cleanLine.match(/^(.+?)дҪҝз”ЁдәҶ?(.+?)иҝӣиЎҢеҸҚеҲ¶[пјҒ!]?(?:\s*Г—(\d+))?$/);
    if (!match) return null;
    const cardText = String(match[2] || '').trim();
    const defId = (cardDict && cardDict.def_id) || findCardDefIdByAnyName(cardText);
    if (!defId) return null;
    const resolvedCardDict = cardDict || { def_id: defId };
    const count = Math.max(1, Number(match[3] || 1));
    return {
        actor: String(match[1] || ''),
        card: cardText,
        cardDict: resolvedCardDict,
        cardSignature: battleLogCardSignature(resolvedCardDict, cardText),
        count,
        cards: [{
            card: cardText,
            cardDict: resolvedCardDict,
            cardSignature: battleLogCardSignature(resolvedCardDict, cardText),
            count,
        }],
    };
}

function buildBattleCardActionEntry(subtype, values, rawCardDict = null) {
    const cardText = String(values && values.card || '').trim();
    const defId = (rawCardDict && rawCardDict.def_id) || findCardDefIdByAnyName(cardText);
    if (!defId) return null;
    const cardDict = rawCardDict || { def_id: defId };
    return {
        subtype,
        actor: String(values.actor || ''),
        target: String(values.target || ''),
        card: cardText,
        detail: String(values.detail || '').trim(),
        cardDict,
        cardSignature: battleLogCardSignature(cardDict, cardText),
        count: Math.max(1, Number(values.count || 1)),
    };
}

function parseBattleCardActionLogForCompact(line) {
    const rawLine = String(line || '');
    const rawCardDict = decodeBattleLogCardMarker(rawLine);
    const cleanLine = stripBattleLogCardMarkers(rawLine).trim();
    let match;
    if ((match = cleanLine.match(/^(.+?)дҪҝз”Ё(?:дәҶ)?е№¶з»ҷ(.+?)иЈ…еӨҮдәҶ([^пјҢ,пјҒ!]+)(?:[пјҢ,пјҒ!:пјҡ]\s*(.+))?$/))) {
        return buildBattleCardActionEntry('use_equip_target', {
            actor: match[1], target: match[2], card: match[3], detail: match[4],
        }, rawCardDict);
    }
    if ((match = cleanLine.match(/^(.+?)дҪҝз”Ё(?:дәҶ)?е№¶иЈ…еӨҮдәҶ([^пјҢ,пјҒ!]+)(?:[пјҢ,пјҒ!:пјҡ]\s*(.+))?$/))) {
        return buildBattleCardActionEntry('use_equip_self', {
            actor: match[1], card: match[2], detail: match[3],
        }, rawCardDict);
    }
    if ((match = cleanLine.match(/^(.+?)иЈ…еӨҮдәҶ([^пјҢ,пјҒ!]+)(?:[пјҢ,пјҒ!:пјҡ]\s*(.+))?$/))) {
        return buildBattleCardActionEntry('equip', {
            actor: match[1], card: match[2], detail: match[3],
        }, rawCardDict);
    }
    if ((match = cleanLine.match(/^(.+?)зҡ„([^пјҢ,:пјҡпјҒ!]+?)и§ҰеҸ‘(?:[пјҢ,:пјҡпјҒ!]\s*(.*))?$/))) {
        return buildBattleCardActionEntry('trigger', {
            actor: match[1], card: match[2], detail: match[3],
        }, rawCardDict);
    }
    if ((match = cleanLine.match(/^(.+?)и§ҰеҸ‘([^пјҢ,:пјҡпјҒ!]+?)(?:[пјҢ,:пјҡпјҒ!]\s*(.*))?$/))) {
        return buildBattleCardActionEntry('trigger', {
            actor: match[1], card: match[2], detail: match[3],
        }, rawCardDict);
    }
    if ((match = cleanLine.match(/^(.+?)ж‘§жҜҒдәҶ?(.+?)зҡ„([^пјҢ,пјҒ!]+)(?:[пјҢ,пјҒ!:пјҡ]\s*(.+))?$/))) {
        return buildBattleCardActionEntry('destroy_equipment', {
            actor: match[1], target: match[2], card: match[3], detail: match[4],
        }, rawCardDict);
    }
    if ((match = cleanLine.match(/^(.+?)иҺ·еҫ—иЈ…еӨҮ([^пјҢ,пјҒ!]+)(?:[пјҢ,пјҒ!:пјҡ]\s*(.+))?$/))) {
        return buildBattleCardActionEntry('gain_equipment', {
            actor: match[1], card: match[2], detail: match[3],
        }, rawCardDict);
    }
    if ((match = cleanLine.match(/^(.+?)зҡ„([^пјҢ,пјҒ!]+?)(еӣ жӯ»дәЎиў«ж‘§жҜҒ|еӣ зӣ®ж Үжӯ»дәЎз§»еҮәиЈ…еӨҮеҢә)(?:[пјҢ,пјҒ!:пјҡ]\s*(.+))?$/))) {
        return buildBattleCardActionEntry('equipment_removed', {
            actor: match[1], card: match[2], detail: `${match[3]}${match[4] ? `пјҢ${match[4]}` : ''}`,
        }, rawCardDict);
    }
    if ((match = cleanLine.match(/^(.+?)зҡ„([^пјҢ,пјҒ!]+?)(иЈ…еӨҮжҠӨз”ІжҠөж¶ҲдәҶж‘§жҜҒ(?:[пјҲ(].+[пјү)])?)(?:[пјҢ,пјҒ!:пјҡ]\s*(.+))?$/))) {
        return buildBattleCardActionEntry('equipment_removed', {
            actor: match[1], card: match[2], detail: `${match[3]}${match[4] ? `пјҢ${match[4]}` : ''}`,
        }, rawCardDict);
    }
    if ((match = cleanLine.match(/^([^пјҢ,пјҒ!]+?)иў«ж‘§жҜҒ(?:[пјҢ,:пјҡпјҒ!]\s*(.*))?$/))) {
        return buildBattleCardActionEntry('equipment_destroyed', {
            card: match[1], detail: match[2],
        }, rawCardDict);
    }
    if ((match = cleanLine.match(/^(.+?)жӢ’з»қ(.+?)еҜ№е…¶дҪҝз”Ё([^пјҢ,пјҒ!]+)(?:[пјҢ,пјҒ!:пјҡ]\s*(.+))?$/))) {
        return buildBattleCardActionEntry('card_rejected', {
            actor: match[2], target: match[1], card: match[3], detail: match[4],
        }, rawCardDict);
    }
    if ((match = cleanLine.match(/^(.+?)дҪҝз”Ё(?:дәҶ)?([^пјҢ,пјҒ!:пјҡ]+)[пјҢ,пјҒ!:пјҡ]\s*(.+)$/))) {
        return buildBattleCardActionEntry('use_detail', {
            actor: match[1], card: match[2], detail: match[3],
        }, rawCardDict);
    }
    return null;
}

function formatBattleCardActionLogForCompact(entry) {
    if (!entry) return '';
    const detail = entry.detail ? `пјҢ${entry.detail}` : '';
    if (entry.subtype === 'use_equip_target') return `${entry.actor}дҪҝз”Ёе№¶з»ҷ${entry.target}иЈ…еӨҮдәҶ${entry.card}${detail}`;
    if (entry.subtype === 'use_equip_self') return `${entry.actor}дҪҝз”Ёе№¶иЈ…еӨҮдәҶ${entry.card}${detail}`;
    if (entry.subtype === 'equip') return `${entry.actor}иЈ…еӨҮдәҶ${entry.card}${detail}`;
    if (entry.subtype === 'trigger') return `${entry.actor}зҡ„${entry.card}и§ҰеҸ‘${detail}`;
    if (entry.subtype === 'destroy_equipment') return `${entry.actor}ж‘§жҜҒдәҶ${entry.target}зҡ„${entry.card}${detail}`;
    if (entry.subtype === 'gain_equipment') return `${entry.actor}иҺ·еҫ—иЈ…еӨҮ${entry.card}${detail}`;
    if (entry.subtype === 'equipment_removed') return `${entry.actor}зҡ„${entry.card}${entry.detail || ''}`;
    if (entry.subtype === 'equipment_destroyed') return `${entry.card}иў«ж‘§жҜҒ${detail}`;
    if (entry.subtype === 'card_rejected') return `${entry.target}жӢ’з»қ${entry.actor}еҜ№е…¶дҪҝз”Ё${entry.card}${detail}`;
    return `${entry.actor}дҪҝз”Ё${entry.card}${detail}`;
}

function mergeBattleCardActionForCompact(target, source) {
    if (!target || !source) return false;
    const keys = ['subtype', 'actor', 'target', 'card', 'detail', 'cardSignature'];
    if (keys.some(key => String(target[key] || '') !== String(source[key] || ''))) return false;
    target.count = Math.max(1, Number(target.count || 1)) + Math.max(1, Number(source.count || 1));
    return true;
}

function mergeBattleCounterForCompact(target, source) {
    return mergeBattleUseForCompact(target, source);
}

function formatBattleCounterLogForCompact(counter) {
    if (!counter) return '';
    const cards = Array.isArray(counter.cards) && counter.cards.length
        ? counter.cards
        : [{ card: counter.card, count: counter.count }];
    const cardText = cards.map(item => `${item.card}${Number(item.count || 1) > 1 ? `Г—${Number(item.count || 1)}` : ''}`).join('гҖҒ');
    return `${counter.actor}дҪҝз”Ё${cardText}иҝӣиЎҢеҸҚеҲ¶пјҒ`;
}

function mergeBattleUseForCompact(target, source) {
    if (!target || !source || target.actor !== source.actor) return false;
    const targetCards = Array.isArray(target.cards) && target.cards.length
        ? target.cards
        : [{
            card: target.card,
            cardDict: target.cardDict,
            cardSignature: target.cardSignature,
            count: Math.max(1, Number(target.count || 1)),
        }];
    const sourceCards = Array.isArray(source.cards) && source.cards.length
        ? source.cards
        : [{
            card: source.card,
            cardDict: source.cardDict,
            cardSignature: source.cardSignature,
            count: Math.max(1, Number(source.count || 1)),
        }];
    sourceCards.forEach(card => {
        const existing = targetCards.find(item =>
            item.card === card.card && item.cardSignature === card.cardSignature
        );
        if (existing) {
            existing.count = Math.max(1, Number(existing.count || 1)) + Math.max(1, Number(card.count || 1));
        } else {
            targetCards.push({ ...card });
        }
    });
    target.cards = targetCards;
    target.card = targetCards[0] ? targetCards[0].card : target.card;
    target.cardDict = targetCards[0] ? targetCards[0].cardDict : target.cardDict;
    target.cardSignature = targetCards[0] ? targetCards[0].cardSignature : target.cardSignature;
    target.count = targetCards.reduce((sum, item) => sum + Math.max(1, Number(item.count || 1)), 0);
    return true;
}

function formatBattleUseLogForCompact(use) {
    if (!use) return '';
    const cards = Array.isArray(use.cards) && use.cards.length
        ? use.cards
        : [{ card: use.card, count: use.count }];
    const cardText = cards.map(item => `${item.card}${Number(item.count || 1) > 1 ? `Г—${Number(item.count || 1)}` : ''}`).join('гҖҒ');
    return `${use.actor}дҪҝз”ЁдәҶ${cardText}`;
}

function formatBattleDamageLogForCompact(damage) {
    if (!damage) return '';
    return `${damage.target}еҸ—еҲ°${formatBattleDamageUnitsForCompact(damage.units)}пјҲH=${(damage.hp || []).join('вҶ’')}пјү`;
}

function parseBattlePostUseLogForCompact(line) {
    const rawLine = String(line || '');
    const cardDict = decodeBattleLogCardMarker(rawLine);
    const cleanLine = stripBattleLogCardMarkers(rawLine);
    let uniqueMatch = cleanLine.match(/^(.+?)зҡ„е”ҜдёҖзүҢ(.+?)еӨҡдҪҷеүҜжң¬иў«ж”ҫйҖҗ(?: Г—(\d+))?$/);
    if (uniqueMatch) {
        const cardText = String(uniqueMatch[2] || '').trim();
        return {
            actor: String(uniqueMatch[1] || ''),
            card: cardText,
            cardDict: resolvedCardDict,
            cardSignature: battleLogCardSignature(resolvedCardDict, cardText),
            action: 'е”ҜдёҖзүҢеӨҡдҪҷеүҜжң¬иў«ж”ҫйҖҗ',
            count: Math.max(1, Number(uniqueMatch[3] || 1)),
        };
    }
    let actorExileMatch = cleanLine.match(/^(.+?)ж”ҫйҖҗдәҶ(.+?)(?: Г—(\d+))?$/);
    if (actorExileMatch) {
        const cardText = String(actorExileMatch[2] || '').trim();
        return {
            actor: String(actorExileMatch[1] || ''),
            card: cardText,
            cardDict,
            cardSignature: battleLogCardSignature(cardDict, cardText),
            action: 'ж”ҫйҖҗдәҶ',
            count: Math.max(1, Number(actorExileMatch[3] || 1)),
        };
    }
    let match = cleanLine.match(/^(.+?)зҡ„(.+?)(еӣ еӣһиҪ¬еӣһеҲ°жүӢдёӯ|з«ӢеҚіеӣһеҲ°жүӢдёӯ|еӣ иҷҡж— иў«ж”ҫйҖҗ|еӣ йҳҹдјҚзӢ¬дёҖиў«ж”ҫйҖҗ|еӣ жјӮжө®жҙ—е…ҘжҠҪзүҢе Ҷ|иў«ж”ҫйҖҗ|з§»е…ҘејғзүҢе Ҷ)(?: Г—(\d+))?$/);
    if (!match) {
        match = cleanLine.match(/^(.+?)(иў«ж”ҫйҖҗ|з§»е…ҘејғзүҢе Ҷ)(?: Г—(\d+))?$/);
        if (!match) return null;
        const cardText = String(match[1] || '').trim();
        return {
            actor: '',
            card: cardText,
            cardDict,
            cardSignature: battleLogCardSignature(cardDict, cardText),
            action: String(match[2] || ''),
            count: Math.max(1, Number(match[3] || 1)),
        };
    }
    const cardText = String(match[2] || '').trim();
    return {
        actor: String(match[1] || ''),
        card: cardText,
        cardDict,
        cardSignature: battleLogCardSignature(cardDict, cardText),
        action: String(match[3] || ''),
        count: Math.max(1, Number(match[4] || 1)),
    };
}

function mergeBattlePostUseForCompact(target, source) {
    if (!target || !source) return false;
    if (target.actor !== source.actor || target.card !== source.card || target.action !== source.action || target.cardSignature !== source.cardSignature) return false;
    target.count = Math.max(1, Number(target.count || 1)) + Math.max(1, Number(source.count || 1));
    return true;
}

function formatBattlePostUseLogForCompact(entry) {
    if (!entry) return '';
    const countText = Number(entry.count || 1) > 1 ? ` Г—${Number(entry.count || 1)}` : '';
    if (entry.action === 'е”ҜдёҖзүҢеӨҡдҪҷеүҜжң¬иў«ж”ҫйҖҗ') {
        return `${entry.actor}зҡ„е”ҜдёҖзүҢ${entry.card}еӨҡдҪҷеүҜжң¬иў«ж”ҫйҖҗ${countText}`;
    }
    if (entry.action === 'ж”ҫйҖҗдәҶ') {
        return `${entry.actor}ж”ҫйҖҗдәҶ${entry.card}${countText}`;
    }
    return entry.actor
        ? `${entry.actor}зҡ„${entry.card}${entry.action}${countText}`
        : `${entry.card}${entry.action}${countText}`;
}

function findRecentCompactUseGroup(output, actor) {
    for (let index = output.length - 1; index >= 0 && index >= output.length - 5; index -= 1) {
        const entry = output[index];
        if (!entry) continue;
        if (entry.kind === 'use' && entry.actor === actor) return entry;
        if (!['damage', 'post_use', 'raw'].includes(entry.kind)) return null;
        if (entry.kind === 'post_use' && entry.actor && entry.actor !== actor) return null;
        if (entry.kind === 'raw' && !/^(?:.+?еҸ—еҲ°|.+?еӣһеӨҚ|.+?иҺ·еҫ—|\+|-|\d+)/.test(entry.text || '')) return null;
    }
    return null;
}

function findRecentCompactEntry(output, kind, predicate) {
    for (let index = output.length - 1; index >= 0 && index >= output.length - 8; index -= 1) {
        const entry = output[index];
        if (!entry) continue;
        if (entry.kind === kind && (!predicate || predicate(entry))) return entry;
        if (!['use', 'damage', 'post_use', 'raw'].includes(entry.kind)) return null;
        if (entry.kind === 'raw' && !/^(?:.+?еҸ—еҲ°|.+?еӣһеӨҚ|.+?иҺ·еҫ—|\+|-|\d+)/.test(entry.text || '')) return null;
    }
    return null;
}

function compactBattleLogLinesForDisplay(log) {
    const output = [];
    const rawLines = Array.isArray(log) ? log.map(line => String(line || '')) : [];
    rawLines.forEach((line, rawIndex) => {
        const counter = parseBattleCounterLogForCompact(line);
        if (counter) {
            const last = output[output.length - 1];
            if (last && last.kind === 'counter' && last.actor === counter.actor) {
                mergeBattleCounterForCompact(last, counter);
                last.rawEnd = rawIndex;
                return;
            }
            output.push({ kind: 'counter', ...counter, rawStart: rawIndex, rawEnd: rawIndex });
            return;
        }
        const use = parseBattleUseLogForCompact(line);
        if (use) {
            const last = output[output.length - 1];
            const previous = output[output.length - 2];
            if (last && last.kind === 'damage' && previous && previous.kind === 'use' && previous.actor === use.actor) {
                mergeBattleUseForCompact(previous, use);
                previous.rawEnd = rawIndex;
                return;
            }
            const recentGroup = findRecentCompactUseGroup(output, use.actor);
            if (recentGroup && recentGroup !== last) {
                mergeBattleUseForCompact(recentGroup, use);
                recentGroup.rawEnd = rawIndex;
                return;
            }
            if (last && last.kind === 'use' && last.actor === use.actor) {
                mergeBattleUseForCompact(last, use);
                last.rawEnd = rawIndex;
                return;
            }
            output.push({ kind: 'use', ...use, rawStart: rawIndex, rawEnd: rawIndex });
            return;
        }
        const damage = parseBattleDamageLogForCompact(line);
        if (damage) {
            const last = output[output.length - 1];
            if (last && last.kind === 'damage' && last.target === damage.target) {
                last.units = (last.units || []).concat(damage.units || []);
                last.hp = mergeBattleHpChainForCompact(last.hp, damage.hp);
                last.rawEnd = rawIndex;
                return;
            }
            const recentDamage = findRecentCompactEntry(output, 'damage', entry => entry.target === damage.target);
            if (recentDamage) {
                recentDamage.units = (recentDamage.units || []).concat(damage.units || []);
                recentDamage.hp = mergeBattleHpChainForCompact(recentDamage.hp, damage.hp);
                recentDamage.rawEnd = rawIndex;
                return;
            }
            output.push({ kind: 'damage', ...damage, rawStart: rawIndex, rawEnd: rawIndex });
            return;
        }
        const postUse = parseBattlePostUseLogForCompact(line);
        if (postUse) {
            const last = output[output.length - 1];
            if (last && last.kind === 'post_use' && mergeBattlePostUseForCompact(last, postUse)) {
                last.rawEnd = rawIndex;
                return;
            }
            const recentPostUse = findRecentCompactEntry(output, 'post_use', entry =>
                entry.actor === postUse.actor
                && entry.card === postUse.card
                && entry.action === postUse.action
                && entry.cardSignature === postUse.cardSignature
            );
            if (recentPostUse && mergeBattlePostUseForCompact(recentPostUse, postUse)) {
                recentPostUse.rawEnd = rawIndex;
                return;
            }
            const group = findRecentCompactUseGroup(output, postUse.actor);
            output.push({ kind: 'post_use', ...postUse, rawStart: rawIndex, rawEnd: rawIndex, groupActor: group ? group.actor : '' });
            return;
        }
        const cardAction = parseBattleCardActionLogForCompact(line);
        if (cardAction) {
            const last = output[output.length - 1];
            if (last && last.kind === 'card_action' && mergeBattleCardActionForCompact(last, cardAction)) {
                last.rawEnd = rawIndex;
                return;
            }
            output.push({ kind: 'card_action', ...cardAction, rawStart: rawIndex, rawEnd: rawIndex });
            return;
        }
        output.push({ kind: 'raw', text: stripBattleLogCardMarkers(line), rawStart: rawIndex, rawEnd: rawIndex });
    });
    return output.map(entry => {
        if (entry.kind === 'use') return formatBattleUseLogForCompact(entry);
        if (entry.kind === 'counter') return formatBattleCounterLogForCompact(entry);
        if (entry.kind === 'damage') return formatBattleDamageLogForCompact(entry);
        if (entry.kind === 'post_use') return formatBattlePostUseLogForCompact(entry);
        if (entry.kind === 'card_action') return formatBattleCardActionLogForCompact(entry);
        return entry.text || '';
    });
}

function compactBattleLogEntriesForDisplay(log) {
    const output = [];
    const rawLines = Array.isArray(log) ? log.map(line => String(line || '')) : [];
    rawLines.forEach((line, rawIndex) => {
        const counter = parseBattleCounterLogForCompact(line);
        if (counter) {
            const last = output[output.length - 1];
            if (last && last.kind === 'counter' && last.actor === counter.actor) {
                mergeBattleCounterForCompact(last, counter);
                last.rawEnd = rawIndex;
                return;
            }
            output.push({ kind: 'counter', ...counter, rawStart: rawIndex, rawEnd: rawIndex });
            return;
        }
        const use = parseBattleUseLogForCompact(line);
        if (use) {
            const last = output[output.length - 1];
            const previous = output[output.length - 2];
            if (last && last.kind === 'damage' && previous && previous.kind === 'use' && previous.actor === use.actor) {
                mergeBattleUseForCompact(previous, use);
                previous.rawEnd = rawIndex;
                return;
            }
            const recentGroup = findRecentCompactUseGroup(output, use.actor);
            if (recentGroup && recentGroup !== last) {
                mergeBattleUseForCompact(recentGroup, use);
                recentGroup.rawEnd = rawIndex;
                return;
            }
            if (last && last.kind === 'use' && last.actor === use.actor) {
                mergeBattleUseForCompact(last, use);
                last.rawEnd = rawIndex;
                return;
            }
            output.push({ kind: 'use', ...use, rawStart: rawIndex, rawEnd: rawIndex });
            return;
        }
        const damage = parseBattleDamageLogForCompact(line);
        if (damage) {
            const last = output[output.length - 1];
            if (last && last.kind === 'damage' && last.target === damage.target) {
                last.units = (last.units || []).concat(damage.units || []);
                last.hp = mergeBattleHpChainForCompact(last.hp, damage.hp);
                last.rawEnd = rawIndex;
                return;
            }
            const recentDamage = findRecentCompactEntry(output, 'damage', entry => entry.target === damage.target);
            if (recentDamage) {
                recentDamage.units = (recentDamage.units || []).concat(damage.units || []);
                recentDamage.hp = mergeBattleHpChainForCompact(recentDamage.hp, damage.hp);
                recentDamage.rawEnd = rawIndex;
                return;
            }
            output.push({ kind: 'damage', ...damage, rawStart: rawIndex, rawEnd: rawIndex });
            return;
        }
        const postUse = parseBattlePostUseLogForCompact(line);
        if (postUse) {
            const last = output[output.length - 1];
            if (last && last.kind === 'post_use' && mergeBattlePostUseForCompact(last, postUse)) {
                last.rawEnd = rawIndex;
                return;
            }
            const recentPostUse = findRecentCompactEntry(output, 'post_use', entry =>
                entry.actor === postUse.actor
                && entry.card === postUse.card
                && entry.action === postUse.action
                && entry.cardSignature === postUse.cardSignature
            );
            if (recentPostUse && mergeBattlePostUseForCompact(recentPostUse, postUse)) {
                recentPostUse.rawEnd = rawIndex;
                return;
            }
            const group = findRecentCompactUseGroup(output, postUse.actor);
            output.push({ kind: 'post_use', ...postUse, rawStart: rawIndex, rawEnd: rawIndex, groupActor: group ? group.actor : '' });
            return;
        }
        const cardAction = parseBattleCardActionLogForCompact(line);
        if (cardAction) {
            const last = output[output.length - 1];
            if (last && last.kind === 'card_action' && mergeBattleCardActionForCompact(last, cardAction)) {
                last.rawEnd = rawIndex;
                return;
            }
            output.push({ kind: 'card_action', ...cardAction, rawStart: rawIndex, rawEnd: rawIndex });
            return;
        }
        const last = output[output.length - 1];
        if (last && last.kind === 'raw' && last.text === line) {
            last.count = Number(last.count || 1) + 1;
            last.rawEnd = rawIndex;
            return;
        }
        output.push({ kind: 'raw', text: stripBattleLogCardMarkers(line), count: 1, rawStart: rawIndex, rawEnd: rawIndex });
    });
    return output.map(entry => ({
        type: 'battle',
        text: entry.kind === 'use'
            ? formatBattleUseLogForCompact(entry)
            : (entry.kind === 'counter'
                ? formatBattleCounterLogForCompact(entry)
                : (entry.kind === 'damage'
                    ? formatBattleDamageLogForCompact(entry)
                    : (entry.kind === 'post_use'
                        ? formatBattlePostUseLogForCompact(entry)
                        : (entry.kind === 'card_action'
                            ? formatBattleCardActionLogForCompact(entry)
                            : `${entry.text || ''}${Number(entry.count || 1) > 1 ? ` Г—${Number(entry.count || 1)}` : ''}`)))),
        kind: entry.kind,
        actor: entry.actor,
        card: entry.card,
        action: entry.action,
        subtype: entry.subtype,
        target: entry.target,
        detail: entry.detail,
        cards: entry.cards,
        cardDict: entry.cardDict,
        cardSignature: entry.cardSignature,
        count: entry.count,
        rawStart: Number(entry.rawStart || 0),
        rawEnd: Number(entry.rawEnd == null ? entry.rawStart || 0 : entry.rawEnd),
    }));
}

function buildBattleTimelineEntries(log) {
    const entries = [];
    const currentMatchKey = phaseContextMatchKey(gameState);
    const chats = (battleChatEntries || [])
        .filter(entry => !currentMatchKey || !entry.matchKey || entry.matchKey === currentMatchKey)
        .slice()
        .sort((a, b) => Number(a.logAnchor || 0) - Number(b.logAnchor || 0));
    pregameChatEntries.forEach((entry, index) => {
        entries.push({ ...entry, pregame: true, pregameChatSeed: index === 0 });
    });
    const compactEntries = compactBattleLogEntriesForDisplay(log);
    let chatIndex = 0;
    compactEntries.forEach(entry => {
        const start = Number(entry.rawStart || 0);
        const end = Number(entry.rawEnd == null ? start : entry.rawEnd);
        while (chatIndex < chats.length && Number(chats[chatIndex].logAnchor || 0) <= start) {
            entries.push(chats[chatIndex++]);
        }
        entries.push(entry);
        while (chatIndex < chats.length && Number(chats[chatIndex].logAnchor || 0) <= end + 1) {
            entries.push(chats[chatIndex++]);
        }
    });
    while (chatIndex < chats.length) entries.push(chats[chatIndex++]);
    return entries;
}

function renderLog(log, logStart = 0, logTotal = null) {
    const container = $('battle-log');
    if (!container) return;
    container.classList.toggle('blind-log-masked', getOwnBlindLevel() >= 2);
    let content = container.querySelector('.log-content');
    if (!content) {
        content = document.createElement('div');
        content.className = 'log-content';
        container.appendChild(content);
    }
    const wasAtBottom = content.scrollTop + content.clientHeight >= content.scrollHeight - 30;
    if (content.dataset.renderLang !== currentLang) {
        content.dataset.renderLang = currentLang;
        resetBattleLogState(content);
    }
    if (!Array.isArray(log)) log = [];
    const matchKey = phaseContextMatchKey(gameState);
    if (matchKey && renderedBattleLogMatchKey && renderedBattleLogMatchKey !== String(matchKey)) {
        resetBattleLogState(content);
    }
    if (matchKey) renderedBattleLogMatchKey = String(matchKey);
    logStart = Number(logStart || 0);
    const rawLog = log.map(line => String(line || ''));
    logTotal = Number(logTotal == null ? logStart + rawLog.length : logTotal);
    playAudioForNewBattleLogs(rawLog, logStart, logTotal, matchKey);
    if (logTotal < renderedBattleLogTotal || logStart > renderedBattleLogTotal) {
        resetBattleLogState(content);
        renderedBattleLogTotal = logStart;
    }
    const nextBattleSnapshot = rawLog.map(line => String(line || ''));
    const canAppendBattleLog = renderedBattleLogSnapshot.length <= nextBattleSnapshot.length
        && renderedBattleLogSnapshot.every((line, index) => line === nextBattleSnapshot[index]);
    if (!canAppendBattleLog) {
        resetBattleLogState(content);
        renderedBattleLogTotal = logStart;
    }
    gameTimelineEntries = buildBattleTimelineEntries(rawLog);
    renderedBattleLogCount = rawLog.length;
    renderedBattleLogTotal = logTotal;
    renderedBattleLogSnapshot = nextBattleSnapshot;
    resetBattleLogDom(content);
    if (gameTimelineEntries.length) {
        const fragment = document.createDocumentFragment();
        gameTimelineEntries.forEach(entry => fragment.appendChild(createBattleLogElement(entry)));
        content.appendChild(fragment);
        renderedTimelineDomCount = gameTimelineEntries.length;
    }
    if (wasAtBottom) content.scrollTop = content.scrollHeight;
}

function getChatChannelLogLabel(entry) {
    const channel = entry && entry.channel;
    if (!channel) return '';
    if (channel === 'team') return t('chat_channel_team');
    if (channel === 'enemy') return t('chat_channel_enemy');
    if (channel === 'private') return tf('chat_channel_private_to', localizeCanonicalPlayerName(entry.targetName || '?'));
    return t('chat_channel_public');
}

function appendLobbyChat(nick, text, meta = {}) {
    const container = $('lobby-chat-log');
    if (!container) return;
    appendLobbyChatEntry({
        type: 'chat',
        nickname: meta.nickname || nick,
        display_nick: nick,
        message_id: meta.message_id || meta.messageId || '',
        sender_user_id: meta.sender_user_id || meta.senderUserId || meta.user_id || '',
        sender_name: meta.sender_name || meta.senderName || meta.nickname || nick,
        text,
        repeat_count: meta.repeat_count || 1,
        ...meta,
    });
}

function currentUserMentionKeys() {
    const keys = new Set();
    if (currentAccount) {
        if (currentAccount.id != null) keys.add(`user:${currentAccount.id}`);
        if (currentAccount.username) keys.add(`name:${String(currentAccount.username).toLowerCase()}`);
        if (currentAccount.player_id) keys.add(`pid:${String(currentAccount.player_id).toUpperCase()}`);
    }
    if (nickname) keys.add(`name:${String(nickname).toLowerCase()}`);
    return keys;
}

function entryMentionsCurrentUser(entry) {
    const mentions = Array.isArray(entry.mentions) ? entry.mentions : [];
    if (!mentions.length) return false;
    const keys = currentUserMentionKeys();
    return mentions.some(item => {
        if (!item) return false;
        if (item.user_id != null && keys.has(`user:${item.user_id}`)) return true;
        if (item.nickname && keys.has(`name:${String(item.nickname).toLowerCase()}`)) return true;
        if (item.player_id && keys.has(`pid:${String(item.player_id).toUpperCase()}`)) return true;
        return false;
    });
}

function lobbyChatEntryKey(entry = {}) {
    return String(entry.message_id || entry.messageId || entry.id || `${entry.time || ''}:${entry.nickname || ''}:${entry.text || ''}`);
}

function currentUserMentionTokens(entry = {}) {
    const tokens = new Set();
    const keys = currentUserMentionKeys();
    (Array.isArray(entry.mentions) ? entry.mentions : []).forEach(item => {
        if (!item) return;
        const matches =
            (item.user_id != null && keys.has(`user:${item.user_id}`))
            || (item.nickname && keys.has(`name:${String(item.nickname).toLowerCase()}`))
            || (item.player_id && keys.has(`pid:${String(item.player_id).toUpperCase()}`));
        if (!matches) return;
        if (item.nickname) tokens.add(String(item.nickname).toLowerCase());
        if (item.player_id) tokens.add(String(item.player_id).toUpperCase());
    });
    return tokens;
}

function appendChatTextWithMentions(parent, text, mentions = [], ownMentionTokens = new Set(), shouldFlashOwnMention = false) {
    const raw = String(text || '');
    const mentionNames = [];
    (Array.isArray(mentions) ? mentions : []).forEach(item => {
        if (!item) return;
        if (item.nickname) mentionNames.push(String(item.nickname));
        if (item.player_id) mentionNames.push(String(item.player_id));
    });
    const unique = [...new Set(mentionNames.filter(Boolean))].sort((a, b) => b.length - a.length);
    if (!unique.length) {
        parent.appendChild(document.createTextNode(raw));
        return;
    }
    const pattern = new RegExp('(@(?:' + unique.map(name => name.replace(/[.*+?^${}()|[\]\\]/g, '\\$&')).join('|') + '))(?![\\w\\u4e00-\\u9fff\\u3040-\\u30ff\\uac00-\\ud7af-])', 'gi');
    let last = 0;
    raw.replace(pattern, (match, token, offset) => {
        if (offset > last) parent.appendChild(document.createTextNode(raw.slice(last, offset)));
        const span = document.createElement('span');
        span.className = 'chat-mention-token';
        const tokenName = String(match || '').replace(/^@/, '');
        if (shouldFlashOwnMention && (ownMentionTokens.has(tokenName.toLowerCase()) || ownMentionTokens.has(tokenName.toUpperCase()))) {
            span.classList.add('mention-flash');
        }
        span.textContent = match;
        parent.appendChild(span);
        last = offset + match.length;
        return match;
    });
    if (last < raw.length) parent.appendChild(document.createTextNode(raw.slice(last)));
}

function parseChatTimeValue(value) {
    if (!value) return null;
    const date = value instanceof Date ? value : new Date(value);
    return Number.isNaN(date.getTime()) ? null : date;
}

function localDateKey(date) {
    return `${date.getFullYear()}-${String(date.getMonth() + 1).padStart(2, '0')}-${String(date.getDate()).padStart(2, '0')}`;
}

function dayStart(date) {
    return new Date(date.getFullYear(), date.getMonth(), date.getDate());
}

function formatLobbyDate(date) {
    if (currentLang === 'zh') {
        return `${date.getFullYear()}е№ҙ${date.getMonth() + 1}жңҲ${date.getDate()}ж—Ҙ`;
    }
    if (currentLang === 'ja') {
        return `${date.getFullYear()}е№ҙ${date.getMonth() + 1}жңҲ${date.getDate()}ж—Ҙ`;
    }
    if (currentLang === 'fr') {
        return date.toLocaleDateString('fr-FR', { year: 'numeric', month: '2-digit', day: '2-digit' });
    }
    return date.toLocaleDateString('en-US', { year: 'numeric', month: 'short', day: 'numeric' });
}

function formatLobbyChatSeparator(entry = {}) {
    const date = parseChatTimeValue(entry.time || entry.created_at || entry.createdAt);
    const fallback = entry.display_time || entry.displayTime || '';
    if (!date) return fallback;
    const timeText = date.toLocaleTimeString(currentLang === 'zh' ? 'zh-CN' : (currentLang === 'ja' ? 'ja-JP' : (currentLang === 'fr' ? 'fr-FR' : 'en-US')), {
        hour: '2-digit',
        minute: '2-digit',
        hour12: false,
    });
    const now = new Date();
    if (localDateKey(date) === localDateKey(now)) return timeText;
    const daysAgo = Math.round((dayStart(now).getTime() - dayStart(date).getTime()) / 86400000);
    if (daysAgo === 1) return `${t('chat_day_yesterday')} ${timeText}`;
    if (daysAgo === 2) return `${t('chat_day_before_yesterday')} ${timeText}`;
    return `${formatLobbyDate(date)} ${timeText}`;
}

const LOBBY_CHAT_AUTO_SCROLL_THRESHOLD = 24;

function isLobbyChatNearBottom(container) {
    if (!container) return true;
    return container.scrollHeight - container.scrollTop - container.clientHeight <= LOBBY_CHAT_AUTO_SCROLL_THRESHOLD;
}

function appendLobbyChatEntry(entry = {}, options = {}) {
    const container = $('lobby-chat-log');
    if (!container) return;
    const shouldAutoScroll = options.autoScroll == null
        ? isLobbyChatNearBottom(container)
        : Boolean(options.autoScroll);
    if (entry.type === 'time') {
        const timeEl = document.createElement('div');
        timeEl.className = 'chat-time-separator';
        timeEl.textContent = formatLobbyChatSeparator(entry);
        container.appendChild(timeEl);
        if (shouldAutoScroll) container.scrollTop = container.scrollHeight;
        return;
    }
    const el = document.createElement('div');
    el.className = 'chat-msg';
    const nameSpan = document.createElement('span');
    nameSpan.className = 'chat-nick';
    if (entry.system) nameSpan.classList.add('system-name');
    if (isAdminPlayer(entry)) nameSpan.classList.add('admin-name');
    if (getSpecialRoleColor(entry) === 'bloom') nameSpan.classList.add('bloom-name');
    if (getSpecialRoleColor(entry) === 'guard') nameSpan.classList.add('guard-name');
    const nick = entry.display_nick || getChatDisplayName(entry);
    nameSpan.textContent = entry.system ? `${nick} ` : `${nick}: `;
    el.appendChild(nameSpan);
    const mentionKey = lobbyChatEntryKey(entry);
    const ownMentionTokens = currentUserMentionTokens(entry);
    const shouldFlashOwnMention = ownMentionTokens.size > 0 && !readLobbyMentionIds.has(mentionKey);
    if (shouldFlashOwnMention) {
        el.dataset.mentionId = mentionKey;
    }
    appendChatTextWithMentions(el, entry.text || '', entry.mentions || [], ownMentionTokens, shouldFlashOwnMention);
    const repeatCount = Number(entry.repeat_count || entry.repeatCount || 1);
    if (repeatCount > 1) {
        const repeatSpan = document.createElement('span');
        repeatSpan.className = 'chat-repeat-count';
        repeatSpan.textContent = ` Г—${repeatCount}`;
        el.appendChild(repeatSpan);
    }
    if (isReportableChatEntry(entry)) {
        el.appendChild(createReportButton(chatEntryReportMeta(entry), {
            className: 'report-inline-btn chat-report-btn',
            text: UI.report,
            title: UI.report_chat,
        }));
    }
    container.appendChild(el);
    if (shouldAutoScroll) container.scrollTop = container.scrollHeight;
}

function renderLobbyChatHistory(data = {}) {
    const container = $('lobby-chat-log');
    if (!container) return;
    const items = Array.isArray(data.items) ? data.items : [];
    const signature = JSON.stringify([currentLang, items.map(entry => [
        entry && entry.type,
        entry && entry.id,
        entry && entry.time,
        entry && entry.nickname,
        entry && entry.text,
        entry && entry.repeat_count,
        entry && entry.display_time,
        entry && entry.chat_channel,
        entry && entry.system,
        entry && JSON.stringify(entry.mentions || []),
    ])]);
    if (signature === lobbyChatHistorySignature) return;
    lobbyChatHistorySignature = signature;
    const shouldAutoScroll = isLobbyChatNearBottom(container);
    const previousScrollTop = container.scrollTop;
    container.innerHTML = '';
    items.forEach(entry => appendLobbyChatEntry(entry, { autoScroll: false }));
    if (shouldAutoScroll) {
        container.scrollTop = container.scrollHeight;
    } else {
        const maxScrollTop = Math.max(0, container.scrollHeight - container.clientHeight);
        container.scrollTop = Math.min(previousScrollTop, maxScrollTop);
    }
}

function appendGameChat(nick, text, meta = {}, channelMeta = {}) {
    const matchKey = phaseContextMatchKey(gameState);
    const entry = makeChatTimelineEntry(nick, text, {
        ...meta,
        log_anchor: meta.log_anchor ?? meta.logAnchor ?? Number(gameState && gameState.log_total != null ? gameState.log_total : ((gameState && Array.isArray(gameState.log)) ? gameState.log.length : 0)),
    }, channelMeta);
    if (matchKey && battleChatMatchKey && battleChatMatchKey !== matchKey) {
        battleChatEntries = [];
        roomChatHistorySignature = '';
    }
    if (matchKey) battleChatMatchKey = matchKey;
    appendCompressedTimelineChat(battleChatEntries, { ...entry, matchKey }, 500);
    refreshBattleLogViews();
}

function refreshBattleLogViews() {
    const gs = gameState || {};
    renderLog(gs.log || [], gs.log_start || 0, gs.log_total);
    if (shouldUseClassicBattle(gs)) {
        renderClassicLog(buildBattleViewModel(gs));
    }
}

function renderPendingCard() {
    const playZone = $('play-zone');
    if (!playZone || !pendingPlayCard) return;
    const cardDef = getCardDef(pendingPlayCard.def_id);
    const typeColor = cardDef ? (CARD_TYPE_COLORS[cardDef.card_type] || COLORS.text_primary) : COLORS.text_primary;
    const typeLabel = cardDef ? getCardTypeLabel(cardDef.card_type) : '';
    playZone.innerHTML = `
        <div class="pending-card" style="border-color:${typeColor}">
            <div style="color:${typeColor};font-weight:bold">${cardDef ? getCardName(cardDef) : '?'}</div>
            <div style="color:${typeColor};font-size:11px">${typeLabel}</div>
            <div style="color:${COLORS.damage};font-size:11px">${UI.waiting_response}</div>
        </div>
    `;
}

function isCardAnimationLocked() {
    return Date.now() < cardAnimationLockUntil;
}

function scheduleCardAnimationUnlock() {
    if (cardAnimationUnlockTimer) clearTimeout(cardAnimationUnlockTimer);
    const delay = Math.max(30, cardAnimationLockUntil - Date.now() + 30);
    cardAnimationUnlockTimer = setTimeout(() => {
        if (isCardAnimationLocked()) {
            scheduleCardAnimationUnlock();
            return;
        }
        document.body.classList.remove('card-animation-lock');
        cardAnimationUnlockTimer = null;
    }, delay);
}

function lockCardAnimation(duration = 320) {
    cardAnimationLockUntil = Math.max(cardAnimationLockUntil, Date.now() + duration);
    document.body.classList.add('card-animation-lock');
    scheduleCardAnimationUnlock();
}

function cardInstanceKey(card) {
    if (!card || card.instance_id == null) return '';
    return String(card.instance_id);
}

function cardHasExileLikeExit(card) {
    if (!card) return false;
    if (card.def_id === 'Yggdrasil') return true;
    const cardDef = getCardDef(card.def_id);
    const flags = new Set([
        ...((cardDef && cardDef.flags) || []),
        ...((card && card.instance_flags) || []),
    ]);
    return flags.has('exile');
}

function ensureLobbyMentionMenu() {
    if (lobbyMentionMenu) return lobbyMentionMenu;
    lobbyMentionMenu = document.createElement('div');
    lobbyMentionMenu.id = 'lobby-mention-menu';
    lobbyMentionMenu.className = 'mention-menu hidden';
    document.body.appendChild(lobbyMentionMenu);
    lobbyMentionMenu.addEventListener('mousedown', (event) => {
        const item = event.target.closest('[data-mention-index]');
        if (!item) return;
        event.preventDefault();
        const idx = Number(item.dataset.mentionIndex);
        const candidate = lobbyMentionCandidates[idx];
        if (candidate) insertLobbyMention(candidate);
    });
    return lobbyMentionMenu;
}

function getLobbyMentionCandidates() {
    const selfKeys = currentUserMentionKeys();
    return (Array.isArray(lobbyPlayers) ? lobbyPlayers : [])
        .map(player => ({
            nickname: player.nickname || player.name || '',
            player_id: player.player_id || '',
            user_id: player.user_id || '',
        }))
        .filter(item => item.nickname && !selfKeys.has(`name:${String(item.nickname).toLowerCase()}`));
}

function findLobbyMentionRange(input) {
    if (!input) return null;
    const value = input.value || '';
    const pos = input.selectionStart ?? value.length;
    const before = value.slice(0, pos);
    const match = before.match(/(^|\s)@([^\s@]*)$/);
    if (!match) return null;
    const start = before.length - match[0].length + match[1].length;
    return { start, end: pos, query: match[2] || '' };
}

function updateLobbyMentionMenu() {
    const input = $('lobby-chat-input');
    const menu = ensureLobbyMentionMenu();
    const range = findLobbyMentionRange(input);
    lobbyMentionActiveRange = range;
    if (!input || !range) {
        menu.classList.add('hidden');
        return;
    }
    const query = String(range.query || '').toLowerCase();
    lobbyMentionCandidates = getLobbyMentionCandidates()
        .filter(item => !query || String(item.nickname).toLowerCase().includes(query) || String(item.player_id).toLowerCase().includes(query))
        .slice(0, 8);
    if (!lobbyMentionCandidates.length) {
        menu.classList.add('hidden');
        return;
    }
    menu.innerHTML = lobbyMentionCandidates.map((item, index) => `
        <button type="button" class="mention-menu-item" data-mention-index="${index}">
          <span>@${escapeHtml(item.nickname)}</span>
          ${item.player_id ? `<small>${escapeHtml(item.player_id)}</small>` : ''}
        </button>
    `).join('');
    const rect = input.getBoundingClientRect();
    menu.style.left = `${Math.max(8, rect.left)}px`;
    menu.style.top = `${Math.max(8, rect.top - Math.min(220, menu.offsetHeight || 180) - 6)}px`;
    menu.style.width = `${Math.min(260, Math.max(180, rect.width))}px`;
    menu.classList.remove('hidden');
}

function insertLobbyMention(candidate) {
    const input = $('lobby-chat-input');
    if (!input || !lobbyMentionActiveRange) return;
    const value = input.value || '';
    const token = `@${candidate.nickname} `;
    input.value = value.slice(0, lobbyMentionActiveRange.start) + token + value.slice(lobbyMentionActiveRange.end);
    const pos = lobbyMentionActiveRange.start + token.length;
    input.focus();
    input.setSelectionRange(pos, pos);
    if (lobbyMentionMenu) lobbyMentionMenu.classList.add('hidden');
}

function clearLobbyMentionFlash() {
    document.querySelectorAll('#lobby-chat-log [data-mention-id]').forEach(el => {
        if (el.dataset.mentionId) readLobbyMentionIds.add(el.dataset.mentionId);
        el.removeAttribute('data-mention-id');
    });
    document.querySelectorAll('#lobby-chat-log .mention-flash').forEach(el => el.classList.remove('mention-flash'));
}

function markRecentlyPlayedExileCard(card) {
    const id = cardInstanceKey(card);
    if (!id) return;
    const expiresAt = Date.now() + 4200;
    recentlyPlayedExileCards.set(id, expiresAt);
    setTimeout(() => {
        if (recentlyPlayedExileCards.get(id) === expiresAt) {
            recentlyPlayedExileCards.delete(id);
        }
    }, 4300);
}

function wasRecentlyPlayedExileCard(id) {
    if (!id) return false;
    const expiresAt = recentlyPlayedExileCards.get(String(id));
    if (!expiresAt) return false;
    if (expiresAt < Date.now()) {
        recentlyPlayedExileCards.delete(String(id));
        return false;
    }
    return true;
}

function getNewlyExiledHandCards(previousPlayer, nextPlayer) {
    const oldHand = (previousPlayer && previousPlayer.hand) || [];
    const newHand = (nextPlayer && nextPlayer.hand) || [];
    if (!oldHand.length) return [];
    const newHandIds = new Set(newHand.map(cardInstanceKey).filter(Boolean));
    const oldExileIds = new Set(((previousPlayer && previousPlayer.exile) || []).map(cardInstanceKey).filter(Boolean));
    const nextExileIds = new Set(((nextPlayer && nextPlayer.exile) || []).map(cardInstanceKey).filter(Boolean));
    const exileCountIncreased = Number((nextPlayer && nextPlayer.exile_count) || 0) > Number((previousPlayer && previousPlayer.exile_count) || 0);
    return oldHand.filter(card => {
        const id = cardInstanceKey(card);
        if (!id || newHandIds.has(id)) return false;
        if (wasRecentlyPlayedExileCard(id)) {
            recentlyPlayedExileCards.delete(id);
            return false;
        }
        if (nextExileIds.has(id) && !oldExileIds.has(id)) return true;
        return exileCountIncreased && cardHasExileLikeExit(card);
    });
}

function animateCardShatterFromElement(cardEl, delay = 0) {
    if (!cardEl) return;
    const rect = cardEl.getBoundingClientRect();
    if (rect.width <= 0 || rect.height <= 0) return;
    const wrap = document.createElement('div');
    wrap.className = 'card-shatter-wrap';
    wrap.style.left = `${rect.left}px`;
    wrap.style.top = `${rect.top}px`;
    wrap.style.width = `${rect.width}px`;
    wrap.style.height = `${rect.height}px`;
    const pieces = [
        { clip: 'polygon(0 0, 48% 0, 38% 34%, 0 45%)', x: -22, y: -18, r: -13 },
        { clip: 'polygon(48% 0, 100% 0, 100% 38%, 58% 32%, 38% 34%)', x: 20, y: -20, r: 12 },
        { clip: 'polygon(0 45%, 38% 34%, 44% 63%, 0 72%)', x: -28, y: 3, r: -18 },
        { clip: 'polygon(38% 34%, 58% 32%, 64% 66%, 44% 63%)', x: 0, y: -2, r: 7 },
        { clip: 'polygon(58% 32%, 100% 38%, 100% 70%, 64% 66%)', x: 28, y: 4, r: 18 },
        { clip: 'polygon(0 72%, 44% 63%, 40% 100%, 0 100%)', x: -18, y: 24, r: 11 },
        { clip: 'polygon(44% 63%, 64% 66%, 100% 70%, 100% 100%, 40% 100%)', x: 24, y: 26, r: -10 },
    ];
    pieces.forEach((piece, index) => {
        const shard = cardEl.cloneNode(true);
        shard.classList.remove('card-play-flash', 'fusion-merge-clone', 'fusion-core-pulse', 'hand-card-animating');
        shard.classList.add('card-shatter-piece');
        shard.style.left = '';
        shard.style.top = '';
        shard.style.right = '';
        shard.style.bottom = '';
        shard.style.width = '100%';
        shard.style.height = '100%';
        shard.style.clipPath = piece.clip;
        shard.style.setProperty('--shard-x', `${piece.x}px`);
        shard.style.setProperty('--shard-y', `${piece.y}px`);
        shard.style.setProperty('--shard-rot', `${piece.r}deg`);
        shard.style.animationDelay = `${delay + index * 18}ms`;
        wrap.appendChild(shard);
    });
    const crack = document.createElement('div');
    crack.className = 'card-shatter-crack';
    crack.style.animationDelay = `${delay}ms`;
    wrap.appendChild(crack);
    document.body.appendChild(wrap);
    lockCardAnimation(delay + 560);
    setTimeout(() => {
        wrap.remove();
        scheduleTutorialOverlayRefresh(30);
    }, delay + 680);
}

function queueVisibleHandExileAnimations(previous, next) {
    if (!areSequentialGameStates(previous, next) || isSpectating) return;
    const removed = getNewlyExiledHandCards(previous.you || {}, next.you || {});
    if (!removed.length) return;
    const hand = $('you-hand');
    if (!hand) return;
    removed.forEach((card, index) => {
        const id = cardInstanceKey(card);
        const cardEl = id ? hand.querySelector(`.card[data-instance-id="${id}"]`) : null;
        if (cardEl) animateCardShatterFromElement(cardEl, index * 70);
    });
}

function getDrawSourcePoint(finalRect) {
    if (!finalRect) return { x: -80, y: window.innerHeight * 0.82 };
    const hand = $('you-hand');
    const rect = hand ? hand.getBoundingClientRect() : null;
    const offset = Math.max(48, finalRect.width * 0.9);
    return {
        x: (rect ? rect.right : window.innerWidth) + offset,
        y: finalRect.top + finalRect.height / 2,
    };
}

function animateDrawnCard(cardEl, index = 0) {
    if (!cardEl) return 0;
    const finalRect = cardEl.getBoundingClientRect();
    const source = getDrawSourcePoint(finalRect);
    const finalX = finalRect.left + finalRect.width / 2;
    const finalY = finalRect.top + finalRect.height / 2;
    const dx = source.x - finalX;
    const dy = source.y - finalY;
    const delay = Math.min(index * 42, 126);
    const duration = 230;
    cardEl.classList.add('hand-card-animating');
    cardEl.style.transition = 'none';
    cardEl.style.opacity = '0';
    cardEl.style.transform = `translate3d(${dx}px, ${dy}px, 0) scale(0.78)`;
    lockCardAnimation(delay + duration + 90);
    requestAnimationFrame(() => {
        requestAnimationFrame(() => {
            cardEl.style.transition = `transform ${duration}ms cubic-bezier(.2,.8,.2,1) ${delay}ms, opacity ${Math.max(160, duration - 50)}ms ease ${delay}ms`;
            cardEl.style.opacity = '';
            cardEl.style.transform = '';
        });
    });
    setTimeout(() => {
        cardEl.classList.remove('hand-card-animating');
        cardEl.style.transition = '';
        cardEl.style.opacity = '';
        cardEl.style.transform = '';
        scheduleTutorialOverlayRefresh(30);
    }, delay + duration + 80);
    return delay + duration;
}

function animateShiftedCard(cardEl, oldRect, delayed) {
    if (!cardEl || !oldRect) return 0;
    const newRect = cardEl.getBoundingClientRect();
    const dx = oldRect.left - newRect.left;
    const dy = oldRect.top - newRect.top;
    if (Math.abs(dx) < 0.5 && Math.abs(dy) < 0.5) return 0;
    const delay = delayed ? 70 : 0;
    const duration = 210;
    cardEl.classList.add('hand-card-animating');
    cardEl.style.transition = 'none';
    cardEl.style.transform = `translate3d(${dx}px, ${dy}px, 0)`;
    lockCardAnimation(delay + duration + 80);
    requestAnimationFrame(() => {
        requestAnimationFrame(() => {
            cardEl.style.transition = `transform ${duration}ms cubic-bezier(.22,.82,.28,1) ${delay}ms`;
            cardEl.style.transform = '';
        });
    });
    setTimeout(() => {
        cardEl.classList.remove('hand-card-animating');
        cardEl.style.transition = '';
        cardEl.style.transform = '';
        scheduleTutorialOverlayRefresh(30);
    }, delay + duration + 70);
    return delay + duration;
}

function animateHandLayoutChanges(container, oldRects, hand) {
    if (!hasPlayerHandSnapshot || isSpectating || !container || !oldRects || oldRects.size === 0) return;
    const nextIds = new Set(hand.map(c => String(c.instance_id)));
    const removedCount = [...oldRects.keys()].filter(id => !nextIds.has(id)).length;
    let drawIndex = 0;
    hand.forEach(cardDict => {
        const id = String(cardDict.instance_id);
        const cardEl = container.querySelector(`.card[data-instance-id="${id}"]`);
        if (!cardEl) return;
        if (oldRects.has(id)) {
            animateShiftedCard(cardEl, oldRects.get(id), removedCount > 0);
        } else {
            animateDrawnCard(cardEl, drawIndex);
            drawIndex += 1;
        }
    });
}

function animatePlayedCard(cardInstanceId, options = {}) {
    const cardEl = document.querySelector(`.card[data-instance-id="${cardInstanceId}"]`);
    if (!cardEl) return;
    const rect = cardEl.getBoundingClientRect();
    const flash = cardEl.cloneNode(true);
    flash.classList.add('card-play-flash');
    flash.style.left = `${rect.left}px`;
    flash.style.top = `${rect.top}px`;
    flash.style.width = `${rect.width}px`;
    let targeted = false;
    if (options.targetElement) {
        const targetRect = options.targetElement.getBoundingClientRect();
        if (targetRect.width > 0 && targetRect.height > 0) {
            const dx = targetRect.left + targetRect.width / 2 - (rect.left + rect.width / 2);
            const dy = targetRect.top + targetRect.height / 2 - (rect.top + rect.height / 2);
            flash.classList.add('card-play-flash-targeted');
            flash.style.setProperty('--play-dx', `${dx}px`);
            flash.style.setProperty('--play-dy', `${dy}px`);
            targeted = true;
            setTimeout(() => {
                const burst = document.createElement('div');
                burst.className = 'card-impact-burst';
                burst.style.left = `${targetRect.left + targetRect.width / 2}px`;
                burst.style.top = `${targetRect.top + targetRect.height / 2}px`;
                document.body.appendChild(burst);
                setTimeout(() => burst.remove(), 520);
            }, 310);
        }
    }
    const startDelay = Math.max(0, Number(options.startDelay || 0));
    const appendFlash = () => document.body.appendChild(flash);
    if (startDelay > 0) setTimeout(appendFlash, startDelay);
    else appendFlash();
    if (options.shatterAfter) {
        lockCardAnimation(startDelay + (targeted ? 980 : 900));
        setTimeout(() => {
            animateCardShatterFromElement(flash);
            flash.remove();
        }, startDelay + (targeted ? 420 : 340));
        setTimeout(() => flash.remove(), startDelay + (targeted ? 900 : 760));
    } else {
        lockCardAnimation(startDelay + (targeted ? 500 : 360));
        setTimeout(() => flash.remove(), startDelay + (targeted ? 560 : 420));
    }
}

function getPlayGestureFallbackTarget() {
    return $('play-zone')
        || $('classic-stage')
        || document.querySelector('.battle-field')
        || document.body;
}

function createVirtualWindowsCursor() {
    const cursor = document.createElement('div');
    cursor.className = 'virtual-play-cursor';
    cursor.innerHTML = `
        <svg viewBox="0 0 32 32" aria-hidden="true" focusable="false">
            <path class="cursor-shadow" d="M6 3 L6 25 L12.2 19.4 L15.9 28 L19.2 26.6 L15.6 18.2 L24 18.2 Z"></path>
            <path class="cursor-fill" d="M5 2 L5 24 L11.2 18.4 L14.9 27 L18.2 25.6 L14.6 17.2 L23 17.2 Z"></path>
        </svg>
    `;
    return cursor;
}

function animateVirtualPlayGesture(cardInstanceId, options = {}) {
    if (!playGestureAnimationEnabled || isSpectating || replayMode) return 0;
    if (window.matchMedia && window.matchMedia('(prefers-reduced-motion: reduce)').matches) return 0;
    const source = document.querySelector(`#you-hand .card[data-instance-id="${cardInstanceId}"], .classic-hand .card[data-instance-id="${cardInstanceId}"], .card[data-instance-id="${cardInstanceId}"]`);
    if (!source) return 0;
    const sourceRect = source.getBoundingClientRect();
    if (!sourceRect || sourceRect.width <= 2 || sourceRect.height <= 2) return 0;
    const targetEl = options.targetElement || getPlayGestureFallbackTarget();
    const targetRect = targetEl && targetEl.getBoundingClientRect ? targetEl.getBoundingClientRect() : null;
    const targetX = targetRect && targetRect.width > 0
        ? targetRect.left + targetRect.width * 0.5
        : window.innerWidth * 0.5;
    const targetY = targetRect && targetRect.height > 0
        ? targetRect.top + targetRect.height * 0.5
        : window.innerHeight * 0.42;
    const startX = sourceRect.left + sourceRect.width * 0.58;
    const startY = sourceRect.top + sourceRect.height * 0.5;
    const cardStartX = sourceRect.left;
    const cardStartY = sourceRect.top;
    const cardEndX = targetX - sourceRect.width * 0.5;
    const cardEndY = targetY - sourceRect.height * 0.5;
    const cursor = createVirtualWindowsCursor();
    const clone = source.cloneNode(true);
    clone.classList.add('virtual-play-card');
    clone.style.left = `${cardStartX}px`;
    clone.style.top = `${cardStartY}px`;
    clone.style.width = `${sourceRect.width}px`;
    clone.style.height = `${sourceRect.height}px`;
    clone.style.setProperty('--gesture-card-dx', `${cardEndX - cardStartX}px`);
    clone.style.setProperty('--gesture-card-dy', `${cardEndY - cardStartY}px`);
    cursor.style.left = `${startX}px`;
    cursor.style.top = `${startY}px`;
    cursor.style.setProperty('--gesture-cursor-dx', `${targetX - startX}px`);
    cursor.style.setProperty('--gesture-cursor-dy', `${targetY - startY}px`);
    document.body.append(clone, cursor);
    source.classList.add('virtual-play-source');
    const canMarkTarget = targetEl && targetEl.classList && targetEl !== document.body && targetEl !== document.documentElement;
    if (canMarkTarget) targetEl.classList.add('virtual-play-target');
    const duration = 680;
    setTimeout(() => {
        clone.remove();
        cursor.remove();
        source.classList.remove('virtual-play-source');
        if (canMarkTarget) targetEl.classList.remove('virtual-play-target');
    }, duration + 80);
    return duration;
}

function animateFusionMerge(fusionCardId, targetIds = [], options = {}) {
    const startDelay = Number(options.startDelay || 0);
    const fusionEl = document.querySelector(`.card[data-instance-id="${fusionCardId}"]`);
    if (!fusionEl || !Array.isArray(targetIds) || !targetIds.length) {
        animatePlayedCard(fusionCardId);
        return;
    }
    const fusionRect = fusionEl.getBoundingClientRect();
    const centerX = fusionRect.left + fusionRect.width / 2;
    const centerY = fusionRect.top + fusionRect.height / 2;
    const clones = [];
    targetIds.slice(0, 3).forEach((id, index) => {
        const source = document.querySelector(`.card[data-instance-id="${id}"]`);
        if (!source) return;
        const rect = source.getBoundingClientRect();
        const clone = source.cloneNode(true);
        clone.classList.add('fusion-merge-clone');
        clone.style.left = `${rect.left}px`;
        clone.style.top = `${rect.top}px`;
        clone.style.width = `${rect.width}px`;
        clone.style.setProperty('--fusion-dx', `${centerX - (rect.left + rect.width / 2)}px`);
        clone.style.setProperty('--fusion-dy', `${centerY - (rect.top + rect.height / 2)}px`);
        clone.style.animationDelay = `${startDelay + index * 55}ms`;
        document.body.appendChild(clone);
        clones.push(clone);
    });
    const pulse = fusionEl.cloneNode(true);
    pulse.classList.add('fusion-core-pulse');
    pulse.style.left = `${fusionRect.left}px`;
    pulse.style.top = `${fusionRect.top}px`;
    pulse.style.width = `${fusionRect.width}px`;
    pulse.style.animationDelay = `${startDelay + Math.min(180, clones.length * 55 + 40)}ms`;
    document.body.appendChild(pulse);
    lockCardAnimation(startDelay + 680);
    setTimeout(() => {
        clones.forEach(el => el.remove());
        pulse.remove();
    }, startDelay + 780);
}

function animateEquipmentForRegion(selector) {
    const region = document.querySelector(selector);
    if (!region) return;
    const items = region.querySelectorAll('.equip-item, .equip-card, .btn-equip-trigger');
    const item = items[items.length - 1];
    if (!item) return;
    item.classList.remove('equip-pop-in');
    void item.offsetWidth;
    item.classList.add('equip-pop-in');
    setTimeout(() => item.classList.remove('equip-pop-in'), 520);
}

function cardChoiceIdentity(card) {
    if (!card) return '';
    const sortList = (list) => (Array.isArray(list) ? [...list].sort() : []).join(',');
    const cardDef = getCardDef(card.def_id || '');
    const flagSets = getEffectiveCardFlagSets(card, cardDef);
    const effectiveFlags = Array.from(flagSets.effective || []);
    const addedFlags = Array.from(flagSets.added || []);
    const disabledFlags = Array.from(flagSets.disabled || []);
    return [
        card.def_id || '',
        Number(card.fusion_level || 1),
        Number(card.fission_level || 1),
        card.cost_e_override == null ? '' : card.cost_e_override,
        card.cost_m_override == null ? '' : card.cost_m_override,
        sortList(effectiveFlags),
        sortList(addedFlags),
        sortList(disabledFlags),
        Number(card.bonus_damage || 0),
        Number(card.held_turns || 0),
        Number(card.return_to_hand_turns || 0),
        Number(card.mimic_discount || 0),
        Number(card.swift_value || 0),
        Number(card.magic_swift_value || 0),
        Number(card.power_value || 0),
        Number(card.temp_swift_value || 0),
        Number(card.temp_heavy_value || 0),
        Number(card.temp_magic_heavy_value || 0),
        Number(card.charge_value || 0),
        Number(card.hand_blind_turns || 0),
        Number(card.extra_hits || 0),
        sortList(card.setup_modifiers),
    ].join('|');
}

function shuffledCardChoiceGroups(cards) {
    const groups = new Map();
    (Array.isArray(cards) ? cards : []).forEach(card => {
        const key = cardChoiceIdentity(card);
        const group = groups.get(key) || [];
        group.push(card);
        groups.set(key, group);
    });
    const result = Array.from(groups.values());
    for (let i = result.length - 1; i > 0; i--) {
        const j = Math.floor(Math.random() * (i + 1));
        [result[i], result[j]] = [result[j], result[i]];
    }
    return result;
}

function isCompassChoiceCard(card, cardDef) {
    return cardMatchesAnyLocalId(card || {}, cardDef, ['Compass'])
        || !!(cardDef && (cardDef.name_cn === 'жҢҮеҚ—й’Ҳ' || cardDef.name_en === 'Compass'));
}

function compassDeckChoiceOptions(cards) {
    const groups = shuffledCardChoiceGroups(cards);
    const options = groups.map(group => cardChoiceOption(group[0], {
        detail: `x${group.length}`,
    }));
    return { groups, options };
}

function dedupeCardCombos(combos) {
    const seen = new Set();
    const result = [];
    combos.forEach(combo => {
        const key = combo.map(cardChoiceIdentity).sort().join(' + ');
        if (seen.has(key)) return;
        seen.add(key);
        result.push(combo);
    });
    return result;
}

function buildFusionCombosForGroup(group) {
    const combos = [];
    for (let i = 0; i < group.length; i++) {
        for (let j = i + 1; j < group.length; j++) {
            combos.push([group[i], group[j]]);
        }
    }
    return dedupeCardCombos(combos);
}

async function onPlayCard(cardInstanceId, options = {}) {
    if (isSpectating) return;
    if (!canSendGameAction('play_card')) return;
    const hand = (gameState.you || {}).hand || [];
    const cardDict = hand.find(c => c.instance_id === cardInstanceId);
    if (!cardDict) return;
    if (!canPlayCard(cardDict)) {
        flashStatus(getCannotPlayReason(cardDict), 2600, 'error');
        return;
    }
    if (isTouchPlayMode() && !options.confirmed && !options.dragDrop) {
        selectPlayCardForConfirm(cardInstanceId);
        return;
    }
    const cardDef = getCardDef(cardDict.def_id);
    if (cardDef && cardDef.card_type === 'thorn' && gameState && gameState.mode !== '2v2') {
        const opponent = gameState.opponent || {};
        const flags = getEffectiveCardFlagSets(cardDict || {}, cardDef || {}).effective;
        if (!flags.has('self_target') && !flags.has('wide_strike') && isPlayerUntargetable(opponent)) {
            flashStatus(UI.no_selectable_player || 'жІЎжңүеҸҜйҖүдёӯзҡ„зҺ©е®¶', 2200, 'error');
            return;
        }
    }
    let targetPlayerId = normalizePlayerId(options.targetPlayerId ?? options.target_player_id);
    if (targetPlayerId == null) targetPlayerId = -1;
    const forcedTargetPlayerId = getForcedTargetForCard(cardDef, cardDict);
    if (forcedTargetPlayerId != null) {
        targetPlayerId = forcedTargetPlayerId;
    } else if (cardHasSelfOnlyFlag(cardDict, cardDef) && (!cardDef || cardDef.card_type !== 'thorn')) {
        targetPlayerId = normalizePlayerId(gameState.your_id);
    } else if (cardNeedsPlayerTarget(cardDef, cardDict) && targetPlayerId < 0) {
        if (tutorialMode) tutorialTargetHintSeen = true;
        targetPlayerId = await choosePlayerTarget(
            UI.choose_target || UI.select_target || 'Choose target',
            getCardTargetPickOptions(cardDef, cardDict),
        );
        if (targetPlayerId < 0) return;
    }
    const choice = await getCardChoice(cardDict, targetPlayerId);
    if (choice === false) return;
    clearSelectedPlayCard();
    const shouldShatterAfterPlay = cardHasExileLikeExit(cardDict);
    if (shouldShatterAfterPlay) markRecentlyPlayedExileCard(cardDict);
    const optimisticCost = getOptimisticResourceCost(cardDict, gameState && gameState.you);
    const optimisticResources = buildOptimisticResourceOverride(cardDict, gameState && gameState.you, optimisticCost);
    queueLocalResourceCost(cardDict, gameState && gameState.you, { shownOptimistically: !!optimisticResources });
    const playedTargetElement = getClassicPlayedCardAnimationTarget(cardDict, cardDef, targetPlayerId);
    const playGestureDelay = animateVirtualPlayGesture(cardInstanceId, {
        targetElement: playedTargetElement,
    });
    if (cardDict.def_id === 'Fusion' && choice && Array.isArray(choice.target_instance_ids)) {
        animateFusionMerge(cardInstanceId, choice.target_instance_ids, { startDelay: playGestureDelay || 300 });
    } else {
        animatePlayedCard(cardInstanceId, {
            shatterAfter: shouldShatterAfterPlay,
            targetElement: playedTargetElement,
            startDelay: playGestureDelay,
        });
    }
    pendingPlayCard = cardDict;
    renderPendingCard();
    beginPendingServerAction('play_card', { optimisticResources, timeoutMs: SERVER_ACTION_TIMEOUT_MS });
    emitModeEvent('solo_play_card', 'play_card', { card_instance_id: cardInstanceId, choice, target_player_id: targetPlayerId });
}

async function getCardChoice(cardDict, targetPlayerId = -1) {
    const defId = cardDict.def_id;
    const sourceCardDef = getCardDef(defId);
    const sourceCardName = sourceCardDef ? getBlindedCardDisplayName(cardDict, sourceCardDef) : '';
    const hand = (gameState.you || {}).hand || [];
    if (defId === 'Fission') {
        const attacks = hand.filter(c => {
            const cd = getCardDef(c.def_id);
            return cd && cd.card_type === 'thorn' && c.instance_id !== cardDict.instance_id;
        });
        if (!attacks.length) { gameAlert(UI.notice, UI.no_attack_cards); return false; }
        const options = attacks.map(a => cardChoiceOption(a));
        const sel = await simpleChoice(UI.choose_attack_for.replace('{0}', sourceCardName), options);
        if (sel < 0) return false;
        return { target_instance_id: attacks[sel].instance_id, target_instance_ids: [attacks[sel].instance_id] };
    } else if (defId === 'Fusion') {
        const attacks = hand.filter(c => {
            const cd = getCardDef(c.def_id);
            return cd && cd.card_type === 'thorn' && c.instance_id !== cardDict.instance_id;
        });
        const groups = {};
        attacks.forEach(a => {
            const g = groups[a.def_id] || (groups[a.def_id] = []);
            g.push(a);
        });
        const validGroups = Object.entries(groups).filter(([_, v]) => v.length >= 2);
        if (!validGroups.length) { gameAlert(UI.notice, UI.no_same_attack); return false; }
        let group = validGroups[0][1];
        if (validGroups.length > 1) {
            const groupOptions = validGroups.map(([k, v]) => cardChoiceOption(v[0], { detail: `x${v.length}` }));
            const sel = await simpleChoice(UI.choose_attack_group_for.replace('{0}', sourceCardName), groupOptions);
            if (sel < 0) return false;
            group = validGroups[sel][1];
        }
        const uniqueCombos = buildFusionCombosForGroup(group);
        const comboOptions = uniqueCombos.map(combo => cardComboChoiceOption(combo));
        const comboSel = await simpleChoice(UI.choose_attack_group_for.replace('{0}', sourceCardName), comboOptions);
        if (comboSel < 0) return false;
        return { target_instance_ids: uniqueCombos[comboSel].map(c => c.instance_id) };
    } else if (isMimicCardDict(cardDict)) {
        const others = hand.filter(c => c.instance_id !== cardDict.instance_id && !cardHasSublimeFlag(c));
        if (!others.length) { gameAlert(UI.notice, UI.no_attack_cards); return false; }
        const options = others.map(c => mimicCardChoiceOption(c, cardDict, gameState && gameState.you));
        const sel = await simpleChoice(UI.choose_hand_for.replace('{0}', sourceCardName), options);
        if (sel < 0) return false;
        return { target_instance_id: others[sel].instance_id };
    } else if (defId === 'Chromosome') {
        const discard = ((gameState.you || {}).discard || []).filter(c => !cardHasSublimeFlag(c));
        if (!discard.length) { gameAlert(UI.notice, UI.discard_empty); return false; }
        const options = discard.map(c => cardChoiceOption(c));
        const sel = await simpleChoice(UI.choose_from_discard_for.replace('{0}', sourceCardName), options);
        if (sel < 0) return false;
        return { target_instance_id: discard[sel].instance_id, target_def_id: discard[sel].def_id };
    } else if (defId === 'Sewage') {
        const targetData = targetPlayerId >= 0 ? getPlayerDataById(targetPlayerId) : (gameState.opponent || {});
        const oppEq = targetData.equipment || [];
        const destroyable = oppEq.filter(e => {
            const cd = getCardDef((e.card_instance || {}).def_id);
            if (!cd) return false;
            const inst = e.card_instance || {};
            const flags = new Set([...(cd.flags || []), ...(inst.instance_flags || [])]);
            (inst.disabled_flags || []).forEach(flag => flags.delete(flag));
            return !flags.has('indestructible');
        });
        if (!destroyable.length) { gameAlert(UI.notice, UI.no_enemy_equipment); return false; }
        const options = destroyable.map(e => equipmentChoiceOption(e));
        const sel = await simpleChoice(UI.choose_equip_for.replace('{0}', sourceCardName), options);
        if (sel < 0) return false;
        return { target_instance_id: destroyable[sel].card_instance.instance_id };
    } else if (defId === 'Chilli') {
        const others = hand.filter(c => c.instance_id !== cardDict.instance_id);
        if (others.length) {
            const options = others.map(c => cardChoiceOption(c));
            const sel = await simpleChoice(UI.choose_discard_for.replace('{0}', sourceCardName), options);
            if (sel < 0) return false;
            return { target_instance_id: others[sel].instance_id };
        }
        return null;
    }
    return null;
}

async function simpleChoice(title, options, config = {}) {
    if (!options.length) return -1;
    return await gamePrompt(title, options, { ...config, numbered: config.numbered !== false });
}

function multiChoice(title, options, config = {}) {
    return new Promise((resolve) => {
        const el = $('game-prompt');
        if (!el) { resolve([]); return; }
        if (!options.length) { resolve([]); return; }
        cleanupGamePromptTransientButtons();
        const min = Number(config.min ?? config.min_count ?? 1);
        const max = Number(config.max || config.max_count || options.length);
        const cancellable = config.cancellable !== false;
        $('game-prompt-title').textContent = title || '';
        const optsEl = $('game-prompt-options');
        containPromptScroll(optsEl);
        let msgEl = $('game-prompt-message');
        if (!msgEl) {
            msgEl = document.createElement('div');
            msgEl.id = 'game-prompt-message';
            msgEl.className = 'game-prompt-message';
            optsEl.parentNode.insertBefore(msgEl, optsEl);
        }
        const message = config.message || config.content || '';
        msgEl.textContent = message;
        msgEl.classList.toggle('hidden', !message);
        optsEl.innerHTML = '';
        const selected = new Set();
        const confirmBtn = document.createElement('button');
        confirmBtn.className = 'btn btn-primary game-prompt-transient-btn';
        const updateConfirm = () => {
            const count = selected.size;
            const ok = count >= min && count <= max;
            confirmBtn.classList.toggle('disabled', !ok);
            confirmBtn.textContent = `${config.confirmText || UI.ok || 'зЎ®е®ҡ'} (${count}/${min}-${max})`;
        };
        options.forEach((opt, i) => {
            const div = document.createElement('div');
            div.className = 'game-prompt-option';
            renderChoiceOptionContent(div, opt, i, { ...config, numbered: true });
            div.onclick = () => {
                if (selected.has(i)) {
                    selected.delete(i);
                } else {
                    if (selected.size >= max) return;
                    selected.add(i);
                }
                div.classList.toggle('selected', selected.has(i));
                updateConfirm();
            };
            optsEl.appendChild(div);
        });
        const finish = (value) => {
            removeFloatingCardPreview();
            el.classList.remove('active');
            cleanupGamePromptTransientButtons();
            resolve(value);
        };
        confirmBtn.onclick = () => {
            if (confirmBtn.classList.contains('disabled')) return;
            finish(Array.from(selected).sort((a, b) => a - b));
        };
        // Place confirm button next to cancel button in the buttons row
        const cancelBtn = $('game-prompt-cancel');
        cancelBtn.textContent = UI.cancel;
        cancelBtn.classList.toggle('hidden', !cancellable);
        cancelBtn.style.display = cancellable ? '' : 'none';
        cancelBtn.onclick = () => finish([]);
        // Insert confirm after cancel in the buttons row
        const buttonsRow = cancelBtn.parentNode;
        buttonsRow.appendChild(confirmBtn);
        updateConfirm();
        el.classList.add('active');
    });
}

function showResponseUI(data) {
    if (isSpectating) return;
    removeFloatingCardPreview();
    const counterCards = data.counter_cards || [];
    const you = gameState.you || {};
    const myElixir = you.elixir || 0;
    const myMagic = you.magic || 0;
    debugLog('[RESPONSE] showResponseUI: counterCards=', counterCards.length, 'myElixir=', myElixir, 'myMagic=', myMagic);
    if (!counterCards.length) {
        debugLog('[RESPONSE] no counter cards, auto pass');
        onRespond(null);
        return;
    }
    let hasAffordable = false;
    const cardCosts = counterCards.map(cc => {
        const ccDef = getCardDef(cc.def_id);
        const displayCosts = ccDef
            ? getCardDisplayCosts(cc, ccDef, you)
            : { totalE: Number(cc.cost_e || cc.cost_e_override || 0), totalM: Number(cc.cost_m || cc.cost_m_override || 0) };
        const costE = Math.max(0, Math.floor(Number(displayCosts.totalE || 0)));
        const costM = Math.max(0, Math.floor(Number(displayCosts.totalM || 0)));
        const canAfford = costE <= myElixir && costM <= myMagic;
        if (canAfford) hasAffordable = true;
        return { cc, ccDef, costE, costM, canAfford };
    });
    const groupedCardCosts = [];
    const groupedBySignature = new Map();
    cardCosts.forEach(item => {
        const signature = counterCardGroupSignature(item.cc);
        let group = groupedBySignature.get(signature);
        if (!group) {
            group = {
                ...item,
                items: [],
                count: 0,
                canAffordAny: false,
            };
            groupedBySignature.set(signature, group);
            groupedCardCosts.push(group);
        }
        group.items.push(item);
        group.count += 1;
        if (item.canAfford) {
            group.canAffordAny = true;
            if (!group.canAfford) {
                group.cc = item.cc;
                group.ccDef = item.ccDef;
                group.costE = item.costE;
                group.costM = item.costM;
                group.canAfford = item.canAfford;
            }
        }
    });
    if (!hasAffordable) {
        flashStatus(UI.counter_insufficient, 3000);
    }
    const container = $('response-panel');
    if (!container) { onRespond(null); return; }
    container.innerHTML = '';
    container.classList.remove('hidden');
    container.classList.add('visible');
    const cardDict = data.card || {};
    const cardDef = getCardDef(cardDict.def_id);
    const blindLevel = getOwnBlindLevel();
    const hideResponsePrediction = blindLevel >= 2;
    let triggerDesc = '';
    if (cardDef) {
        if (cardDef.card_type === 'thorn') triggerDesc = UI.enemy_attack;
        else if (cardDef.card_type === 'bloom') triggerDesc = UI.enemy_skill;
        if (cardDef.id === 'Sewage' || cardDef.id === 'MagicSewage') triggerDesc += UI.enemy_destroy_equip;
    }
    const responseWindowDef = cardCosts.map(item => item.ccDef).find(cd => cd && (cd.response_title || cd.response_content));
    const localizedResponseTitle = responseWindowDef
        ? getLocalizedCardText(responseWindowDef, 'response_title_i18n', 'response_title')
        : '';
    if (localizedResponseTitle) {
        const title = document.createElement('div');
        title.className = 'response-label response-title';
        title.textContent = localizedResponseTitle;
        container.appendChild(title);
    }
    const label = document.createElement('div');
    label.className = 'response-label response-trigger-label';
    const prefix = document.createElement('span');
    prefix.className = 'response-trigger-prefix';
    prefix.textContent = triggerDesc ? `${triggerDesc}:` : '';
    if (prefix.textContent) label.appendChild(prefix);
    label.appendChild(createCardChoiceChip(cardDict, blindLevel > 0 ? { blindForSelf: true, blindLevel } : {}));
    const prediction = data.damage_prediction || {};
    const noCounterPrediction = prediction.no_counter || {};
    const baseEffectPrediction = getResponseBaseEffectPrediction(data, cardDict, noCounterPrediction);
    if (!hideResponsePrediction) appendResponseEffectPreview(label, baseEffectPrediction);
    container.appendChild(label);
    const localizedResponseContent = responseWindowDef
        ? getLocalizedCardText(responseWindowDef, 'response_content_i18n', 'response_content')
        : '';
    if (localizedResponseContent) {
        const content = document.createElement('div');
        content.className = 'response-label response-content';
        content.textContent = localizedResponseContent;
        container.appendChild(content);
    }
    const btnRow = document.createElement('div');
    btnRow.className = 'response-btn-row';
    groupedCardCosts.forEach(({ cc, ccDef, costE, costM, canAffordAny, count }) => {
        if (!ccDef) return;
        const btn = document.createElement('button');
        btn.className = 'btn counter-card-btn ' + (canAffordAny ? 'btn-primary' : 'btn-counter-disabled');
        btn.appendChild(createCardChoiceChip(cc));
        if (count > 1) {
            const countEl = document.createElement('span');
            countEl.className = 'counter-card-count';
            countEl.textContent = `Г—${count}`;
            btn.appendChild(countEl);
        }
        const cost = document.createElement('span');
        cost.className = 'counter-card-cost';
        cost.innerHTML = blindLevel > 0 ? '[?]' : renderResourceCostInline(costE, costM, { bracket: true });
        btn.appendChild(cost);
        if (!hideResponsePrediction) {
            const counterPrediction = prediction.counters && prediction.counters[String(cc.instance_id)];
            const statusReduction = getResponseCounterStatusReduction(data, cardDict, baseEffectPrediction, counterPrediction, cc);
            appendCounterEffectReductions(btn, {
                damage: Math.max(0, Number(counterPrediction && counterPrediction.reduction || 0)),
                damageText: counterPrediction && counterPrediction.reduction_display,
                poison: statusReduction.poison,
                fire: statusReduction.fire,
            });
        }
        btn.disabled = !canAffordAny;
        btn.onclick = () => onRespond(cc.instance_id);
        btnRow.appendChild(btn);
    });
    container.appendChild(btnRow);
    responseCountdown = tutorialMode ? 10 : (hasAffordable ? 5 : 2);
    const passBtn = document.createElement('button');
    passBtn.className = 'btn btn-danger';
    passBtn.id = 'pass-btn';
    passBtn.textContent = UI.no_counter_countdown.replace('{0}', responseCountdown);
    passBtn.onclick = () => onRespond(null);
    container.appendChild(passBtn);
    if (responseTimerId) clearInterval(responseTimerId);
    responseTimerId = setInterval(() => {
        responseCountdown--;
        if (responseCountdown <= 0) {
            onRespond(null);
            return;
        }
        const pb = $('pass-btn');
        if (pb) pb.textContent = UI.no_counter_countdown.replace('{0}', responseCountdown);
    }, 1000);
}

function onRespond(cardInstanceId) {
    if (!canSendGameAction('response', { includeAnimation: false })) return;
    removeFloatingCardPreview();
    if (responseTimerId) { clearInterval(responseTimerId); responseTimerId = null; }
    responsePending = false;
    if (tutorialMode) tutorialCounterSeen = true;
    if (cardInstanceId != null) {
        const hand = (gameState.you || {}).hand || [];
        const cardDict = hand.find(c => c.instance_id === cardInstanceId);
        const shouldShatterAfterPlay = cardHasExileLikeExit(cardDict);
        if (shouldShatterAfterPlay) markRecentlyPlayedExileCard(cardDict);
        const optimisticCost = getOptimisticResourceCost(cardDict, gameState && gameState.you);
        const optimisticResources = buildOptimisticResourceOverride(cardDict, gameState && gameState.you, optimisticCost);
        queueLocalResourceCost(cardDict, gameState && gameState.you, { shownOptimistically: !!optimisticResources });
        animatePlayedCard(cardInstanceId, { shatterAfter: shouldShatterAfterPlay });
        beginPendingServerAction('response', { optimisticResources, timeoutMs: SERVER_ACTION_TIMEOUT_MS });
    } else {
        beginPendingServerAction('response', { timeoutMs: SERVER_ACTION_TIMEOUT_MS });
    }
    const container = $('response-panel');
    if (container) { container.innerHTML = ''; container.classList.add('hidden'); container.classList.remove('visible'); }
    emitModeEvent('solo_response', 'response', { card_instance_id: cardInstanceId });
}

function showMagicSaltReflectResponseUI(data = {}, choiceParams = {}) {
    removeFloatingCardPreview();
    const container = $('response-panel');
    if (!container) {
        return Promise.resolve({ confirmed: false, accepted: false });
    }
    const cardDict = data.card || choiceParams.card || { def_id: 'MagicSalt' };
    const you = gameState && gameState.you ? gameState.you : {};
    const costM = Math.max(0, Math.floor(Number(choiceParams.cost_m || 1)));
    const canAfford = Math.max(0, Number(you.magic || 0)) >= costM;
    const reflect = Math.max(0, Math.ceil(Number(choiceParams.reflect || 0)));
    const attackerId = normalizePlayerId(choiceParams.attacker_id);
    const attacker = attackerId == null ? null : getPlayerDataById(attackerId);
    const attackerName = attacker && attacker.name ? attacker.name : (choiceParams.attacker_name || '');

    container.innerHTML = '';
    container.classList.remove('hidden');
    container.classList.add('visible', 'magic-salt-response-panel');

    const title = document.createElement('div');
    title.className = 'response-label response-title';
    title.textContent = choiceParams.title || 'йӯ”жі•зӣҗ';
    container.appendChild(title);

    const label = document.createElement('div');
    label.className = 'response-label response-trigger-label';
    const prefix = document.createElement('span');
    prefix.className = 'response-trigger-prefix';
    prefix.textContent = attackerName
        ? `${attackerName}йҖ жҲҗдјӨе®іеҗҺеҸҜи§ҰеҸ‘:`
        : 'еҸ—еҲ°дјӨе®іеҗҺеҸҜи§ҰеҸ‘:';
    label.appendChild(prefix);
    label.appendChild(createCardChoiceChip(cardDict));
    if (reflect > 0) {
        const preview = document.createElement('span');
        preview.className = 'counter-damage-reduction magic-salt-reflect-preview';
        preview.textContent = `еҸҚеј№${reflect}D`;
        label.appendChild(preview);
    }
    container.appendChild(label);

    const btnRow = document.createElement('div');
    btnRow.className = 'response-btn-row';

    const useBtn = document.createElement('button');
    useBtn.className = 'btn counter-card-btn ' + (canAfford ? 'btn-primary' : 'btn-counter-disabled');
    useBtn.appendChild(createCardChoiceChip(cardDict));
    const cost = document.createElement('span');
    cost.className = 'counter-card-cost';
    cost.innerHTML = renderResourceCostInline(0, costM, { bracket: true });
    useBtn.appendChild(cost);
    if (reflect > 0) {
        const effect = document.createElement('span');
        effect.className = 'counter-damage-reduction magic-salt-reflect-preview';
        effect.textContent = `еҸҚеј№${reflect}D`;
        useBtn.appendChild(effect);
    }
    useBtn.disabled = !canAfford;
    btnRow.appendChild(useBtn);
    container.appendChild(btnRow);

    const passBtn = document.createElement('button');
    passBtn.className = 'btn btn-danger';
    passBtn.textContent = choiceParams.cancel_text || 'дёҚи§ҰеҸ‘';
    container.appendChild(passBtn);

    return new Promise(resolve => {
        const finish = (accepted) => {
            removeFloatingCardPreview();
            container.innerHTML = '';
            container.classList.add('hidden');
            container.classList.remove('visible', 'magic-salt-response-panel');
            resolve({ confirmed: !!accepted, accepted: !!accepted });
        };
        useBtn.onclick = () => {
            if (!canAfford) return;
            finish(true);
        };
        passBtn.onclick = () => finish(false);
    });
}

