async function showReorderDeckUI(deckCards, titleText, config = {}) {
    const modal = $('modal');
    const content = $('modal-content');
    if (!modal || !content) return null;
    const cancellable = config.cancellable !== false;
    removeFloatingCardPreview();
    const order = deckCards.map(c => c.instance_id);
    content.className = 'modal-inner view-deck-modal';
    content.innerHTML = '';
    const title = document.createElement('h3');
    title.textContent = titleText;
    content.appendChild(title);
    const hint = document.createElement('p');
    hint.className = 'deck-total';
    hint.textContent = 'жӢ–жӢҪдёүжЁӘзәҝи°ғж•ҙйЎәеәҸпјҲжңҖдёҠж–№е…ҲжҠҪеҲ°пјү';
    content.appendChild(hint);
    const list = document.createElement('div');
    list.className = 'deck-list reorder-deck-list';

    // Build rows
    const rows = [];
    deckCards.forEach((c, idx) => {
        const row = document.createElement('div');
        row.className = 'reorder-deck-entry';
        row.dataset.idx = idx;
        // Drag handle (hamburger icon)
        const handle = document.createElement('span');
        handle.className = 'reorder-handle';
        handle.innerHTML = '&#9776;';
        handle.setAttribute('aria-label', 'жӢ–жӢҪжҺ’еәҸ');
        row.appendChild(handle);
        row.appendChild(createCardChoiceChip(c));
        const numEl = document.createElement('span');
        numEl.className = 'choice-option-detail deck-entry-count reorder-deck-num';
        numEl.textContent = `#${idx + 1}`;
        row.appendChild(numEl);
        list.appendChild(row);
        rows.push(row);
    });

    // Pointer-based smooth drag reorder
    let dragRow = null;
    let dragOffsetY = 0;
    let placeholder = null;
    let dragClone = null;
    let dragHandle = null;
    let dragPointerId = null;

    function rebuildOrderNumbers() {
        const currentRows = list.querySelectorAll('.reorder-deck-entry:not(.reorder-clone)');
        order.length = 0;
        currentRows.forEach((el, i) => {
            el.dataset.idx = i;
            const num = el.querySelector('.reorder-deck-num');
            if (num) num.textContent = `#${i + 1}`;
            const origIdx = rows.indexOf(el);
            if (origIdx >= 0) order.push(deckCards[origIdx].instance_id);
        });
    }

    function removeDragListeners() {
        document.removeEventListener('pointermove', moveDrag);
        document.removeEventListener('pointerup', endDrag);
        document.removeEventListener('pointercancel', cancelDrag);
        window.removeEventListener('blur', cancelDrag);
    }

    function cleanupDrag(commit) {
        const row = dragRow;
        const ph = placeholder;
        const clone = dragClone;
        const handle = dragHandle;
        const pointerId = dragPointerId;
        removeDragListeners();
        if (handle && pointerId !== null && typeof handle.releasePointerCapture === 'function') {
            try {
                if (handle.hasPointerCapture && handle.hasPointerCapture(pointerId)) {
                    handle.releasePointerCapture(pointerId);
                }
            } catch (_) {}
        }
        if (row) {
            if (commit && ph && ph.parentNode === list) {
                list.insertBefore(row, ph);
            }
            row.classList.remove('reorder-dragging');
            row.style.visibility = '';
        }
        if (ph && ph.parentNode) ph.remove();
        if (clone && clone.parentNode) clone.remove();
        document.querySelectorAll('.reorder-clone').forEach(el => {
            if (el !== clone) el.remove();
        });
        dragRow = null;
        dragClone = null;
        placeholder = null;
        dragHandle = null;
        dragPointerId = null;
        if (commit) rebuildOrderNumbers();
    }

    function moveDrag(e) {
        if (!dragRow || !dragClone) return;
        if (dragPointerId !== null && e.pointerId !== dragPointerId) return;
        e.preventDefault();
        dragClone.style.top = (e.clientY - dragOffsetY) + 'px';

        const listRect = list.getBoundingClientRect();
        const scrollBand = Math.min(48, Math.max(28, listRect.height * 0.16));
        if (e.clientY < listRect.top + scrollBand) {
            list.scrollTop -= 10;
        } else if (e.clientY > listRect.bottom - scrollBand) {
            list.scrollTop += 10;
        }

        // Find insertion point among current visible rows (skip placeholder & dragging row)
        let insertBefore = null;
        const children = list.children;
        for (let i = 0; i < children.length; i++) {
            const child = children[i];
            if (child === placeholder || child === dragRow) continue;
            const rect = child.getBoundingClientRect();
            if (rect.top + rect.height / 2 > e.clientY) {
                insertBefore = child;
                break;
            }
        }

        if (insertBefore) {
            list.insertBefore(placeholder, insertBefore);
        } else {
            list.appendChild(placeholder);
        }
    }

    function endDrag() {
        if (!dragRow) return;
        cleanupDrag(true);
    }

    function cancelDrag() {
        if (!dragRow) return;
        cleanupDrag(false);
    }

    rows.forEach(row => {
        const handle = row.querySelector('.reorder-handle');
        handle.addEventListener('pointerdown', e => {
            if (e.button !== undefined && e.button !== 0) return;
            if (dragRow) cleanupDrag(false);
            e.preventDefault();
            e.stopPropagation();
            const rect = row.getBoundingClientRect();
            dragRow = row;
            dragHandle = handle;
            dragPointerId = e.pointerId;
            dragOffsetY = e.clientY - rect.top;
            if (typeof handle.setPointerCapture === 'function') {
                try { handle.setPointerCapture(e.pointerId); } catch (_) {}
            }

            // Create placeholder at current position
            placeholder = document.createElement('div');
            placeholder.className = 'reorder-placeholder';
            placeholder.style.height = rect.height + 'px';
            list.insertBefore(placeholder, row);

            // Hide original row (remove from flow)
            row.classList.add('reorder-dragging');
            row.style.visibility = 'hidden';

            // Create floating clone
            dragClone = row.cloneNode(true);
            dragClone.className = 'reorder-deck-entry reorder-clone';
            dragClone.style.position = 'fixed';
            dragClone.style.left = rect.left + 'px';
            dragClone.style.top = rect.top + 'px';
            dragClone.style.width = rect.width + 'px';
            dragClone.style.zIndex = '10000';
            dragClone.style.pointerEvents = 'none';
            dragClone.style.touchAction = 'none';
            document.body.appendChild(dragClone);

            document.addEventListener('pointermove', moveDrag, { passive: false });
            document.addEventListener('pointerup', endDrag);
            document.addEventListener('pointercancel', cancelDrag);
            window.addEventListener('blur', cancelDrag);
        });
    });

    content.appendChild(list);
    const buttons = document.createElement('div');
    buttons.className = 'modal-buttons';
    const confirmBtn = document.createElement('button');
    confirmBtn.className = 'btn btn-primary';
    confirmBtn.textContent = UI.ok || 'зЎ®е®ҡ';
    confirmBtn.onclick = () => {
        cleanupDrag(false);
        modal.classList.add('hidden');
        modal.classList.remove('active');
    };
    const cancelBtn = document.createElement('button');
    cancelBtn.className = 'btn btn-danger';
    cancelBtn.textContent = UI.cancel || 'еҸ–ж¶Ҳ';
    cancelBtn.onclick = () => {
        cleanupDrag(false);
        order.length = 0;
        modal.classList.add('hidden');
        modal.classList.remove('active');
    };
    if (cancellable) buttons.appendChild(cancelBtn);
    buttons.appendChild(confirmBtn);
    content.appendChild(buttons);
    modal.classList.remove('hidden');
    modal.classList.add('active');
    return new Promise(resolve => {
        const checkClosed = () => {
            if (modal.classList.contains('hidden') || !modal.classList.contains('active')) {
                if (order.length > 0) {
                    resolve({ new_order: order });
                } else {
                    resolve(null);
                }
            } else {
                requestAnimationFrame(checkClosed);
            }
        };
        confirmBtn.addEventListener('click', () => setTimeout(checkClosed, 50));
        if (cancellable) cancelBtn.addEventListener('click', () => setTimeout(checkClosed, 50));
    });
}

async function showChoiceUI(data) {
    if (isSpectating) return;
    const requestSeq = data && data._choice_request_seq ? data._choice_request_seq : choiceRequestSeq;
    removeFloatingCardPreview();
    const choiceType = data.choice_type || '';
    const cardDict = data.card || {};
    const cardDef = getCardDef(cardDict.def_id);
    const cardName = cardDef ? (getOwnBlindLevel() > 0 ? '?' : getCardName(cardDef)) : '?';
    const choiceParams = data.choice_params || {};
    const choicePromptConfig = {
        cancellable: choiceParams.cancellable !== false && !(cardDef && (cardDef.flags || []).includes('uncancellable')),
        message: choiceParams.content || choiceParams.message || ''
    };
    const choiceTitle = fallback => choiceParams.title || fallback;
    const choiceTargetId = data.target_player_id != null ? normalizePlayerId(data.target_player_id) : null;
    const choiceTargetData = () => (choiceTargetId != null ? (getPlayerDataById(choiceTargetId) || {}) : (gameState.you || {}));
    let choiceResult = null;
    if (choiceType === 'choose_attack_from_hand') {
        const attacks = ((gameState.you || {}).hand || []).filter(c => {
            const cd = getCardDef(c.def_id);
            return cd && cd.card_type === 'thorn';
        });
        if (!attacks.length) { gameAlert(UI.notice, UI.no_attack_cards); }
        else {
            const options = attacks.map(a => cardChoiceOption(a));
            const sel = await simpleChoice(choiceTitle(UI.choose_attack_for.replace('{0}', cardName)), options, choicePromptConfig);
            if (sel >= 0 && sel < attacks.length) choiceResult = { target_instance_id: attacks[sel].instance_id };
        }
    } else if (choiceType === 'hel_card_suit') {
        const suits = Array.isArray(choiceParams.options) && choiceParams.options.length
            ? choiceParams.options
            : ['heart', 'diamond', 'spade', 'club'];
        const labels = Array.isArray(choiceParams.labels) && choiceParams.labels.length
            ? choiceParams.labels
            : ['вҷҘ зәўжЎғ', 'вҷҰ ж–№зүҮ', 'вҷ  й»‘жЎғ', 'вҷЈ жў…иҠұ'];
        const sel = await simpleChoice(choiceTitle('йҖүжӢ©иҠұиүІ'), labels.map((label, i) => ({
            text: label,
            value: suits[i] || suits[0],
            suit: suits[i] || suits[0],
        })), choicePromptConfig);
        if (sel >= 0 && sel < suits.length) choiceResult = { hel_suit: suits[sel] };
    } else if (choiceType === 'bio_blood_sugar_mode') {
        const modes = Array.isArray(choiceParams.options) && choiceParams.options.length
            ? choiceParams.options
            : ['electric_target', 'physical_target'];
        const labels = Array.isArray(choiceParams.labels) && choiceParams.labels.length
            ? choiceParams.labels
            : [
                'еҜ№зӣ®ж ҮйҖ жҲҗз”өдјӨпјҢеҜ№иҮӘе·ұйҖ жҲҗзү©зҗҶдјӨе®і',
                'еҜ№зӣ®ж ҮйҖ жҲҗзү©зҗҶдјӨе®іпјҢеҜ№иҮӘе·ұйҖ жҲҗз”өдјӨ',
            ];
        const sel = await simpleChoice(choiceTitle('иЎҖзі–пјҡйҖүжӢ©дјӨе®ізұ»еһӢ'), labels.map((label, i) => ({
            text: label,
            value: modes[i] || modes[0],
        })), choicePromptConfig);
        if (sel >= 0 && sel < modes.length) choiceResult = { bio_blood_sugar_mode: modes[sel] };
    } else if (choiceType === 'choose_ocean_sapphire') {
        const targetId = await choosePlayerTarget(choiceTitle(UI.choose_target || UI.select_target || 'Choose target'), {
            includeSelf: true,
            aliveOnly: true,
            candidates: 'all',
        });
        if (targetId >= 0) {
            const attacks = ((gameState.you || {}).hand || []).filter(c => {
                if (!c || c.instance_id === cardDict.instance_id || cardHasSublimeFlag(c)) return false;
                const cd = getCardDef(c.def_id);
                if (!cd || cd.card_type !== 'thorn') return false;
                const { effective } = getEffectiveCardFlagSets(c || {}, cd || {});
                return !effective.has('unique') && !effective.has('exile');
            });
            if (!attacks.length) {
                gameAlert(UI.notice, UI.no_attack_cards || 'жІЎжңүж”»еҮ»зүҢ');
                choiceResult = { cancelled: true };
            } else {
                const options = attacks.map(a => cardChoiceOption(a));
                const sel = await simpleChoice(choiceTitle(UI.choose_attack_for.replace('{0}', cardName)), options, choicePromptConfig);
                if (sel >= 0 && sel < attacks.length) {
                    choiceResult = {
                        target_player: targetId,
                        target_player_id: targetId,
                        target_id: targetId,
                        target_instance_id: attacks[sel].instance_id,
                    };
                }
            }
        }
    } else if (choiceType === 'choose_enemy_equipment') {
        const oppEq = (gameState.opponent || {}).equipment || [];
        if (!oppEq.length) { gameAlert(UI.notice, UI.no_enemy_equipment); }
        else {
            const options = oppEq.map(e => equipmentChoiceOption(e));
            const sel = await simpleChoice(choiceTitle(UI.choose_equip_for.replace('{0}', cardName)), options, choicePromptConfig);
            if (sel >= 0 && sel < oppEq.length) choiceResult = { target_instance_id: oppEq[sel].card_instance.instance_id };
        }
    } else if (choiceType === 'choose_card_to_discard') {
        const otherCards = ((gameState.you || {}).hand || []).filter(c => (
            c && c.instance_id !== cardDict.instance_id && !cardHasSublimeFlag(c)
        ));
        if (otherCards.length) {
            const options = otherCards.map(c => cardChoiceOption(c));
            const sel = await simpleChoice(choiceTitle(UI.choose_discard_for.replace('{0}', cardName)), options, choicePromptConfig);
            if (sel >= 0 && sel < otherCards.length) choiceResult = { target_instance_id: otherCards[sel].instance_id };
        } else if (choiceParams.continue_on_cancel) {
            choiceResult = { cancelled: true };
        }
    } else if (choiceType === 'choose_card_from_deck') {
        const deck = ((gameState.you || {}).deck || []).filter(c => !cardHasSublimeFlag(c));
        if (!deck.length) {
            gameAlert(UI.notice, UI.deck_empty);
            choiceResult = { cancelled: true };
        }
        else {
            const compassChoice = isCompassChoiceCard(cardDict, cardDef);
            const grouped = compassChoice ? compassDeckChoiceOptions(deck) : null;
            const options = grouped ? grouped.options : deck.map(c => cardChoiceOption(c));
            const sel = await simpleChoice(choiceTitle(UI.choose_from_deck_for.replace('{0}', cardName)), options, choicePromptConfig);
            const selected = grouped ? (grouped.groups[sel] || [])[0] : deck[sel];
            if (sel >= 0 && selected) choiceResult = { target_instance_id: selected.instance_id, target_def_id: selected.def_id };
        }
    } else if (choiceType === 'choose_card_from_discard') {
        const discard = ((gameState.you || {}).discard || []).filter(c => !cardHasSublimeFlag(c));
        if (!discard.length) {
            gameAlert(UI.notice, UI.discard_empty);
            choiceResult = { cancelled: true };
        }
        else {
            const options = discard.map(c => cardChoiceOption(c));
            const sel = await simpleChoice(choiceTitle(UI.choose_from_discard_for.replace('{0}', cardName)), options, choicePromptConfig);
            if (sel >= 0 && sel < discard.length) choiceResult = { target_instance_id: discard[sel].instance_id, target_def_id: discard[sel].def_id };
        }
    } else if (choiceType === 'choose_same_attacks_from_hand') {
        const attacks = ((gameState.you || {}).hand || []).filter(c => {
            const cd = getCardDef(c.def_id);
            return cd && cd.card_type === 'thorn';
        });
        const groups = {};
        attacks.forEach(a => { const g = groups[a.def_id] || (groups[a.def_id] = []); g.push(a); });
        const validGroups = Object.entries(groups).filter(([_, v]) => v.length >= 2);
        if (!validGroups.length) { gameAlert(UI.notice, UI.no_same_attack); }
        else {
            let group = validGroups[0][1];
            let groupAccepted = true;
            if (validGroups.length > 1) {
                const groupOptions = validGroups.map(([k, v]) => cardChoiceOption(v[0], { detail: `x${v.length}` }));
                const sel = await simpleChoice(UI.choose_attack_group_for.replace('{0}', cardName), groupOptions, choicePromptConfig);
                groupAccepted = sel >= 0;
                if (groupAccepted) group = validGroups[sel][1];
            }
            if (groupAccepted) {
                const uniqueCombos = buildFusionCombosForGroup(group);
                const comboOptions = uniqueCombos.map(combo => cardComboChoiceOption(combo));
                const comboSel = await simpleChoice(choiceTitle(UI.choose_attack_group_for.replace('{0}', cardName)), comboOptions, choicePromptConfig);
                if (comboSel >= 0) choiceResult = { target_instance_ids: uniqueCombos[comboSel].map(c => c.instance_id) };
            }
        }
    } else if (choiceType === 'choose_cards_from_hand') {
        const allCards = (choiceTargetData().hand || []).filter(c => (
            !cardHasSublimeFlag(c) && c.instance_id !== cardDict.instance_id
        ));
        const wantedType = choiceParams.card_type || 'any';
        const minCount = Number(choiceParams.min_count ?? 1);
        const maxCount = Math.max(minCount, Number(choiceParams.max_count || minCount));
        const cards = allCards.filter(c => {
            const cd = getCardDef(c.def_id);
            return wantedType === 'any' || (cd && cd.card_type === wantedType);
        });
        if (!cards.length && minCount <= 0) {
            choiceResult = { target_instance_ids: [] };
        } else if (!cards.length) { gameAlert(UI.notice, UI.no_valid_target || 'жІЎжңүеҸҜйҖүжӢ©зҡ„еҚЎзүҢ'); }
        else if (choiceParams.same_name) {
            const groups = {};
            cards.forEach(c => { const g = groups[c.def_id] || (groups[c.def_id] = []); g.push(c); });
            const combos = [];
            const collect = (group, start, picked) => {
                if (picked.length >= minCount) combos.push([...picked]);
                if (picked.length >= maxCount) return;
                for (let i = start; i < group.length; i++) {
                    picked.push(group[i]);
                    collect(group, i + 1, picked);
                    picked.pop();
                }
            };
            Object.values(groups).forEach(group => {
                if (group.length >= minCount) collect(group, 0, []);
            });
            const uniqueCombos = dedupeCardCombos(combos);
            if (!uniqueCombos.length) { gameAlert(UI.notice, UI.no_valid_target || 'жІЎжңүеҸҜйҖүжӢ©зҡ„з»„еҗҲ'); }
            else {
                const options = uniqueCombos.map(combo => cardComboChoiceOption(combo));
                const sel = await simpleChoice(choiceTitle(UI.choose_hand_for.replace('{0}', cardName)), options, choicePromptConfig);
                if (sel >= 0 && sel < uniqueCombos.length) choiceResult = { target_instance_ids: uniqueCombos[sel].map(c => c.instance_id) };
            }
        } else {
            const options = cards.map(c => cardChoiceOption(c));
            const selected = await multiChoice(choiceTitle(UI.choose_hand_for.replace('{0}', cardName)), options, {
                ...choicePromptConfig,
                min: minCount,
                max: maxCount,
            });
            if (selected.length >= minCount) choiceResult = { target_instance_ids: selected.map(i => cards[i].instance_id) };
        }
    } else if (choiceType === 'choose_card_from_hand') {
        const isMimicChoice = isMimicCardDict(cardDict);
        const filter = choiceParams.filter || {};
        let otherCards = (data.hand_cards || choiceTargetData().hand || []).filter(c => (
            !cardHasSublimeFlag(c) &&
            c.instance_id !== cardDict.instance_id &&
            (!isMimicChoice || c.instance_id !== cardDict.instance_id)
        ));
        if (filter.card_type) {
            const allowedTypes = Array.isArray(filter.card_type) ? filter.card_type : [filter.card_type];
            otherCards = otherCards.filter(c => {
                const def = getCardDef(c.def_id);
                return def && allowedTypes.includes(def.card_type);
            });
        }
        if (filter.exclude_current && cardDict.instance_id) {
            otherCards = otherCards.filter(c => c.instance_id !== cardDict.instance_id);
        }
        if (otherCards.length) {
            const options = otherCards.map(c => (
                isMimicChoice
                    ? mimicCardChoiceOption(c, cardDict, gameState && gameState.you)
                    : cardChoiceOption(c)
            ));
            const sel = await simpleChoice(choiceTitle(UI.choose_hand_for.replace('{0}', cardName)), options, choicePromptConfig);
            if (sel >= 0 && sel < otherCards.length) {
                choiceResult = { target_instance_id: otherCards[sel].instance_id };
                if (choiceTargetId != null) choiceResult.target_player_id = choiceTargetId;
            }
        } else {
            const noMatchMsg = filter.card_type ? UI.no_matching_cards || 'жІЎжңүз¬ҰеҗҲжқЎд»¶зҡ„зүҢ' : (UI.no_cards_in_hand || 'жүӢзүҢдёәз©ә');
            gameAlert(UI.notice, noMatchMsg);
        }
    } else if (choiceType === 'choose_from_deck') {
        const deck = (choiceTargetData().deck || []).filter(c => !cardHasSublimeFlag(c));
        if (!deck.length) {
            gameAlert(UI.notice, UI.deck_empty);
            choiceResult = { cancelled: true };
        }
        else {
            const compassChoice = isCompassChoiceCard(cardDict, cardDef);
            const grouped = compassChoice ? compassDeckChoiceOptions(deck) : null;
            const options = grouped ? grouped.options : deck.map(c => cardChoiceOption(c));
            const sel = await simpleChoice(choiceTitle(UI.choose_from_deck_for.replace('{0}', cardName)), options, choicePromptConfig);
            const selected = grouped ? (grouped.groups[sel] || [])[0] : deck[sel];
            if (sel >= 0 && selected) choiceResult = { target_instance_id: selected.instance_id };
        }
    } else if (choiceType === 'choose_from_discard') {
        const discard = (choiceTargetData().discard || []).filter(c => !cardHasSublimeFlag(c));
        if (!discard.length) {
            gameAlert(UI.notice, UI.discard_empty);
            choiceResult = { cancelled: true };
        }
        else {
            const options = discard.map(c => cardChoiceOption(c));
            const sel = await simpleChoice(choiceTitle(UI.choose_from_discard_for.replace('{0}', cardName)), options, choicePromptConfig);
            if (sel >= 0 && sel < discard.length) choiceResult = { target_instance_id: discard[sel].instance_id, target_def_id: discard[sel].def_id };
        }
    } else if (choiceType === 'choose_from_exile') {
        const exile = (choiceTargetData().exile || []).filter(c => !cardHasSublimeFlag(c));
        if (!exile.length) {
            gameAlert(UI.notice, UI.no_valid_target || 'ж— еҸҜйҖүеҚЎзүҢ');
            choiceResult = { cancelled: true };
        }
        else {
            const options = exile.map(c => cardChoiceOption(c));
            const sel = await simpleChoice(choiceTitle('д»Һж”ҫйҖҗеҢәйҖүжӢ©'), options, choicePromptConfig);
            if (sel >= 0 && sel < exile.length) choiceResult = { target_instance_id: exile[sel].instance_id, target_def_id: exile[sel].def_id };
        }
    } else if (choiceType === 'choose_equipment') {
        const equipment = choiceTargetData().equipment || [];
        if (!equipment.length) { gameAlert(UI.notice, UI.no_valid_target || 'ж— еҸҜйҖүиЈ…еӨҮ'); }
        else {
            const options = equipment.map(e => equipmentChoiceOption(e));
            const sel = await simpleChoice(choiceTitle('йҖүжӢ©иЈ…еӨҮ'), options, choicePromptConfig);
            if (sel >= 0 && sel < equipment.length) choiceResult = { target_instance_id: equipment[sel].card_instance.instance_id };
        }
    } else if (choiceType === 'choose_from_enemy_hand') {
        const targetId = data.target_player_id != null ? data.target_player_id : -1;
        const targetData = targetId >= 0 ? getPlayerDataById(targetId) : (gameState.opponent || {});
        const fallbackOpponent = gameState.opponent || {};
        const oppHand = (data.hand_cards || targetData.hand || targetData.revealed_hand || fallbackOpponent.hand || fallbackOpponent.revealed_hand || [])
            .filter(c => !cardHasSublimeFlag(c));
        if (!oppHand.length) { gameAlert(UI.notice, UI.no_enemy_hand); }
        else {
            const options = oppHand.map(c => cardChoiceOption(c));
            const sel = await simpleChoice(choiceTitle(UI.choose_from_enemy_hand_for.replace('{0}', cardName)), options, choicePromptConfig);
            if (sel >= 0 && sel < oppHand.length) choiceResult = { target_instance_id: oppHand[sel].instance_id, target_player_id: targetId };
        }
    } else if (choiceType === 'choose_target') {
        const candidates = choiceParams.candidates || choiceParams.target || choiceParams.targets || 'enemy';
        const candidateList = normalizeTargetCandidates(candidates);
        const includeSelf = choiceParams.include_self === true
            || candidateList.some(c => ['self', 'friendly', 'both', 'all', 'random_friendly', 'random_player', 'random_side'].includes(c));
        const targetId = await choosePlayerTarget(choiceTitle(UI.choose_target || UI.select_target || 'Choose target'), {
            includeSelf,
            aliveOnly: choiceParams.alive_only !== false,
            candidates,
        });
        if (targetId >= 0) choiceResult = { target_player: targetId, target_player_id: targetId };
    } else if (choiceType === 'foresight_replace') {
        const handCards = (data.hand_cards || data.deck_cards || []).filter(c => (
            !cardHasSublimeFlag(c) && c.instance_id !== cardDict.instance_id
        ));
        const maxReplace = Number(choiceParams.max_count || choiceParams.count || 1);
        if (!handCards.length) { gameAlert(UI.notice, UI.no_valid_target || 'жІЎжңүеҸҜйҖүжӢ©зҡ„еҚЎзүҢ'); }
        else {
            const options = handCards.map(c => cardChoiceOption(c));
            const selected = await multiChoice(
                choiceTitle(UI.foresight_replace_title || 'Foresight'),
                options,
                {
                    ...choicePromptConfig,
                    min: 0,
                    max: maxReplace,
                    message: (UI.foresight_replace_desc || 'Select up to {0} cards to draw').replace('{0}', maxReplace),
                    confirmText: UI.foresight_replace_confirm || 'Draw',
                }
            );
            if (selected.length > 0) choiceResult = { selected_instance_ids: selected.map(i => handCards[i].instance_id) };
            else choiceResult = { selected_instance_ids: [] };
        }
    } else if (choiceType === 'magic_salt_reflect') {
        choiceResult = await showMagicSaltReflectResponseUI(data, choiceParams);
    } else if (choiceType === 'confirm') {
        const sel = await simpleChoice(choiceTitle(UI.notice || 'Confirm'), [
            choiceParams.ok_text || UI.ok || 'OK',
            choiceParams.cancel_text || UI.cancel || 'Cancel',
        ], choicePromptConfig);
        if (sel >= 0) choiceResult = { confirmed: sel === 0, accepted: sel === 0 };
    } else if (choiceType === 'reorder_deck') {
        const deckCards = data.deck_cards || [];
        if (!deckCards.length) { gameAlert(UI.notice, UI.deck_empty); }
        else {
            choiceResult = await showReorderDeckUI(deckCards, data.message || 'и°ғж•ҙзүҢе ҶйЎәеәҸ', choicePromptConfig);
        }
    }
    if (!choiceResult && choiceParams.continue_on_cancel) {
        choiceResult = { cancelled: true };
    }
    if (!choiceResult) {
        choiceResult = { cancelled: true };
    }
    if (requestSeq !== choiceRequestSeq || !choicePending) {
        debugLog('[client] skipped stale choice result', { requestSeq, choiceRequestSeq, choiceType });
        return;
    }
    if (!canSendGameAction('resolve_choice', { includeAnimation: false })) {
        invalidateChoiceRequest();
        return;
    }
    choicePending = false;
    beginPendingServerAction('resolve_choice', { timeoutMs: SERVER_ACTION_TIMEOUT_MS });
    emitModeEvent('solo_resolve_choice', 'resolve_choice', { choice: choiceResult });
}

let rematchRequestedByOpponent = false;
let rematchState = null;

function resetRematchUiState() {
    rematchRequestedByOpponent = false;
    rematchState = null;
}

function updateRematchState(data = {}) {
    const votes = Number(data.votes ?? data.rematch_votes ?? 0);
    const total = Number(data.total ?? data.rematch_total ?? 0);
    rematchState = {
        votes: Number.isFinite(votes) ? Math.max(0, votes) : 0,
        total: Number.isFinite(total) ? Math.max(0, total) : 0,
        hasVoted: !!(data.has_voted ?? data.rematch_has_voted),
        mode: data.mode || (gameState && gameState.mode) || '',
        blocked: !!(data.rematch_blocked || data.blocked),
        blockedReason: data.rematch_blocked_reason || data.blocked_reason || '',
        returnedPlayerName: data.rematch_returned_player_name || data.returned_player_name || data.player_name || '',
    };
}

function syncRematchStateFromGameState(gs) {
    if (!gs || gs.rematch_total === undefined) return;
    updateRematchState({
        votes: gs.rematch_votes,
        total: gs.rematch_total,
        has_voted: gs.rematch_has_voted,
        mode: gs.mode,
        rematch_blocked: gs.rematch_blocked,
        rematch_blocked_reason: gs.rematch_blocked_reason,
        rematch_returned_player_name: gs.rematch_returned_player_name,
    });
}

function isTeamRematchGame(gs) {
    const mode = (gs && gs.mode) || (rematchState && rematchState.mode) || '';
    return mode === '2v2' || !!(gs && Array.isArray(gs.teams));
}

function getRematchProgress(gs) {
    const teamMode = isTeamRematchGame(gs);
    const fallbackTotal = teamMode ? 4 : 2;
    const votes = Number((rematchState && rematchState.votes) ?? (gs && gs.rematch_votes) ?? 0);
    const total = Number((rematchState && rematchState.total) ?? (gs && gs.rematch_total) ?? fallbackTotal);
    const hasVoted = !!((rematchState && rematchState.hasVoted) ?? (gs && gs.rematch_has_voted));
    const blocked = !!((rematchState && rematchState.blocked) ?? (gs && gs.rematch_blocked));
    return {
        votes: Number.isFinite(votes) ? Math.max(0, votes) : 0,
        total: Number.isFinite(total) && total > 0 ? total : fallbackTotal,
        hasVoted,
        blocked,
    };
}

function formatRematchProgress(votes, total) {
    return tf('rematch_progress', votes, total);
}

function updateGameOverRematchButton(gs) {
    const rematchBtn = $('btn-rematch');
    if (!rematchBtn) return;
    const progress = getRematchProgress(gs);
    const teamMode = isTeamRematchGame(gs);
    if (progress.blocked) {
        rematchBtn.textContent = UI.rematch_unavailable_returned || 'A player returned to lobby';
        rematchBtn.disabled = true;
        rematchBtn.onclick = null;
    } else if (teamMode) {
        rematchBtn.textContent = formatRematchProgress(progress.votes, progress.total);
        rematchBtn.disabled = progress.hasVoted;
        rematchBtn.onclick = () => {
            if (!socket || rematchBtn.disabled) return;
            clearActiveMatchRoute('rematch');
            socket.emit('rematch');
            const nextVotes = Math.min(progress.total, Math.max(progress.votes + (progress.hasVoted ? 0 : 1), progress.votes));
            rematchState = { ...progress, votes: nextVotes, hasVoted: true, mode: '2v2' };
            rematchBtn.textContent = formatRematchProgress(nextVotes, progress.total);
            rematchBtn.disabled = true;
        };
    } else if (progress.hasVoted) {
        rematchBtn.textContent = UI.rematch_sent;
        rematchBtn.disabled = true;
        rematchBtn.onclick = null;
    } else if (rematchRequestedByOpponent) {
        rematchBtn.textContent = UI.agree_rematch;
        rematchBtn.disabled = false;
        rematchBtn.onclick = () => {
            if (!socket) { debugLog('[REMATCH] socket missing'); return; }
            debugLog('[REMATCH] emit rematch accept');
            clearActiveMatchRoute('rematch');
            socket.emit('rematch');
            rematchBtn.textContent = UI.rematch_sent;
            rematchBtn.disabled = true;
        };
    } else {
        rematchBtn.textContent = UI.rematch;
        rematchBtn.disabled = false;
        rematchBtn.onclick = () => {
            if (!socket) { debugLog('[REMATCH] socket missing'); return; }
            debugLog('[REMATCH] emit rematch request');
            clearActiveMatchRoute('rematch');
            socket.emit('rematch');
            rematchBtn.textContent = UI.rematch_sent;
            rematchBtn.disabled = true;
        };
    }
}

function formatGrDelta(delta) {
    const value = Number(delta || 0);
    if (!Number.isFinite(value) || Math.abs(value) < 0.05) return 'Вұ0';
    return `${value > 0 ? '+' : ''}${value.toFixed(Math.abs(value) >= 10 ? 0 : 1)}`;
}

function grDeltaClass(delta) {
    const value = Number(delta || 0);
    if (!Number.isFinite(value) || Math.abs(value) < 0.05) return 'neutral';
    return value > 0 ? 'positive' : 'negative';
}

function renderInviteGrPreview(data = {}) {
    const preview = data.gr_preview || data || {};
    const text = preview.text || data.gr_preview_text || '';
    if (!preview.applied) {
        return text ? `<p class="invite-gr-preview is-neutral">${escapeHtml(text)}</p>` : '';
    }
    const viewer = preview.viewer || {};
    const rows = [
        [currentLang === 'zh' ? 'иғңеҲ©' : 'Win', viewer.win_delta],
        [currentLang === 'zh' ? 'е№іеұҖ' : 'Draw', viewer.draw_delta],
        [currentLang === 'zh' ? 'еӨұиҙҘ' : 'Loss', viewer.loss_delta],
    ];
    const repeat = Number(preview.repeat_factor || 1);
    const repeatText = repeat < 0.999
        ? `<div class="invite-gr-repeat">${escapeHtml(currentLang === 'zh' ? `йҮҚеӨҚеҜ№еұҖиЎ°еҮҸ Г—${repeat.toFixed(2)}` : `Repeat match factor Г—${repeat.toFixed(2)}`)}</div>`
        : '';
    return `
        <div class="invite-gr-preview-card">
            <div class="invite-gr-title">${escapeHtml(currentLang === 'zh' ? 'иҠұйҳ¶еҲҶйў„дј°' : 'Garden Rating Preview')}</div>
            ${rows.map(([label, delta]) => `
                <div class="invite-gr-row">
                    <span>${escapeHtml(label)}</span>
                    <b class="${escapeHtml(grDeltaClass(delta))}">${escapeHtml(formatGrDelta(delta))}</b>
                </div>
            `).join('')}
            ${repeatText}
        </div>
    `;
}

function showInviteConfirmModal({ title, message, preview, confirmText, onConfirm }) {
    showModal(`
        <h3>${escapeHtml(title || (currentLang === 'zh' ? 'зЎ®и®ӨйӮҖиҜ·' : 'Confirm Invite'))}</h3>
        <p>${escapeHtml(message || '')}</p>
        ${renderInviteGrPreview(preview || {})}
        <div class="modal-buttons">
            <button class="btn btn-danger" id="invite-confirm-cancel">${escapeHtml(UI.cancel || 'еҸ–ж¶Ҳ')}</button>
            <button class="btn btn-primary" id="invite-confirm-ok">${escapeHtml(confirmText || UI.invite || 'йӮҖиҜ·')}</button>
        </div>
    `);
    const cancel = $('invite-confirm-cancel');
    const ok = $('invite-confirm-ok');
    if (cancel) cancel.onclick = hideModal;
    if (ok) {
        ok.onclick = () => {
            hideModal();
            if (typeof onConfirm === 'function') onConfirm();
        };
    }
}

function renderGameOverGr(gs = {}) {
    const box = $('gameover-gr');
    if (!box) return;
    const summary = gs.match_summary || gs.summary || {};
    const gr = summary.gr_result || gs.gr_result || null;
    box.innerHTML = '';
    box.classList.add('hidden');
    const title = currentLang === 'zh' ? 'иҠұйҳ¶еҲҶ' : 'Garden Rating';
    if (!gr) return;
    if (!gr.applied) {
        const reason = gr.reason || summary.ranking_invalid_reason || '';
        const text = reason === 'entertainment_mod'
            ? UI.gr_unranked_entertainment
            : (currentLang === 'zh'
                ? `жң¬еұҖдёҚи®Ўе…ҘиҠұйҳ¶еҲҶ${reason ? `пјҲ${reason}пјү` : ''}`
                : `This match did not affect GR${reason ? ` (${reason})` : ''}`);
        box.innerHTML = `<div class="gameover-gr-title">${escapeHtml(title)}</div><div class="gameover-gr-muted">${escapeHtml(text)}</div>`;
        box.classList.remove('hidden');
        return;
    }
    const playerIds = Array.isArray(summary.player_ids) ? summary.player_ids : [];
    const names = Array.isArray(summary.players) ? summary.players : [];
    const seasonDeltas = gr.season_deltas || {};
    const before = gr.before || {};
    const after = gr.after || {};
    const rows = [];
    playerIds.forEach((uid, idx) => {
        if (uid === null || uid === undefined || uid === '') return;
        const key = String(uid);
        const delta = seasonDeltas[key];
        if (delta === undefined) return;
        const oldGr = before[key] && before[key].season_gr;
        const newGr = after[key] && after[key].season_gr;
        const isMe = currentAccount && String(currentAccount.id) === key;
        rows.push(`
            <div class="gameover-gr-row${isMe ? ' is-self' : ''}">
                <span>${escapeHtml(names[idx] || `P${idx + 1}`)}</span>
                <span>${escapeHtml(formatGrValue(oldGr))} вҶ’ ${escapeHtml(formatGrValue(newGr))}</span>
                <b class="${Number(delta) >= 0 ? 'positive' : 'negative'}">${escapeHtml(formatGrDelta(delta))}</b>
            </div>
        `);
    });
    const repeat = Number(gr.repeat_factor || 1);
    const repeatText = repeat < 0.999
        ? `<div class="gameover-gr-muted">${escapeHtml(currentLang === 'zh' ? `йҮҚеӨҚеҜ№еұҖиЎ°еҮҸпјҡГ—${repeat.toFixed(2)}` : `Repeat match factor: Г—${repeat.toFixed(2)}`)}</div>`
        : '';
    box.innerHTML = `<div class="gameover-gr-title">${escapeHtml(title)}</div>${rows.join('')}${repeatText}`;
    box.classList.toggle('hidden', rows.length === 0);
}

function renderGameOver(data) {
    const gs = preserveGameOverLogState(data || gameState, gameState) || {};
    const finalLog = Array.isArray(gs.log) ? gs.log.slice() : [];
    resetMatchRuntimeState({ clearGameState: false });
    showView('view-gameover');
    syncRematchStateFromGameState(gs);
    const isTutorialGameOver = !!gs.tutorial;
    const isSpectatorGameOver = !!(gs.spectating || isSpectating || gs.your_id === -1 || playerId === -1);
    const winner = gs.winner;
    const isDraw = winner === -1 || winner === null || winner === undefined;
    const is2v2GameOver = gs.mode === '2v2' || Array.isArray(gs.teams);
    const winningTeam = gs.winning_team !== undefined ? gs.winning_team : winner;
    const myTeam = gs.team_id;
    const isWin = is2v2GameOver
        ? (Number(winningTeam) === Number(myTeam))
        : (winner === playerId);
    const title = $('gameover-title');
    if (title) {
        title.textContent = isSpectatorGameOver ? UI.game_over : (isDraw ? UI.draw : (isWin ? UI.victory : UI.defeat));
        title.style.whiteSpace = '';
        const isDark = document.documentElement.getAttribute('data-theme') === 'dark';
        if (isSpectatorGameOver || isDraw) {
            title.style.color = isDark ? '#E5E7EB' : '#374151';
            title.style.background = isDark ? 'rgba(229, 231, 235, 0.14)' : 'rgba(55, 65, 81, 0.12)';
        } else {
            title.style.color = isWin ? COLORS.health : COLORS.damage;
            title.style.background = isWin
                ? (isDark ? 'rgba(46, 204, 113, 0.15)' : COLORS.health_bg)
                : (isDark ? 'rgba(192, 57, 43, 0.15)' : COLORS.damage_bg);
        }
    }
    const message = $('gameover-message');
    if (message) {
        const tutorialMessage = isTutorialGameOver && !isDraw
            ? (isWin ? UI.tutorial_victory_message : UI.tutorial_defeat_message)
            : '';
        message.textContent = tutorialMessage;
        message.classList.toggle('hidden', !tutorialMessage);
    }
    renderGameOverGr(gs);
    const replayBox = $('gameover-replay');
    const replayCopy = $('btn-copy-gameover-replay');
    const replayId = Number((gs.match_summary || gs.summary || {}).replay_id || gs.replay_id || 0);
    if (replayBox) replayBox.classList.toggle('hidden', !(replayId > 0) || isTutorialGameOver || soloMode);
    if (replayCopy) {
        const replayRef = replayId > 0 ? `R-${replayId}` : '';
        replayCopy.textContent = replayRef;
        replayCopy.title = UI.replay_copy || 'еӨҚеҲ¶';
        replayCopy.onclick = replayRef ? (async () => {
            if (await copyPlainText(replayRef)) flashStatus(UI.replay_copied || 'е·ІеӨҚеҲ¶еӣһж”ҫ ID', 1800);
        }) : null;
    }
    const logContainer = $('gameover-log');
    if (logContainer) {
        logContainer.innerHTML = '';
        const finalLogEntries = compactBattleLogEntriesForDisplay(finalLog);
        finalLogEntries.forEach(entry => logContainer.appendChild(createBattleLogElement(entry)));
    }
    const rematchBtn = $('btn-rematch');
    if (rematchBtn) {
        rematchBtn.classList.remove('hidden');
        rematchBtn.style.display = '';
        if (isSpectatorGameOver) {
            rematchBtn.classList.add('hidden');
            rematchBtn.style.display = 'none';
            rematchBtn.disabled = true;
            rematchBtn.onclick = null;
        } else if (isTutorialGameOver && isWin) {
            rematchBtn.classList.add('hidden');
            rematchBtn.style.display = 'none';
            rematchBtn.disabled = true;
            rematchBtn.onclick = null;
        } else if (isTutorialGameOver) {
            rematchBtn.textContent = UI.tutorial_retry || UI.rematch;
            rematchBtn.disabled = false;
            rematchBtn.onclick = () => startTutorial('home');
        } else {
            updateGameOverRematchButton(gs);
        }
    }
    const reportMatchBtn = $('btn-report-match');
    if (reportMatchBtn) {
        const matchObjectId = getReportMatchObjectId(gs);
        const showReportMatch = !!matchObjectId && !isTutorialGameOver && !soloMode && gs.mode !== 'solo';
        reportMatchBtn.textContent = UI.report_match || UI.report || 'Report';
        reportMatchBtn.classList.toggle('hidden', !showReportMatch);
        reportMatchBtn.style.display = showReportMatch ? '' : 'none';
        reportMatchBtn.onclick = showReportMatch ? (() => openReportDialog({
            objectType: 'match',
            objectId: matchObjectId,
            title: UI.report_match,
        })) : null;
    }
    const returnLobbyBtn = $('btn-return-lobby');
    if (returnLobbyBtn) {
        if (isTutorialGameOver) {
            returnLobbyBtn.textContent = UI.back_to_home || UI.return_lobby;
            returnLobbyBtn.onclick = () => {
                if (socket || isLocalSoloRuntimeActive()) {
                    suppressSoloPausedHandler = true;
                    emitSoloEvent('solo_pause', {});
                }
                soloMode = false;
                stopTutorialUiForGameOver();
                showView('view-login');
                phase = 'login';
                updateStatus(UI.default_status);
            };
        } else {
            returnLobbyBtn.textContent = UI.return_lobby;
            returnLobbyBtn.onclick = () => {
                if (!socket) return;
                allowLobbyTransition('return_lobby_button');
                socket.emit('return_lobby');
                clearNetworkMatchStateForLobby();
                showView('view-lobby');
                phase = 'lobby';
            };
        }
    }
}

function showOpponentDCWaiting(data) {
    const timeout = data.reconnect_timeout || 120;
    const oppName = data.opponent_nickname || '?';
    const spectateDcModal = !!(isSpectating || (gameState && gameState.spectating));
    const leaveSpectateHtml = spectateDcModal
        ? `<button id="dc-leave-spectate" class="btn btn-danger btn-leave-spectate dc-leave-spectate" type="button">${UI.leave_spectate || 'йҖҖеҮәи§ӮжҲҳ'}</button>`
        : '';
    if (window._opponentDcTimerId) {
        clearInterval(window._opponentDcTimerId);
        window._opponentDcTimerId = null;
    }
    if (data && data.wait_forever) {
        showModal(`
            <div class="disconnect-modal">
                <h3>${UI.opponent_disconnected}</h3>
                <p id="dc-countdown" class="disconnect-countdown">${oppName}</p>
                ${leaveSpectateHtml}
            </div>
        `);
        setSpectateDisconnectModalActive(spectateDcModal);
        const leaveBtn = $('dc-leave-spectate');
        if (leaveBtn) leaveBtn.addEventListener('click', leaveSpectateAction);
        return;
    }
    let remaining = timeout;
    showModal(`
        <div class="disconnect-modal">
            <h3>${UI.opponent_disconnected}</h3>
            <p id="dc-countdown" class="disconnect-countdown">${oppName} ${remaining}s</p>
            ${leaveSpectateHtml}
        </div>
    `);
    setSpectateDisconnectModalActive(spectateDcModal);
    const leaveBtn = $('dc-leave-spectate');
    if (leaveBtn) leaveBtn.addEventListener('click', leaveSpectateAction);
    window._opponentDcTimerId = setInterval(() => {
        remaining--;
        const el = $('dc-countdown');
        if (el) el.textContent = `${oppName} ${remaining}s`;
        if (remaining <= 0) {
            clearInterval(window._opponentDcTimerId);
            window._opponentDcTimerId = null;
            setSpectateDisconnectModalActive(false);
            hideModal();
        }
    }, 1000);
}

function clearOpponentDisconnectModal() {
    if (window._opponentDcTimerId) {
        clearInterval(window._opponentDcTimerId);
        window._opponentDcTimerId = null;
    }
    const dcEl = $('dc-countdown');
    if (dcEl) hideModal();
    setSpectateDisconnectModalActive(false);
}

function syncOpponentDisconnectModalFromState(state) {
    if (!state || state.phase === 'game_over' || state.solo) {
        clearOpponentDisconnectModal();
        return;
    }
    const dc = state.disconnect_state;
    const list = dc && Array.isArray(dc.players) ? dc.players.filter(p => Number(p && p.remaining) > 0) : [];
    if (!dc || !dc.active || !list.length) {
        clearOpponentDisconnectModal();
        return;
    }
    const names = list.map(p => p && p.nickname ? p.nickname : '?').join('гҖҒ');
    const remaining = Math.max(1, Math.min(...list.map(p => Number(p.remaining) || Number(dc.reconnect_timeout) || 120)));
    showOpponentDCWaiting({
        reconnect_timeout: remaining,
        opponent_nickname: names || (UI.opponent || '?'),
    });
}

function onEndTurn() {
    if (!canSendGameAction('end_turn', { includeAnimation: false })) return;
    if (!isMyTurn()) {
        flashStatus(UI.not_your_turn, 2000, 'error');
        return;
    }
    if (socket || isLocalSoloRuntimeActive()) {
        beginPendingServerAction('end_turn', { timeoutMs: SERVER_ACTION_TIMEOUT_MS });
        emitModeEvent('solo_end_turn', 'end_turn', {});
    } else {
        updateStatus(UI.server_not_connected);
    }
}

async function onSoloNextDraw() {
    if (!soloMode || (!socket && !isLocalSoloRuntimeActive())) return;
    const deck = (gameState.you || {}).deck || [];
    if (!deck.length) {
        gameAlert(UI.notice, UI.deck_empty);
        return;
    }
    const maxCount = Math.min(5, deck.length);
    const countOptions = Array.from({ length: maxCount }, (_, i) => String(i + 1));
    const countSel = await simpleChoice(UI.next_draw_count, countOptions);
    if (countSel < 0) return;
    const pickCount = countSel + 1;
    const pool = deck.map(c => ({ ...c }));
    const chosen = [];
    for (let i = 0; i < pickCount; i++) {
        if (!pool.length) break;
        const options = pool.map(p => cardChoiceOption(p));
        const sel = await simpleChoice(tf('next_draw_pick', i + 1, pickCount), options);
        if (sel < 0) return;
        chosen.push(pool[sel].def_id);
        pool.splice(sel, 1);
    }
    if (!chosen.length) return;
    emitSoloEvent('solo_set_next_draw', { def_ids: chosen });
}

function onSurrender() {
    const message = gameState && gameState.mode === '2v2' ? UI.confirm_team_surrender : UI.confirm_surrender;
    gameAlert(message, '', [
        { text: UI.ok, cls: 'btn-danger', action: () => {
            if (socket) {
                emitModeEvent('solo_pause', 'surrender', {});
            }
        }},
        { text: UI.cancel, cls: 'btn-secondary', action: () => {} }
    ]);
}

function getSpectatePerspectivePlayer(gs = gameState) {
    if (!gs || !Array.isArray(gs.spectate_players) || !gs.spectate_players.length) {
        return null;
    }
    const current = normalizePlayerId(gs.spectate_perspective != null ? gs.spectate_perspective : spectatePerspective);
    if (current != null) {
        const byId = gs.spectate_players.find(p => normalizePlayerId(p && p.player_id) === current);
        if (byId) return byId;
    }
    return gs.spectate_players[0] || null;
}

function getDeckViewerPlayer() {
    if (isSpectating || (gameState && gameState.spectating)) {
        return getSpectatePerspectivePlayer(gameState) || gameState.you || {};
    }
    return (gameState && gameState.you) || {};
}

function getPileViewerPlayers(pileType = 'deck') {
    if (!gameState) return [];
    const self = getDeckViewerPlayer();
    const players = [];
    const seen = new Set();
    const addPlayer = (player) => {
        if (!player) return;
        const pid = normalizePlayerId(player.player_id);
        const key = pid != null ? `p${pid}` : JSON.stringify(player.name || player.nickname || '');
        if (seen.has(key)) return;
        seen.add(key);
        players.push(player);
    };
    addPlayer(self);
    const orderedKey = pileType === 'discard'
        ? 'discard_ordered'
        : (pileType === 'deck' ? 'deck_ordered' : 'exile_ordered');
    [gameState.you, gameState.teammate, gameState.opponent, gameState.opponent2]
        .forEach(player => {
            if (player && Array.isArray(player[orderedKey])) addPlayer(player);
        });
    return players;
}

function getPileViewerName(player) {
    if (!player) return '';
    const pid = normalizePlayerId(player.player_id);
    if (pid != null) return getPlayerNameById(pid);
    return localizeCanonicalPlayerName(player.name || player.nickname || '');
}

function getPileFromPlayer(player, pileType = 'deck') {
    if (!player) return [];
    if (pileType === 'exile') return player.exile || [];
    if (pileType === 'discard') return player.discard_ordered || player.discard || [];
    return player.deck_ordered || player.deck || [];
}

function repairSpectate2v2Layout(gs) {
    if (!gs || gs.mode !== '2v2' || !gs.spectating || !Array.isArray(gs.spectate_players) || gs.spectate_players.length < 4) return;
    const perspective = normalizePlayerId(gs.spectate_perspective != null ? gs.spectate_perspective : gs.your_id);
    if (perspective == null || perspective < 0 || perspective >= gs.spectate_players.length) return;
    const teammate = perspective < 2 ? 1 - perspective : (perspective === 2 ? 3 : 2);
    const enemies = [0, 1, 2, 3].filter(id => id !== perspective && id !== teammate);
    const currentIds = [
        normalizePlayerId(gs.your_id),
        normalizePlayerId(gs.teammate_id),
        ...((gs.enemy_ids || []).map(normalizePlayerId)),
    ].filter(id => id != null);
    if (currentIds.length >= 4 && new Set(currentIds).size === currentIds.length) return;
    const players = gs.spectate_players;
    const playerName = id => (players[id] && players[id].name) || `P${id + 1}`;
    gs.your_id = perspective;
    gs.spectate_perspective = perspective;
    gs.teammate_id = teammate;
    gs.enemy_ids = enemies;
    gs.you = players[perspective] || {};
    gs.teammate = players[teammate] || {};
    gs.opponent = players[enemies[0]] || {};
    gs.opponent2 = players[enemies[1]] || {};
    gs.your_name = playerName(perspective);
    gs.teammate_name = playerName(teammate);
    gs.opponent_names = enemies.map(playerName);
    gs.teammate_is_admin_player = !!(players[teammate] && players[teammate].is_admin_player);
    gs.opponent_admin_flags = enemies.map(id => !!(players[id] && players[id].is_admin_player));
    gs.teammate_special = specialPublicReplayFields(players[teammate] || {});
    gs.opponent_specials = enemies.map(id => specialPublicReplayFields(players[id] || {}));
}

function onViewDeck() {
    onViewPile('deck');
}

function onViewDiscard() {
    onViewPile('discard');
}

function onViewExile() {
    onViewPile('exile');
}

function onViewPile(pileType = 'deck') {
    if (gameState && gameState.mode === 'urf') {
        return;
    }
    const isDeckPile = pileType === 'deck';
    const isDiscardPile = pileType === 'discard';
    const isExilePile = pileType === 'exile';
    if (isDeckPile && tutorialMode) {
        tutorialDeckViewed = true;
        hideTutorialOverlay();
        setTimeout(updateTutorialOverlay, 80);
    }
    const pilePlayers = getPileViewerPlayers(pileType);
    const modal = $('modal');
    const content = $('modal-content');
    if (!modal || !content) return;
    removeFloatingCardPreview();
    content.className = 'modal-inner view-deck-modal';
    content.innerHTML = '';
    const title = document.createElement('h3');
    const titleText = isDeckPile
        ? (UI.view_draw_deck_title || UI.view_deck_title)
        : (isExilePile
            ? (UI.view_exile_title || UI.flag_exile || 'Exile')
            : (UI.view_discard_title || UI.discard_empty || 'Discard'));
    const deckOwnerName = !isDiscardPile && pilePlayers[0] && pilePlayers[0].name
        ? getPileViewerName(pilePlayers[0])
        : '';
    title.textContent = deckOwnerName ? `${titleText} - ${deckOwnerName}` : titleText;
    content.appendChild(title);
    const totalTemplate = isDeckPile
        ? (UI.draw_deck_total || UI.deck_total)
        : (isExilePile
            ? (UI.exile_total || 'Exile: {0}')
            : (UI.discard_total || 'Discard: {0}'));
    const emptyText = isDeckPile
        ? (UI.deck_empty || 'Deck empty')
        : (isExilePile
            ? (UI.exile_empty || 'Exile empty')
            : (UI.discard_empty || 'Discard pile empty'));

    const renderPileSection = (pilePlayer, showOwner) => {
        const pid = normalizePlayerId(pilePlayer && pilePlayer.player_id);
        const selfId = normalizePlayerId(gameState && gameState.your_id);
        const isSelf = pid != null && selfId != null && pid === selfId;
        const pile = getPileFromPlayer(pilePlayer, pileType);
        const orderedKey = isDeckPile ? 'deck_ordered' : (isDiscardPile ? 'discard_ordered' : 'exile_ordered');
        const hasVisibleOrder = !!(pilePlayer && Array.isArray(pilePlayer[orderedKey]));
        const blindPile = isDeckPile
            ? (isSelf && shouldMaskOwnDrawDeck())
            : ((isDiscardPile || isExilePile) && isSelf && shouldMaskOwnDiscardPile());
        if (showOwner) {
            const owner = document.createElement('h4');
            owner.className = 'deck-owner-title';
            owner.textContent = getPileViewerName(pilePlayer) || '?';
            content.appendChild(owner);
        }
        const total = document.createElement('p');
        total.className = 'deck-total';
        total.textContent = totalTemplate.replace('{0}', blindPile ? '?' : pile.length);
        content.appendChild(total);
        const list = document.createElement('div');
        list.className = 'deck-list pile-tile-grid';
        if (blindPile) {
            const row = document.createElement('div');
            row.className = 'deck-entry pile-tile-entry deck-entry-blinded';
            row.appendChild(createClassicCardTile({}, { faceDown: true }));
            list.appendChild(row);
        } else if (!pile.length) {
            const row = document.createElement('div');
            row.className = 'deck-entry deck-entry-empty pile-tile-empty';
            const empty = document.createElement('span');
            empty.className = 'choice-option-detail';
            empty.textContent = emptyText;
            row.appendChild(empty);
            list.appendChild(row);
        } else if (hasVisibleOrder) {
            // Ordered visibility: show cards from top/first to bottom/last.
            pile.forEach((c, idx) => {
                const row = document.createElement('div');
                row.className = 'deck-entry pile-tile-entry pile-tile-ordered';
                const numEl = document.createElement('span');
                numEl.className = 'choice-option-detail deck-entry-count pile-tile-order';
                numEl.textContent = `#${idx + 1}`;
                row.appendChild(createClassicCardTile(c, { ownerState: pilePlayer }));
                row.appendChild(numEl);
                list.appendChild(row);
            });
        } else {
            const groups = new Map();
            pile.forEach(c => {
                const key = cardChoiceIdentity(c);
                const group = groups.get(key) || { card: c, count: 0 };
                group.count += 1;
                groups.set(key, group);
            });
            Array.from(groups.values()).sort((a, b) => {
                const ad = getCardDef(a.card.def_id);
                const bd = getCardDef(b.card.def_id);
                if (ad && bd) return compareGalleryCards(a.card.def_id, b.card.def_id);
                return (ad ? getCardName(ad) : a.card.def_id || '').localeCompare(bd ? getCardName(bd) : b.card.def_id || '');
            }).forEach(({ card, count }) => {
                const row = document.createElement('div');
                row.className = 'deck-entry pile-tile-entry pile-tile-grouped';
                row.appendChild(createClassicCardTile(card, { ownerState: pilePlayer }));
                const countEl = document.createElement('span');
                countEl.className = 'choice-option-detail deck-entry-count pile-tile-count';
                countEl.textContent = `Г—${count}`;
                row.appendChild(countEl);
                list.appendChild(row);
            });
        }
        content.appendChild(list);
    };

    const players = pilePlayers.length ? pilePlayers : [{}];
    players.forEach(player => renderPileSection(player, isDiscardPile && players.length > 1));
    const buttons = document.createElement('div');
    buttons.className = 'modal-buttons';
    const closeBtn = document.createElement('button');
    closeBtn.className = 'btn btn-danger';
    closeBtn.textContent = UI.close;
    closeBtn.onclick = hideModal;
    buttons.appendChild(closeBtn);
    content.appendChild(buttons);
    modal.classList.remove('hidden');
    modal.classList.add('active');
}

async function onUrfReplaceCard() {
    if (!gameState || gameState.mode !== 'urf' || !isMyTurn()) return;
    if (isActionBusy({ includeAnimation: false })) return;
    const hand = (gameState.you || {}).hand || [];
    if (!hand.length) return;
    const options = hand.map(c => cardChoiceOption(c));
    const sel = await simpleChoice(UI.urf_replace || 'жӣҝжҚўжүӢзүҢ', options);
    if (sel < 0) return;
    beginPendingServerAction('urf_replace', { timeoutMs: SERVER_ACTION_TIMEOUT_MS });
    socket.emit('urf_replace_card', { card_instance_id: hand[sel].instance_id });
}

async function onUrfSellEquipment() {
    if (!gameState || gameState.mode !== 'urf' || !isMyTurn()) return;
    if (isActionBusy({ includeAnimation: false })) return;
    const equipment = ((gameState.you || {}).equipment || []).filter(isUrfEquipmentSellable);
    if (!equipment.length) return;
    const options = equipment.map(eq => equipmentChoiceOption(eq));
    const sel = await simpleChoice(UI.urf_sell || 'е”®еҚ–иЈ…еӨҮ', options);
    if (sel < 0) return;
    const inst = (equipment[sel].card_instance || {});
    beginPendingServerAction('urf_sell', { timeoutMs: SERVER_ACTION_TIMEOUT_MS });
    socket.emit('urf_sell_equipment', { equipment_instance_id: inst.instance_id });
}

