    document.addEventListener('click', (event) => {
        const respondBtn = event.target.closest('[data-friend-respond]');
        if (respondBtn) {
            event.preventDefault();
            respondFriendRequest(respondBtn.dataset.friendRespond, respondBtn.dataset.friendAction);
            return;
        }
        const removeBtn = event.target.closest('[data-friend-remove]');
        if (removeBtn) {
            event.preventDefault();
            removeFriend(removeBtn.dataset.friendRemove);
            return;
        }
        const friendOpenBtn = event.target.closest('[data-friend-open]');
        if (friendOpenBtn) {
            event.preventDefault();
            openFriendDetail(friendOpenBtn.dataset.friendOpen, 'profile');
            return;
        }
        const requestOpenCard = event.target.closest('[data-friend-request-open]');
        if (requestOpenCard) {
            event.preventDefault();
            openFriendRequestDetail(requestOpenCard.dataset.friendRequestOpen);
            return;
        }
        const dmThreadBtn = event.target.closest('[data-dm-thread]');
        if (dmThreadBtn) {
            event.preventDefault();
            toggleSocialDetailModal(true, 'dm');
            activeDmThreadId = dmThreadBtn.dataset.dmThread;
            clearDmUnreadForThread(dmThreadBtn.dataset.dmThread);
            renderDmThreads();
            renderSocialSelectorList();
            openDmThread(dmThreadBtn.dataset.dmThread, { markRead: true, force: true });
            return;
        }
        const dmUserBtn = event.target.closest('[data-dm-open-user]');
        if (dmUserBtn) {
            event.preventDefault();
            startDmToUser(dmUserBtn.dataset.dmOpenUser, dmUserBtn.dataset.dmOpenName || '');
            return;
        }
        const feedbackGroupBtn = event.target.closest('[data-feedback-group-toggle]');
        if (feedbackGroupBtn) {
            event.preventDefault();
            const key = String(feedbackGroupBtn.dataset.feedbackGroupToggle || '');
            if (key) {
                feedbackCollapsedGroups[key] = !feedbackCollapsedGroups[key];
                renderFeedbackThreads();
            }
            return;
        }
        const feedbackThreadBtn = event.target.closest('[data-feedback-thread]');
        if (feedbackThreadBtn) {
            event.preventDefault();
            openFeedbackThread(feedbackThreadBtn.dataset.feedbackThread);
        }
    });
